function json(
  data: unknown,
  status = 200,
  headers?: HeadersInit,
): NextResponse {
  return NextResponse.json(data, { status, headers });
}

function text(data: string, status = 200, headers?: HeadersInit): NextResponse {
  return new NextResponse(data, { status, headers });
}

function error(message: string, status = 400): NextResponse {
  return json({ error: message }, status);
}

function runAfter(label: string, task: () => Promise<unknown>) {
  after(async () => {
    try {
      await task();
    } catch (err: any) {
      console.error("background task failed", { label, message: err?.message });
    }
  });
}

type ValidationIssue = { field: string; message: string };

function validationError(
  scope: string,
  parsed: {
    error: { issues: Array<{ path: PropertyKey[]; message: string }> };
  },
): NextResponse {
  const details: ValidationIssue[] = parsed.error.issues.map((issue) => ({
    field: issue.path.map(String).join(".") || "body",
    message: issue.message,
  }));
  console.warn("API validation failed", { scope, details });
  const summary = details
    .slice(0, 4)
    .map((issue) => `${issue.field}: ${issue.message}`)
    .join("، ");
  return json(
    {
      error: summary ? `تحقق من البيانات: ${summary}` : "بيانات غير صحيحة",
      details,
    },
    400,
  );
}

async function body(req: NextRequest): Promise<any> {
  if (req.method === "GET" || req.method === "HEAD") return {};
  const raw = await req.text();
  if (!raw.trim()) return {};
  const contentType = req.headers.get("content-type") ?? "";
  if (contentType.includes("application/x-www-form-urlencoded")) {
    return Object.fromEntries(new URLSearchParams(raw).entries());
  }
  try {
    return JSON.parse(raw);
  } catch {
    return {};
  }
}

function query(req: NextRequest): Record<string, string> {
  return Object.fromEntries(req.nextUrl.searchParams.entries());
}

function int(value: string | undefined): number | null {
  const n = Number.parseInt(String(value ?? ""), 10);
  return Number.isFinite(n) ? n : null;
}

function ip(req: NextRequest): string {
  return (
    req.headers.get("x-forwarded-for")?.split(",")[0]?.trim() ||
    req.headers.get("x-real-ip") ||
    "unknown"
  );
}

function checkRateLimit(
  map: Map<string, Bucket>,
  key: string,
  max: number,
  windowMs: number,
): boolean {
  const now = Date.now();
  const b = map.get(key);
  if (!b || b.resetAt < now) {
    map.set(key, { count: 1, resetAt: now + windowMs });
    return true;
  }
  if (b.count >= max) return false;
  b.count++;
  return true;
}

function rollingRateLimited(
  map: Map<string, number[]>,
  key: string,
  max: number,
  windowMs: number,
): boolean {
  const now = Date.now();
  const hits = (map.get(key) ?? []).filter((t) => now - t < windowMs);
  hits.push(now);
  map.set(key, hits);
  return hits.length > max;
}

function generateOtp(): string {
  return randomInt(100000, 1000000).toString();
}

function generateTrackingCode(prefix = "AJN"): string {
  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  let code = prefix;
  for (let i = 0; i < 7; i++)
    code += chars[Math.floor(Math.random() * chars.length)];
  return code;
}

function phoneLast4(value: string | null | undefined): string {
  const normalized = normalizeIraqiPhone(value);
  const digits = normalized ?? normalizePhoneDigits(value);
  return digits.length >= 4 ? digits.slice(-4) : "";
}

function trackingCodeForPhone(phone: string): string {
  const last4 = phoneLast4(phone);
  return last4 ? `AJN-${last4}` : generateTrackingCode();
}

function normalizeTrackingCode(value: string): string {
  const raw = String(value ?? "")
    .trim()
    .toUpperCase();
  const digits = normalizePhoneDigits(raw);
  const compact = raw.replace(/[\s-]/g, "");
  if (compact.startsWith("AJN") && digits.length >= 4 && compact.length <= 7)
    return `AJN-${digits.slice(-4)}`;
  if (/^\d{4}$/.test(digits) && raw.length <= 4) return `AJN-${digits}`;
  return raw;
}

function trackingCodeLast4(value: string): string {
  const code = normalizeTrackingCode(value);
  const match = /^AJN-(\d{4})$/.exec(code);
  return match?.[1] ?? "";
}

function money(value: unknown): number {
  const raw = typeof value === "string" ? value.replace(/,/g, "") : value;
  const n = Number(raw ?? 0);
  return Number.isFinite(n) && n > 0 ? n : 0;
}

function textFallback(...values: unknown[]): string {
  for (const value of values) {
    const text = String(value ?? "").trim();
    if (text) return text;
  }
  return "";
}

function nullableText(value: unknown): string | null {
  const normalized = String(value ?? "").trim();
  return normalized || null;
}

function slugFallback(value: unknown, fallback = "item"): string {
  const normalized = String(value ?? "")
    .trim()
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 80);
  return normalized || fallback;
}

function numberId(value: unknown): number | null {
  const parsed = Number.parseInt(String(value ?? ""), 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : null;
}

function normalizeProductBarcode(value: unknown): string {
  return String(value ?? "")
    .trim()
    .toUpperCase()
    .replace(/\s+/g, "")
    .slice(0, 100);
}

function generatedProductBarcode(id: number): string {
  return `AJN${String(id).padStart(8, "0")}`;
}

async function productBarcodeExists(
  barcode: string,
  ignoreId?: number,
): Promise<boolean> {
  if (!barcode) return false;
  const existing = await db.query.productsTable.findFirst({
    where: eq(productsTable.barcode, barcode),
  });
  return !!existing && existing.id !== ignoreId;
}

function paymentSummary(
  totalValue: unknown,
  depositValue: unknown,
  preferredStatus?: unknown,
  paymentMethod?: unknown,
) {
  const settled = settlePaymentAmounts(
    totalValue,
    depositValue,
    preferredStatus,
    paymentMethod,
  );
  return {
    deposit: settled.paid,
    remaining: settled.remaining,
    status: settled.status,
  };
}

function sessionSecret(): string {
  return (
    process.env.AUTH_SECRET ||
    process.env.SESSION_SECRET ||
    process.env.NEXTAUTH_SECRET ||
    process.env.ADMIN_PASSWORD ||
    process.env.DATABASE_URL ||
    "ajn-dev-secret"
  );
}

function otpSecret(): string {
  return process.env.AUTH_SECRET || sessionSecret();
}

function hashOtp(phone: string, code: string): string {
  return createHmac("sha256", otpSecret())
    .update(`${phone}:${code}`)
    .digest("hex");
}

function verifyOtpHash(phone: string, code: string, hash: string): boolean {
  const expected = hashOtp(phone, code);
  try {
    return timingSafeEqual(
      Buffer.from(hash, "hex"),
      Buffer.from(expected, "hex"),
    );
  } catch {
    return false;
  }
}

function signCustomerToken(customerId: number): string {
  const issuedAt = Date.now().toString(36);
  const nonce = randomBytes(8).toString("hex");
  const payload = `${customerId}.${issuedAt}.${nonce}`;
  const signature = createHmac("sha256", sessionSecret())
    .update(payload)
    .digest("hex");
  return `v1.${payload}.${signature}`;
}

function verifyCustomerToken(token: string): number | null {
  if (!token.startsWith("v1.")) return customerSessions.get(token) ?? null;
  const [, idText, issuedAt, nonce, signature] = token.split(".");
  if (!idText || !issuedAt || !nonce || !signature) return null;
  const payload = `${idText}.${issuedAt}.${nonce}`;
  const expected = createHmac("sha256", sessionSecret())
    .update(payload)
    .digest("hex");
  try {
    if (
      !timingSafeEqual(
        Buffer.from(signature, "hex"),
        Buffer.from(expected, "hex"),
      )
    )
      return null;
  } catch {
    return null;
  }
  const customerId = Number.parseInt(idText, 10);
  return Number.isFinite(customerId) ? customerId : null;
}

function bearer(req: NextRequest): string | null {
  const auth = req.headers.get("authorization");
  return auth?.startsWith("Bearer ") ? auth.slice(7) : null;
}

function getSessionId(req: NextRequest): string {
  return req.headers.get("x-session-id") || "anonymous";
}

function getCurrentCustomerId(req: NextRequest): number | null {
  const token = req.cookies.get(CUSTOMER_COOKIE_NAME)?.value || bearer(req);
  return token ? verifyCustomerToken(token) : null;
}

function withCustomerCookie(
  response: NextResponse,
  token: string,
): NextResponse {
  response.cookies.set(CUSTOMER_COOKIE_NAME, token, {
    httpOnly: true,
    sameSite: "lax",
    secure: isProd,
    path: "/",
    maxAge: Math.floor(SESSION_TTL_MS / 1000),
  });
  return response;
}

function clearCustomerCookie(response: NextResponse): NextResponse {
  response.cookies.set(CUSTOMER_COOKIE_NAME, "", {
    httpOnly: true,
    sameSite: "lax",
    secure: isProd,
    path: "/",
    maxAge: 0,
  });
  return response;
}

export function hashPassword(plain: string): string {
  return bcrypt.hashSync(plain, 10);
}

export function verifyPassword(plain: string, hash: string): boolean {
  if (!hash) return false;
  if (hash.startsWith("$2")) {
    try {
      return bcrypt.compareSync(plain, hash);
    } catch {
      return false;
    }
  }
  const [salt, expected] = hash.split(":");
  if (!salt || !expected) return false;
  try {
    const got = scryptSync(plain, salt, 64).toString("hex");
    return timingSafeEqual(
      Buffer.from(got, "hex"),
      Buffer.from(expected, "hex"),
    );
  } catch {
    return false;
  }
}

async function createSession(
  userId: number,
): Promise<{ token: string; expiresAt: Date }> {
  const token = randomBytes(32).toString("hex");
  const expiresAt = new Date(Date.now() + SESSION_TTL_MS);
  await db.insert(adminSessionsTable).values({ token, userId, expiresAt });
  return { token, expiresAt };
}

async function destroySession(token: string): Promise<void> {
  await db
    .delete(adminSessionsTable)
    .where(eq(adminSessionsTable.token, token));
}

async function pruneExpiredSessions(): Promise<void> {
  try {
    await db
      .delete(adminSessionsTable)
      .where(lt(adminSessionsTable.expiresAt, new Date()));
  } catch {
    // Session cleanup is best-effort.
  }
}

async function seedAdminUser(): Promise<void> {
  try {
    await ensureStaffTableShape();
    const username = process.env.ADMIN_USERNAME?.trim() || "alijan";
    const password = process.env.ADMIN_PASSWORD?.trim();
    const fullName = process.env.ADMIN_FULL_NAME?.trim() || "المدير الرئيسي";
    const fallbackPassword =
      process.env.NODE_ENV === "production" ? null : "123123";
    const initialPassword = password || fallbackPassword;

    const legacy = await db.query.staffTable.findFirst({
      where: eq(staffTable.username, "admin"),
    });
    if (legacy) {
      const taken = await db.query.staffTable.findFirst({
        where: eq(staffTable.username, username),
      });
      if (!taken)
        await db
          .update(staffTable)
          .set({ username })
          .where(eq(staffTable.id, legacy.id));
    }

    const existing = await db.query.staffTable.findFirst({
      where: eq(staffTable.username, username),
    });
    if (existing) {
      const current = Array.isArray(existing.permissions)
        ? existing.permissions
        : [];
      const missing = ALL_PERMISSIONS.filter((p) => !current.includes(p));
      if (
        !existing.isActive ||
        existing.role !== "admin" ||
        missing.length > 0
      ) {
        await db
          .update(staffTable)
          .set({
            isActive: true,
            role: "admin",
            permissions: [...ALL_PERMISSIONS],
          })
          .where(eq(staffTable.id, existing.id));
      }
      return;
    }

    if (!initialPassword) {
      console.error(
        "ADMIN_PASSWORD is required to seed the first admin in production.",
      );
      return;
    }

    await db.insert(staffTable).values({
      username,
      passwordHash: hashPassword(initialPassword),
      fullName,
      role: "admin",
      permissions: [...ALL_PERMISSIONS],
      isActive: true,
    });
  } catch (err) {
    console.error("seedAdminUser failed:", err);
  }
}

async function ensureAdminSeeded(): Promise<void> {
  seedPromise ??= seedAdminUser().then(() => pruneExpiredSessions());
  return seedPromise;
}

function readAdminToken(req: NextRequest): string | null {
  const cookieToken = req.cookies.get(COOKIE_NAME)?.value;
  if (cookieToken) return cookieToken;
  return bearer(req);
}

async function getAdminUser(req: NextRequest): Promise<AdminUser | null> {
  const token = readAdminToken(req);
  if (!token) return null;
  const session = await db.query.adminSessionsTable.findFirst({
    where: and(
      eq(adminSessionsTable.token, token),
      gt(adminSessionsTable.expiresAt, new Date()),
    ),
  });
  if (!session) return null;
  const user = await db.query.staffTable.findFirst({
    where: eq(staffTable.id, session.userId),
  });
  if (!user || !user.isActive) return null;
  return {
    id: user.id,
    username: user.username,
    fullName: user.fullName,
    role: user.role,
    permissions: user.permissions ?? [],
    isActive: user.isActive,
  };
}

function hasPermission(
  user: AdminUser | null,
  perm: Permission | null,
): boolean {
  if (!user || !user.isActive) return false;
  if (user.role === "admin") return true;
  if (!perm) return true;
  return user.permissions.includes(perm);
}

async function requirePermission(
  req: NextRequest,
  perm: Permission,
): Promise<AdminUser | NextResponse> {
  const user = await getAdminUser(req);
  if (!user) return error("غير مخول", 401);
  if (!hasPermission(user, perm)) return error("ليس لديك صلاحية", 403);
  return user;
}

async function requireAnyPermission(
  req: NextRequest,
  perms: Permission[],
): Promise<AdminUser | NextResponse> {
  const user = await getAdminUser(req);
  if (!user) return error("غير مخول", 401);
  if (!perms.some((perm) => hasPermission(user, perm)))
    return error("ليس لديك صلاحية", 403);
  return user;
}

function isResponse(value: unknown): value is NextResponse {
  return value instanceof NextResponse;
}

function publicUser(u: AdminUser) {
  return {
    id: u.id,
    username: u.username,
    fullName: u.fullName,
    role: u.role,
    permissions: u.permissions,
    isActive: u.isActive,
  };
}

function safeDate(value: unknown): Date | null {
  if (!value) return null;
  const date = value instanceof Date ? value : new Date(String(value));
  return Number.isNaN(date.getTime()) ? null : date;
}

function idList(value: unknown): number[] {
  return Array.isArray(value)
    ? value
        .map((item) => Number.parseInt(String(item), 10))
        .filter((item) => Number.isFinite(item) && item > 0)
    : [];
}

function taskStatus(value: unknown): string {
  const status = String(value ?? "new");
  return ["new", "in_progress", "review", "completed", "cancelled"].includes(
    status,
  )
    ? status
    : "new";
}

function taskPriority(value: unknown): string {
  const priority = String(value ?? "medium");
  return ["low", "medium", "high", "urgent"].includes(priority)
    ? priority
    : "medium";
}

function messageStatus(value: unknown): string {
  const status = String(value ?? "new");
  return ["new", "read", "replied", "closed"].includes(status) ? status : "new";
}

function attendanceStatus(value: unknown): string {
  const status = String(value ?? "present");
  return ["present", "out", "late", "absent"].includes(status)
    ? status
    : "present";
}

function formatTask(
  row: any,
  staffById = new Map<number, any>(),
  entityProgress?: { total: number; completed: number; percent: number } | null,
) {
  const assigned = Array.isArray(row.assignedStaffIds)
    ? row.assignedStaffIds
    : (row.assigned_staff_ids ?? []);
  return {
    id: row.id,
    title: row.title,
    description: row.description ?? "",
    status: row.status,
    priority: row.priority,
    dueAt: row.dueAt?.toISOString?.() ?? row.due_at?.toISOString?.() ?? null,
    assignedStaffIds: assigned,
    assignedStaff: assigned
      .map((id: number) => staffById.get(id))
      .filter(Boolean),
    relatedType: row.relatedType ?? row.related_type ?? null,
    relatedId: row.relatedId ?? row.related_id ?? null,
    templateKey: row.templateKey ?? row.template_key ?? null,
    sequence: row.sequence ?? 0,
    autoGenerated: Number(row.autoGenerated ?? row.auto_generated ?? 0) === 1,
    entityProgress: entityProgress ?? null,
    notes: row.notes ?? "",
    attachments: Array.isArray(row.attachments) ? row.attachments : [],
    createdBy: row.createdBy ?? row.created_by ?? null,
    archivedAt:
      row.archivedAt?.toISOString?.() ??
      row.archived_at?.toISOString?.() ??
      null,
    createdAt:
      row.createdAt?.toISOString?.() ?? row.created_at?.toISOString?.() ?? null,
    updatedAt:
      row.updatedAt?.toISOString?.() ?? row.updated_at?.toISOString?.() ?? null,
  };
}

function formatMessageThread(row: any, replies: any[] = []) {
  return {
    id: row.id,
    customerId: row.customerId ?? row.customer_id ?? null,
    phone: row.phone ?? null,
    customerName: row.customerName ?? row.customer_name ?? "",
    subject: row.subject ?? "",
    status: row.status,
    relatedType: row.relatedType ?? row.related_type ?? null,
    relatedId: row.relatedId ?? row.related_id ?? null,
    lastMessageAt:
      row.lastMessageAt?.toISOString?.() ??
      row.last_message_at?.toISOString?.() ??
      null,
    createdAt:
      row.createdAt?.toISOString?.() ?? row.created_at?.toISOString?.() ?? null,
    updatedAt:
      row.updatedAt?.toISOString?.() ?? row.updated_at?.toISOString?.() ?? null,
    replies: replies.map((reply) => ({
      id: reply.id,
      threadId: reply.threadId ?? reply.thread_id,
      senderType: reply.senderType ?? reply.sender_type,
      staffId: reply.staffId ?? reply.staff_id ?? null,
      body: reply.body,
      createdAt:
        reply.createdAt?.toISOString?.() ??
        reply.created_at?.toISOString?.() ??
        null,
    })),
  };
}

function formatAttendance(row: any, staff?: any) {
  const inAt = row.checkInAt ?? row.check_in_at;
  const outAt = row.checkOutAt ?? row.check_out_at;
  const hours =
    inAt && outAt
      ? Math.max(
          0,
          (new Date(outAt).getTime() - new Date(inAt).getTime()) / 36e5,
        )
      : 0;
  return {
    id: row.id,
    staffId: row.staffId ?? row.staff_id,
    staffName: staff?.fullName || staff?.username || "",
    checkInAt: inAt?.toISOString?.() ?? inAt ?? null,
    checkOutAt: outAt?.toISOString?.() ?? outAt ?? null,
    status: row.status,
    notes: row.notes ?? "",
    hours: Number(hours.toFixed(2)),
    createdAt:
      row.createdAt?.toISOString?.() ?? row.created_at?.toISOString?.() ?? null,
    updatedAt:
      row.updatedAt?.toISOString?.() ?? row.updated_at?.toISOString?.() ?? null,
  };
}

function baseUrlFromReq(req: NextRequest): string {
  return process.env.APP_BASE_URL?.replace(/\/$/, "") || req.nextUrl.origin;
}

function publicQrTarget(
  entityType: string,
  _entity: any,
  req: NextRequest,
  token: string,
): string {
  const base = baseUrlFromReq(req);
  // Kosha bookings have their own customer tracking page; everything else uses order tracking.
  if (entityType === "kosha_booking")
    return `${base}/kosha-tracking/${encodeURIComponent(token)}`;
  return `${base}/track/${encodeURIComponent(token)}`;
}

async function ensureQrForEntity(
  entityType:
    | "order"
    | "service_order"
    | "invoice"
    | "kosha_booking"
    | "photography_order",
  entity: any,
  req: NextRequest,
) {
  await ensureAdminExtensionsTables();
  const existing = await db.query.qrTokensTable.findFirst({
    where: and(
      eq(qrTokensTable.entityType, entityType),
      eq(qrTokensTable.entityId, entity.id),
    ),
  });
  const token = existing?.token || randomBytes(32).toString("hex");
  const targetUrl = publicQrTarget(entityType, entity, req, token);
  if (!existing) {
    await db
      .insert(qrTokensTable)
      .values({ entityType, entityId: entity.id, token, targetUrl });
  } else if (
    existing.targetUrl !== targetUrl ||
    /\/admin(?:\/|$)|\/dashboard(?:\/|$)|\/orders(?:\/|$)|\/invoices(?:\/|$)/i.test(
      existing.targetUrl,
    )
  ) {
    await db
      .update(qrTokensTable)
      .set({ targetUrl })
      .where(eq(qrTokensTable.id, existing.id));
  }
  if (!entity.qrToken) {
    if (entityType === "order")
      await db
        .update(ordersTable)
        .set({ qrToken: token })
        .where(eq(ordersTable.id, entity.id));
    if (entityType === "service_order")
      await db
        .update(serviceOrdersTable)
        .set({ qrToken: token })
        .where(eq(serviceOrdersTable.id, entity.id));
    if (entityType === "invoice")
      await db
        .update(salesInvoicesTable)
        .set({ qrToken: token })
        .where(eq(salesInvoicesTable.id, entity.id));
  }
  const scanUrl = `${baseUrlFromReq(req)}/api/qr/${token}`;
  const dataUrl = await QRCode.toDataURL(scanUrl, { margin: 1, width: 240 });
  return { token, targetUrl, scanUrl, dataUrl };
}

// Digital DNA — deterministic identity fingerprint for an asset, derived from its
// immutable attributes. Same inputs always yield the same code, so it doubles as a
// tamper-evident signature printed on the asset.
function assetDigitalDna(
  productId: number,
  serialNumber: string | null | undefined,
  purchaseDate: Date | string | null | undefined,
  purchasePrice: number | string,
): string {
  const dateKey = purchaseDate
    ? new Date(purchaseDate).toISOString().slice(0, 10)
    : "";
  const seed = `${productId}|${(serialNumber ?? "").trim().toUpperCase()}|${dateKey}|${purchasePrice}`;
  const hash = createHash("sha256")
    .update(seed)
    .digest("hex")
    .slice(0, 12)
    .toUpperCase();
  return `AJN-A${productId}-${hash}`;
}

// Per-type pre-checkout checklist — picked from the asset's category/name keywords.
function assetChecklistFor(product: {
  nameAr?: string | null;
  name?: string | null;
  category?: string | null;
  subcategory?: string | null;
}): string[] {
  const hay =
    `${product.category ?? ""} ${product.subcategory ?? ""} ${product.nameAr ?? ""} ${product.name ?? ""}`.toLowerCase();
  const has = (...keys: string[]) => keys.some((k) => hay.includes(k));
  if (has("كاميرا", "تصوير", "camera", "lens", "عدسة"))
    return [
      "البطارية",
      "العدسة",
      "الشاحن",
      "كرت الذاكرة",
      "الحقيبة",
      "اختبار التشغيل",
    ];
  if (has("إضاء", "اضاء", "light", "فلاش", "flash", "led"))
    return [
      "الكابلات",
      "اللمبات/الإضاءة",
      "الحامل (الاستاند)",
      "وحدة التحكم",
      "اختبار التشغيل",
    ];
  if (has("صوت", "سماع", "speaker", "audio", "مايك", "mic"))
    return ["الكابلات", "المايكات", "البطاريات", "اختبار الصوت", "الحقيبة"];
  if (has("كوش", "kosha", "ديكور", "decor", "ستارة", "قماش"))
    return [
      "اكتمال القطع",
      "سلامة القماش/الإطار",
      "الإكسسوارات",
      "النظافة العامة",
      "تصوير الحالة",
    ];
  return [
    "النظافة العامة",
    "سلامة الأجزاء والوصلات",
    "اختبار التشغيل",
    "اكتمال الملحقات",
    "تصوير الحالة قبل التسليم",
  ];
}

function assetMetadataObject(value: unknown): Record<string, any> {
  return value && typeof value === "object" && !Array.isArray(value)
    ? (value as Record<string, any>)
    : {};
}

function assetHealthSnapshot(input: {
  purchaseDate?: Date | string | null;
  purchasePrice: number;
  maintenanceCost: number;
  usageCount: number;
  expectedLifeUses: number;
  repairCount: number;
  damageCount: number;
  lastInspectionAt?: Date | string | null;
}) {
  const now = Date.now();
  const purchaseAt = input.purchaseDate
    ? new Date(input.purchaseDate).getTime()
    : Number.NaN;
  const ageYears = Number.isFinite(purchaseAt)
    ? Math.max(0, (now - purchaseAt) / (365.25 * 86400000))
    : 0;
  const inspectedAt = input.lastInspectionAt
    ? new Date(input.lastInspectionAt).getTime()
    : Number.NaN;
  const inspectionDays = Number.isFinite(inspectedAt)
    ? Math.max(0, (now - inspectedAt) / 86400000)
    : null;
  const usageRatio = Math.min(
    1.25,
    input.usageCount / Math.max(1, input.expectedLifeUses),
  );
  const maintenanceRatio = input.purchasePrice
    ? Math.min(1, input.maintenanceCost / input.purchasePrice)
    : 0;
  const inspectionPenalty =
    inspectionDays === null
      ? 8
      : inspectionDays > 365
        ? 12
        : inspectionDays > 180
          ? 6
          : 0;
  const score = Math.max(
    0,
    Math.min(
      100,
      Math.round(
        100 -
          usageRatio * 35 -
          maintenanceRatio * 25 -
          Math.min(15, input.repairCount * 3) -
          Math.min(20, input.damageCount * 5) -
          Math.min(10, ageYears * 1.25) -
          inspectionPenalty,
      ),
    ),
  );
  const label =
    score >= 85
      ? "ممتاز"
      : score >= 65
        ? "جيد"
        : score >= 40
          ? "يحتاج صيانة"
          : "حرج";
  return {
    score,
    label,
    ageYears: Number(ageYears.toFixed(1)),
    inspectionDays: inspectionDays === null ? null : Math.round(inspectionDays),
  };
}

// Scan&Go — a stable QR per asset that resolves through the public /track gateway
// to a safe, financial-free asset status card. Reuses the shared qr_tokens table.
async function ensureAssetQr(productId: number, req: NextRequest) {
  await ensureAdminExtensionsTables();
  const existing = await db.query.qrTokensTable.findFirst({
    where: and(
      eq(qrTokensTable.entityType, "asset"),
      eq(qrTokensTable.entityId, productId),
    ),
  });
  const token = existing?.token || randomBytes(32).toString("hex");
  const targetUrl = publicQrTarget("asset", { id: productId }, req, token);
  if (!existing) {
    await db
      .insert(qrTokensTable)
      .values({ entityType: "asset", entityId: productId, token, targetUrl });
  } else if (existing.targetUrl !== targetUrl) {
    await db
      .update(qrTokensTable)
      .set({ targetUrl })
      .where(eq(qrTokensTable.id, existing.id));
  }
  const scanUrl = `${baseUrlFromReq(req)}/api/qr/${token}`;
  const dataUrl = await QRCode.toDataURL(scanUrl, { margin: 1, width: 240 });
  return { token, targetUrl, scanUrl, dataUrl };
}

let webPushConfigured = false;

function boolFromDb(value: unknown, fallback = true) {
  if (value === null || value === undefined) return fallback;
  return Number(value) !== 0 && value !== false;
}

function notificationSettingsToJson(row: any = {}) {
  return {
    pushEnabled: boolFromDb(row.pushEnabled ?? row.push_enabled, true),
    ordersEnabled: boolFromDb(row.ordersEnabled ?? row.orders_enabled, true),
    messagesEnabled: boolFromDb(
      row.messagesEnabled ?? row.messages_enabled,
      true,
    ),
    tasksEnabled: boolFromDb(row.tasksEnabled ?? row.tasks_enabled, true),
    inventoryEnabled: boolFromDb(
      row.inventoryEnabled ?? row.inventory_enabled,
      true,
    ),
    customerEnabled: boolFromDb(
      row.customerEnabled ?? row.customer_enabled,
      true,
    ),
  };
}

async function getGlobalNotificationSettings() {
  await ensureAdminExtensionsTables();
  const row = await db.query.notificationSettingsTable.findFirst({
    where: and(
      eq(notificationSettingsTable.ownerType, "global"),
      sql`${notificationSettingsTable.ownerId} is null`,
    ),
  });
  return notificationSettingsToJson(row);
}

function notificationTypeEnabled(
  settings: ReturnType<typeof notificationSettingsToJson>,
  type: string,
  audienceType: string,
) {
  if (!settings.pushEnabled) return false;
  if (audienceType === "customer" && !settings.customerEnabled) return false;
  if (type.includes("order") || type.includes("booking"))
    return settings.ordersEnabled;
  if (type.includes("message")) return settings.messagesEnabled;
  if (type.includes("task")) return settings.tasksEnabled;
  if (type.includes("inventory")) return settings.inventoryEnabled;
  return true;
}

function getVapidPublicKey() {
  return (
    process.env.VAPID_PUBLIC_KEY ||
    process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY ||
    ""
  );
}

function configureWebPush() {
  const publicKey = getVapidPublicKey();
  const privateKey = process.env.VAPID_PRIVATE_KEY || "";
  if (!publicKey || !privateKey) return false;
  if (!webPushConfigured) {
    const subject =
      process.env.VAPID_SUBJECT ||
      process.env.APP_BASE_URL ||
      "mailto:admin@ajn.local";
    webpush.setVapidDetails(subject, publicKey, privateKey);
    webPushConfigured = true;
  }
  return true;
}

async function sendPushToSubscriptions(
  subscriptions: any[],
  payload: Record<string, unknown>,
) {
  if (!configureWebPush() || subscriptions.length === 0) return;
  await Promise.allSettled(
    subscriptions.map(async (sub) => {
      try {
        await webpush.sendNotification(
          {
            endpoint: sub.endpoint,
            keys: { p256dh: sub.p256dh, auth: sub.auth },
          },
          JSON.stringify(payload),
        );
      } catch (err: any) {
        const status = Number(err?.statusCode ?? err?.status);
        if (status === 404 || status === 410) {
          await db
            .update(notificationSubscriptionsTable)
            .set({ isActive: 0, updatedAt: new Date() })
            .where(eq(notificationSubscriptionsTable.id, sub.id));
        } else {
          console.error("push notification failed", {
            status,
            message: err?.message,
          });
        }
      }
    }),
  );
}

async function createNotification(input: {
  audienceType?: "admin" | "customer";
  staffId?: number | null;
  customerId?: number | null;
  type: string;
  title: string;
  body?: string;
  entityType?: string | null;
  entityId?: number | null;
  href?: string | null;
  metadata?: Record<string, unknown>;
}) {
  await ensureAdminExtensionsTables();
  const audienceType = input.audienceType ?? "admin";
  const settings = await getGlobalNotificationSettings();
  const [row] = await db
    .insert(notificationsTable)
    .values({
      audienceType,
      staffId: input.staffId ?? null,
      customerId: input.customerId ?? null,
      type: input.type,
      title: input.title,
      body: input.body ?? "",
      entityType: input.entityType ?? null,
      entityId: input.entityId ?? null,
      href: input.href ?? null,
      metadata: input.metadata ?? {},
    })
    .returning();
  if (notificationTypeEnabled(settings, input.type, audienceType)) {
    let subscriptions: any[] = [];
    if (audienceType === "customer" && input.customerId) {
      subscriptions = await db.query.notificationSubscriptionsTable.findMany({
        where: and(
          eq(notificationSubscriptionsTable.ownerType, "customer"),
          eq(notificationSubscriptionsTable.customerId, input.customerId),
          eq(notificationSubscriptionsTable.isActive, 1),
        ),
      });
    } else {
      const managerRows = await db.query.staffTable.findMany({
        where: and(
          eq(staffTable.isActive, true),
          sql`${staffTable.role} in ('admin','manager')`,
        ),
      });
      const staffIds = input.staffId
        ? [input.staffId]
        : managerRows.map((staff) => staff.id);
      subscriptions = staffIds.length
        ? await db.query.notificationSubscriptionsTable.findMany({
            where: and(
              eq(notificationSubscriptionsTable.ownerType, "staff"),
              inArray(notificationSubscriptionsTable.staffId, staffIds),
              eq(notificationSubscriptionsTable.isActive, 1),
            ),
          })
        : [];
    }
    await sendPushToSubscriptions(subscriptions, {
      id: row.id,
      title: row.title,
      body: row.body,
      type: row.type,
      href: row.href,
      icon: "/icons/icon-192.png",
      badge: "/icons/icon-192.png",
      tag: `${row.type}-${row.entityType ?? "item"}-${row.entityId ?? row.id}`,
    });
  }
  return row;
}

async function createNotificationOnce(
  input: Parameters<typeof createNotification>[0],
) {
  await ensureAdminExtensionsTables();
  const audienceType = input.audienceType ?? "admin";
  if (input.entityType && input.entityId) {
    const existing = await db.query.notificationsTable.findFirst({
      where: and(
        eq(notificationsTable.audienceType, audienceType),
        eq(notificationsTable.type, input.type),
        eq(notificationsTable.entityType, input.entityType),
        eq(notificationsTable.entityId, input.entityId),
        sql`${notificationsTable.archivedAt} is null`,
      ),
    });
    if (existing) return existing;
  }
  return createNotification(input);
}

async function notifyOrderNeedsFollowup(input: {
  kind: "order" | "service_order";
  id: number;
  trackingCode?: string | null;
  customerName?: string | null;
  paymentStatus?: string | null;
  remainingAmount?: string | number | null;
  reason?: "payment" | "late";
}) {
  const remaining = money(input.remainingAmount ?? 0);
  const isLate = input.reason === "late";
  const paymentStatus = String(input.paymentStatus ?? "unpaid");
  if (!isLate && paymentStatus === "paid" && remaining <= 0) return null;
  return createNotificationOnce({
    type: "order_followup",
    title: isLate ? "طلب يحتاج متابعة" : "طلب يحتاج متابعة مالية",
    body: `${input.customerName || "زبون"} - ${input.trackingCode || `#${input.id}`}${remaining > 0 ? ` - المتبقي ${formatCurrency(remaining)}` : ""}`,
    entityType: input.kind,
    entityId: input.id,
    href: "/admin/orders",
    metadata: {
      reason: input.reason ?? "payment",
      paymentStatus,
      remainingAmount: remaining,
    },
  });
}

async function customerIdForPhone(phone: string | null | undefined) {
  const normalized = normalizeIraqiPhone(phone ?? "");
  if (!normalized) return null;
  const customer = await db.query.customersTable.findFirst({
    where: inArray(customersTable.phone, iraqiPhoneVariants(normalized)),
  });
  return customer?.id ?? null;
}

async function createCustomerNotificationByPhone(
  phone: string | null | undefined,
  input: Omit<
    Parameters<typeof createNotification>[0],
    "audienceType" | "customerId"
  >,
) {
  const customerId = await customerIdForPhone(phone);
  if (!customerId) return null;
  return createNotification({ ...input, audienceType: "customer", customerId });
}

type ErpActor = { id?: number | null; name?: string | null };

