function erpEntityHref(entityType: string, entityId?: number | null): string {
  if (entityType === "kosha_booking") return "/admin/kosha-bookings";
  if (entityType === "photography_event")
    return entityId
      ? `/staff/photography/events/${entityId}/register`
      : "/staff/photography";
  if (entityType === "photography_order")
    return entityId
      ? `/staff/photography/orders/${entityId}`
      : "/staff/photography/orders";
  if (entityType === "service_order") return "/admin/orders";
  if (entityType === "order") return "/admin/orders";
  if (entityType === "sales_invoice") return "/admin/sales";
  if (entityType === "purchase_invoice") return "/admin/purchases";
  if (entityType === "product") return "/admin/products";
  return "/admin/dashboard";
}

