async function notifyLowStockForProductIds(productIds: number[]) {
  const ids = await stockOwnerIdsForProductIds(productIds);
  if (ids.length === 0) return;
  const rows = await db.query.productsTable.findMany({
    where: and(
      inArray(productsTable.id, ids),
      sql`${productsTable.stock} <= ${productsTable.minStock}`,
    ),
    limit: 20,
  });
  await Promise.all(
    rows.map((product) =>
      createNotification({
        type: "inventory_low",
        title: "انخفاض المخزون",
        body: `${product.nameAr || product.name} وصل إلى ${product.stock}`,
        entityType: "product",
        entityId: product.id,
        href: "/admin/inventory-alerts",
      }),
    ),
  );
}

function withSessionCookie(res: NextResponse, token: string): NextResponse {
  res.cookies.set(COOKIE_NAME, token, {
    httpOnly: true,
    secure: isProd,
    sameSite: "lax",
    path: "/",
    maxAge: Math.floor(SESSION_TTL_MS / 1000),
  });
  return res;
}

function clearSessionCookie(res: NextResponse): NextResponse {
  res.cookies.set(COOKIE_NAME, "", {
    httpOnly: true,
    secure: isProd,
    sameSite: "lax",
    path: "/",
    maxAge: 0,
  });
  return res;
}

const MEDIA_CACHE_HEADER = "public, max-age=31536000, immutable";
const STORAGE_BUCKET =
  process.env.SUPABASE_STORAGE_BUCKET ||
  process.env.SUPABASE_BUCKET ||
  "ajn-assets";
const STORAGE_URL =
  process.env.SUPABASE_URL || process.env.NEXT_PUBLIC_SUPABASE_URL || "";
const STORAGE_SERVICE_KEY =
  process.env.SUPABASE_SERVICE_ROLE_KEY ||
  process.env.SUPABASE_SERVICE_ROLE ||
  "";

function isDataUrl(value: unknown): boolean {
  return typeof value === "string" && value.startsWith("data:");
}

function parseDataUrl(value: string): { mime: string; bytes: Buffer } | null {
  const match = /^data:([^;,]+)(;base64)?,(.*)$/s.exec(value);
  if (!match) return null;
  const mime = match[1] || "application/octet-stream";
  const payload = match[3] || "";
  try {
    const bytes = match[2]
      ? Buffer.from(payload, "base64")
      : Buffer.from(decodeURIComponent(payload), "utf8");
    return { mime, bytes };
  } catch {
    return null;
  }
}

function bodyFromBuffer(bytes: Buffer): ArrayBuffer {
  return bytes.buffer.slice(
    bytes.byteOffset,
    bytes.byteOffset + bytes.byteLength,
  ) as ArrayBuffer;
}

function mediaVersion(row: any): string {
  const value =
    row?.updatedAt ??
    row?.updated_at ??
    row?.createdAt ??
    row?.created_at ??
    "";
  if (value instanceof Date) return String(value.getTime());
  return value
    ? String(value)
        .replace(/[^0-9a-z]/gi, "")
        .slice(0, 24)
    : "1";
}

function mediaRoute(
  kind: string,
  id: number | string,
  index?: number,
  version?: string,
) {
  const suffix = typeof index === "number" ? `/${index}` : "";
  const qs = version ? `?v=${encodeURIComponent(version)}` : "";
  return `/api/media/${kind}/${id}${suffix}${qs}`;
}

function publicMediaValue(
  kind: string,
  row: any,
  value: unknown,
  index?: number,
) {
  if (!value || typeof value !== "string") return null;
  if (isDataUrl(value))
    return mediaRoute(kind, row.id, index, mediaVersion(row));
  return value;
}

function publicMediaList(kind: string, row: any, images: unknown) {
  if (!Array.isArray(images)) return [];
  return images
    .map((value, index) => publicMediaValue(kind, row, value, index))
    .filter((value): value is string => Boolean(value));
}

function storageExtension(mime: string) {
  if (mime.includes("webp")) return "webp";
  if (mime.includes("png")) return "png";
  if (mime.includes("jpeg") || mime.includes("jpg")) return "jpg";
  if (mime.includes("gif")) return "gif";
  if (mime.includes("svg")) return "svg";
  if (mime.includes("mp4")) return "mp4";
  if (mime.includes("webm")) return "webm";
  if (mime.includes("quicktime")) return "mov";
  return "bin";
}

async function persistDataUrlToStorage(
  value: string,
  folder: string,
): Promise<string> {
  if (!STORAGE_URL || !STORAGE_SERVICE_KEY) return value;
  const parsed = parseDataUrl(value);
  if (!parsed) return value;
  const path = `${folder}/${new Date().toISOString().slice(0, 10)}/${Date.now()}-${randomUUID()}.${storageExtension(parsed.mime)}`;
  try {
    const upload = await fetch(
      `${STORAGE_URL.replace(/\/$/, "")}/storage/v1/object/${STORAGE_BUCKET}/${path}`,
      {
        method: "POST",
        headers: {
          apikey: STORAGE_SERVICE_KEY,
          authorization: `Bearer ${STORAGE_SERVICE_KEY}`,
          "content-type": parsed.mime,
          "x-upsert": "true",
        },
        body: bodyFromBuffer(parsed.bytes),
      },
    );
    if (!upload.ok) {
      console.warn("Supabase storage upload failed", {
        folder,
        status: upload.status,
      });
      return value;
    }
    return `${STORAGE_URL.replace(/\/$/, "")}/storage/v1/object/public/${STORAGE_BUCKET}/${path}`;
  } catch (err) {
    console.warn("Supabase storage upload failed", {
      folder,
      error: err instanceof Error ? err.message : "unknown",
    });
    return value;
  }
}

function cleanMediaInput(value: unknown): string {
  const raw = String(value ?? "").trim();
  if (!raw) return "";
  if (raw.startsWith("data:image/") || raw.startsWith("data:video/"))
    return raw;
  return cleanPublicUrl(raw);
}

async function persistMediaValue(
  value: unknown,
  folder: string,
): Promise<string | null> {
  const cleaned = cleanMediaInput(value ?? "");
  if (!cleaned) return null;
  return isDataUrl(cleaned)
    ? persistDataUrlToStorage(cleaned, folder)
    : cleaned;
}

async function persistMediaList(
  images: unknown,
  folder: string,
): Promise<string[]> {
  if (!Array.isArray(images)) return [];
  const stored: string[] = [];
  for (const image of images) {
    const value = await persistMediaValue(image, folder);
    if (value) stored.push(value);
  }
  return stored;
}

function localMediaReference(value: unknown) {
  if (typeof value !== "string") return null;
  const match = /^\/api\/media\/([^/?#]+)\/(\d+)(?:\/(\d+))?/.exec(value);
  if (!match) return null;
  return {
    kind: match[1],
    id: Number.parseInt(match[2] ?? "0", 10),
    index: match[3] !== undefined ? Number.parseInt(match[3], 10) : undefined,
  };
}

async function resolveProductImageInputs(
  productId: number,
  images: unknown,
): Promise<string[]> {
  if (!Array.isArray(images)) return [];
  let currentImages: string[] | null = null;
  const resolved: unknown[] = [];
  for (const image of images) {
    const ref = localMediaReference(image);
    if (
      ref?.kind === "product" &&
      ref.id === productId &&
      typeof ref.index === "number"
    ) {
      if (!currentImages) {
        const current = (await db.query.productsTable.findFirst({
          where: eq(productsTable.id, productId),
        })) as any;
        currentImages = Array.isArray(current?.images) ? current.images : [];
      }
      resolved.push((currentImages ?? [])[ref.index] ?? "");
    } else {
      resolved.push(image);
    }
  }
  return persistMediaList(resolved, "products");
}

async function resolveProductVideoInputs(
  productId: number,
  videos: unknown,
): Promise<string[]> {
  if (!Array.isArray(videos)) return [];
  let currentVideos: string[] | null = null;
  const resolved: unknown[] = [];
  for (const video of videos) {
    const ref = localMediaReference(video);
    if (
      ref?.kind === "product-video" &&
      ref.id === productId &&
      typeof ref.index === "number"
    ) {
      if (!currentVideos) {
        const current = (await db.query.productsTable.findFirst({
          where: eq(productsTable.id, productId),
        })) as any;
        currentVideos = Array.isArray(current?.videos) ? current.videos : [];
      }
      resolved.push((currentVideos ?? [])[ref.index] ?? "");
    } else {
      resolved.push(video);
    }
  }
  return persistMediaList(resolved, "products/videos");
}

async function upgradeStoredMedia(
  kind: string,
  id: number | string,
  value: unknown,
  index?: number,
): Promise<unknown> {
  if (!isDataUrl(value)) return value;
  const stored = await persistDataUrlToStorage(
    String(value),
    kind === "settings" ? "settings/logo" : kind,
  );
  if (stored === value) return value;
  try {
    if (
      kind === "product" &&
      typeof id === "number" &&
      typeof index === "number"
    ) {
      const product = (await db.query.productsTable.findFirst({
        where: eq(productsTable.id, id),
      })) as any;
      const images = Array.isArray(product?.images) ? [...product.images] : [];
      images[index] = stored;
      await db
        .update(productsTable)
        .set({ images, updatedAt: new Date() })
        .where(eq(productsTable.id, id));
    } else if (
      kind === "product-video" &&
      typeof id === "number" &&
      typeof index === "number"
    ) {
      const product = (await db.query.productsTable.findFirst({
        where: eq(productsTable.id, id),
      })) as any;
      const videos = Array.isArray(product?.videos) ? [...product.videos] : [];
      videos[index] = stored;
      await db
        .update(productsTable)
        .set({ videos, updatedAt: new Date() })
        .where(eq(productsTable.id, id));
    } else if (kind === "category" && typeof id === "number") {
      await db
        .update(categoriesTable)
        .set({ imageUrl: stored, updatedAt: new Date() })
        .where(eq(categoriesTable.id, id));
      clearStoreCategoriesCache();
    } else if (kind === "service" && typeof id === "number") {
      await db
        .update(servicesTable)
        .set({ image: stored })
        .where(eq(servicesTable.id, id));
    } else if (kind === "gallery" && typeof id === "number") {
      await db
        .update(galleryItemsTable)
        .set({ mediaUrl: stored })
        .where(eq(galleryItemsTable.id, id));
    } else if (kind === "kosha" && typeof id === "number") {
      await db
        .update(koshasTable)
        .set({ mainImage: stored, updatedAt: new Date() })
        .where(eq(koshasTable.id, id));
    } else if (kind === "kosha-image" && typeof id === "number") {
      await db
        .update(koshaImagesTable)
        .set({ imageUrl: stored })
        .where(eq(koshaImagesTable.id, id));
    } else if (kind === "kosha-addon" && typeof id === "number") {
      await db
        .update(koshaAddonsTable)
        .set({ mainImage: stored, updatedAt: new Date() })
        .where(eq(koshaAddonsTable.id, id));
    } else if (kind === "kosha-welcome-board" && typeof id === "number") {
      await db
        .update(koshaWelcomeBoardsTable)
        .set({ mainImage: stored, updatedAt: new Date() })
        .where(eq(koshaWelcomeBoardsTable.id, id));
    } else if (kind === "kosha-accessory" && typeof id === "number") {
      await db
        .update(koshaAccessoriesTable)
        .set({ mainImage: stored, updatedAt: new Date() })
        .where(eq(koshaAccessoriesTable.id, id));
    } else if (kind === "order-item" && typeof id === "number") {
      await db
        .update(orderItemsTable)
        .set({ image: stored })
        .where(eq(orderItemsTable.id, id));
    } else if (kind === "customer-avatar" && typeof id === "number") {
      await db
        .update(customersTable)
        .set({ avatarUrl: stored, updatedAt: new Date() })
        .where(eq(customersTable.id, id));
    } else if (kind === "settings") {
      await db
        .insert(settingsTable)
        .values({ key: "logoUrl", value: stored as any })
        .onConflictDoUpdate({
          target: settingsTable.key,
          set: { value: stored as any, updatedAt: new Date() },
        });
      revalidateTag(PUBLIC_SETTINGS_TAG, { expire: 0 });
    }
  } catch (err) {
    console.warn("Stored media upgrade failed", {
      kind,
      id,
      error: err instanceof Error ? err.message : "unknown",
    });
  }
  return stored;
}

// يستخرج حقول ترجمة المحتوى من جسم الطلب (إضافية وغير مخلّة بأي عقد API قائم)
function pickContentTranslations(
  src: any,
  withDescription: boolean,
): Record<string, string | null> {
  const out: Record<string, string | null> = {};
  const keys = withDescription
    ? ["nameKu", "nameTr", "descriptionKu", "descriptionTr"]
    : ["nameKu", "nameTr"];
  for (const k of keys) {
    if (src && src[k] !== undefined) out[k] = nullableText(src[k]);
  }
  return out;
}

function formatProduct(p: any, avgRating?: number, reviewCount?: number) {
  return {
    id: p.id,
    name: p.name,
    nameAr: p.nameAr,
    nameKu: p.nameKu ?? p.name_ku ?? null,
    nameTr: p.nameTr ?? p.name_tr ?? null,
    description: p.description ?? null,
    descriptionAr: p.descriptionAr ?? null,
    descriptionKu: p.descriptionKu ?? p.description_ku ?? null,
    descriptionTr: p.descriptionTr ?? p.description_tr ?? null,
    price: Number.parseFloat(p.price),
    originalPrice: p.originalPrice ? Number.parseFloat(p.originalPrice) : null,
    stock: Number(p.effectiveStock ?? p.stock ?? 0),
    ownStock: Number(p.ownStock ?? p.stock ?? 0),
    isRental: Boolean(p.isRental ?? p.is_rental ?? false),
    pricePerDay:
      Number.parseFloat(String(p.pricePerDay ?? p.price_per_day ?? "0")) || 0,
    minStock: Number(p.effectiveMinStock ?? p.minStock ?? p.min_stock ?? 0),
    sharedStockProductId:
      p.sharedStockProductId ?? p.shared_stock_product_id ?? null,
    sharedStockProductName:
      p.sharedStockProductName ?? p.shared_stock_product_name ?? null,
    sharedStockLinkedProducts: Array.isArray(p.sharedStockLinkedProducts)
      ? p.sharedStockLinkedProducts
      : [],
    barcode: p.barcode ?? null,
    costPrice:
      Number.parseFloat(String(p.costPrice ?? p.cost_price ?? "0")) || 0,
    categoryId: p.categoryId ?? p.category_id ?? null,
    subcategoryId: p.subcategoryId ?? p.subcategory_id ?? null,
    categoryName: p.categoryName ?? p.category_name ?? null,
    subcategoryName: p.subcategoryName ?? p.subcategory_name ?? null,
    category: p.category ?? null,
    images: publicMediaList("product", p, p.images),
    videos: publicMediaList("product-video", p, p.videos),
    imageMetadata: Array.isArray(p.imageMetadata) ? p.imageMetadata : [],
    colors: normalizeColors(p.colors ?? []),
    subcategory: p.subcategory ?? null,
    isFeatured: p.isFeatured,
    isActive: p.isActive ?? true,
    sortOrder: p.sortOrder ?? 0,
    rating: avgRating ?? null,
    reviewCount: reviewCount ?? 0,
    createdAt: p.createdAt.toISOString(),
  };
}

const KOSHA_STATUS_VALUES = [
  "available",
  "booked",
  "hidden",
  "maintenance",
] as const;
const KOSHA_BOOKING_STATUS_VALUES = [
  "new",
  "contacted",
  "confirmed",
  "in_progress",
  "completed",
  "cancelled",
] as const;
const blankToZero = (value: unknown) =>
  value === "" || value === null || value === undefined || Number.isNaN(value)
    ? 0
    : value;
const blankToNull = (value: unknown) =>
  value === "" || value === null || value === undefined || Number.isNaN(value)
    ? null
    : value;
const looseText = (value: unknown) =>
  value === null || value === undefined ? "" : String(value);
const looseBoolean = (value: unknown) => {
  if (typeof value === "boolean") return value;
  if (typeof value === "number") return value !== 0;
  const text = String(value ?? "")
    .trim()
    .toLowerCase();
  if (["false", "0", "no", "off", "لا"].includes(text)) return false;
  if (["true", "1", "yes", "on", "نعم"].includes(text)) return true;
  return Boolean(value);
};

