function normalizeKoshaAccessories(value: unknown): string[] {
  if (Array.isArray(value)) {
    return value.map((item) => String(item ?? "").trim()).filter(Boolean);
  }
  return String(value ?? "")
    .split(/\n|،|,/)
    .map((item) => item.trim())
    .filter(Boolean);
}

function normalizeKoshaStringList(value: unknown): string[] {
  if (!Array.isArray(value)) return [];
  return value.map((item) => String(item ?? "").trim()).filter(Boolean);
}

function normalizeIdList(value: unknown): number[] {
  if (!Array.isArray(value)) return [];
  return Array.from(
    new Set(
      value
        .map((item) => Number(item))
        .filter((item) => Number.isInteger(item) && item > 0),
    ),
  );
}

function koshaOptionImageKind(
  section: "addon" | "welcome_board" | "accessory",
) {
  if (section === "addon") return "kosha-addon";
  if (section === "welcome_board") return "kosha-welcome-board";
  return "kosha-accessory";
}

function formatKoshaOptionProduct(
  row: any,
  section: "addon" | "welcome_board" | "accessory",
) {
  return {
    id: row.id,
    name: row.name,
    price: Number.parseFloat(String(row.price ?? "0")) || 0,
    description: row.description ?? "",
    mainImage: publicMediaValue(
      koshaOptionImageKind(section),
      row,
      row.mainImage ?? row.main_image,
    ),
    isActive: row.isActive ?? row.is_active ?? true,
    sortOrder: row.sortOrder ?? row.sort_order ?? 0,
    createdAt:
      row.createdAt?.toISOString?.() ??
      String(row.createdAt ?? row.created_at ?? ""),
    updatedAt:
      row.updatedAt?.toISOString?.() ??
      String(row.updatedAt ?? row.updated_at ?? ""),
  };
}

async function koshaOptionValuesFromData(data: any, folder: string) {
  const values: any = { updatedAt: new Date() };
  if (data.name !== undefined) values.name = textFallback(data.name, "");
  if (data.price !== undefined) values.price = String(money(data.price));
  if (data.description !== undefined)
    values.description = nullableText(data.description);
  if (data.mainImage !== undefined)
    values.mainImage = await persistMediaValue(data.mainImage, folder);
  if (data.isActive !== undefined) values.isActive = data.isActive !== false;
  if (data.sortOrder !== undefined)
    values.sortOrder = Number.isFinite(Number(data.sortOrder))
      ? Number(data.sortOrder)
      : 0;
  return values;
}

function koshaOptionSummary(
  items: Array<{
    name: string;
    price: number;
    mainImage?: string | null;
    description?: string | null;
  }>,
  selected: string[],
) {
  const selectedSet = new Set(
    selected.map((item) => String(item ?? "").trim()).filter(Boolean),
  );
  return items
    .filter((item) => selectedSet.has(item.name))
    .map((item) => ({
      name: item.name,
      price: Number(item.price ?? 0) || 0,
      image: item.mainImage ?? null,
      description: item.description ?? "",
    }));
}

function normalizeKoshaSlug(value: unknown, fallback: unknown): string {
  const base = slugFallback(
    value,
    slugFallback(fallback, `kosha-${Date.now().toString(36)}`),
  );
  return base.slice(0, 150);
}

async function uniqueKoshaSlug(
  input: string,
  ignoreId?: number,
): Promise<string> {
  let base = normalizeKoshaSlug(input, "kosha");
  let slug = base;
  let attempt = 1;
  while (true) {
    const existing = await db.query.koshasTable.findFirst({
      where: eq(koshasTable.slug, slug),
    });
    if (!existing || existing.id === ignoreId) return slug;
    attempt += 1;
    slug = `${base}-${attempt}`.slice(0, 160);
  }
}

async function loadKoshaImages(koshaId: number) {
  const images = await db.query.koshaImagesTable.findMany({
    where: eq(koshaImagesTable.koshaId, koshaId),
    orderBy: (img, { asc }) => [asc(img.sortOrder), asc(img.id)],
  });
  return images.map((image) => ({
    id: image.id,
    imageUrl: publicMediaValue("kosha-image", image, image.imageUrl),
    imageMetadata: image.imageMetadata ?? {},
    sortOrder: image.sortOrder ?? 0,
    createdAt: image.createdAt.toISOString(),
  }));
}

async function formatKosha(row: any, includeImages = true) {
  const images = includeImages ? await loadKoshaImages(row.id) : [];
  return {
    id: row.id,
    name: row.name,
    slug: row.slug,
    description: row.description ?? "",
    price: Number.parseFloat(String(row.price ?? "0")) || 0,
    oldPrice: row.oldPrice ? Number.parseFloat(String(row.oldPrice)) : null,
    discountPercentage: Number(row.discountPercentage ?? 0),
    mainImage: publicMediaValue("kosha", row, row.mainImage),
    galleryImages: images,
    numberOfPieces: row.numberOfPieces ?? null,
    mainColor: row.mainColor ?? null,
    flowerColor: row.flowerColor ?? null,
    koshaSpace: row.koshaSpace ?? null,
    sideConsoleSpace: row.sideConsoleSpace ?? null,
    accessories: Array.isArray(row.accessories) ? row.accessories : [],
    notes: row.notes ?? null,
    availabilityStatus: row.availabilityStatus ?? "available",
    isFeatured: row.isFeatured ?? false,
    isActive: row.isActive ?? true,
    sortOrder: row.sortOrder ?? 0,
    categoryId: row.categoryId ?? null,
    createdAt: row.createdAt?.toISOString?.() ?? String(row.createdAt ?? ""),
    updatedAt: row.updatedAt?.toISOString?.() ?? String(row.updatedAt ?? ""),
  };
}

async function uniqueKoshaPackageSlug(
  input: string,
  ignoreId?: number,
): Promise<string> {
  const base = normalizeKoshaSlug(input, "kosha-package");
  let slug = base;
  let attempt = 1;
  while (true) {
    const existing = await db.query.koshaPackagesTable.findFirst({
      where: eq(koshaPackagesTable.slug, slug),
    });
    if (!existing || existing.id === ignoreId) return slug;
    attempt += 1;
    slug = `${base}-${attempt}`.slice(0, 160);
  }
}

async function loadKoshaPackageParts(packageId: number) {
  const links = await db.query.koshaPackageComponentsTable.findMany({
    where: eq(koshaPackageComponentsTable.packageId, packageId),
    orderBy: (item, { asc }) => [asc(item.sortOrder), asc(item.id)],
  });
  const ids = (type: string) =>
    links
      .filter((item) => item.componentType === type)
      .map((item) => item.componentId);
  const koshaIds = ids("kosha");
  const addonIds = ids("addon");
  const boardIds = ids("welcome_board");
  const accessoryIds = ids("accessory");
  const [koshas, addons, welcomeBoards, accessories] = await Promise.all([
    koshaIds.length
      ? db.query.koshasTable.findMany({
          where: inArray(koshasTable.id, koshaIds),
        })
      : Promise.resolve([]),
    addonIds.length
      ? db.query.koshaAddonsTable.findMany({
          where: inArray(koshaAddonsTable.id, addonIds),
        })
      : Promise.resolve([]),
    boardIds.length
      ? db.query.koshaWelcomeBoardsTable.findMany({
          where: inArray(koshaWelcomeBoardsTable.id, boardIds),
        })
      : Promise.resolve([]),
    accessoryIds.length
      ? db.query.koshaAccessoriesTable.findMany({
          where: inArray(koshaAccessoriesTable.id, accessoryIds),
        })
      : Promise.resolve([]),
  ]);
  const orderByIds = <T extends { id: number }>(
    rows: T[],
    orderedIds: number[],
  ) =>
    orderedIds
      .map((id) => rows.find((row) => row.id === id))
      .filter(Boolean) as T[];
  const orderedKoshas = orderByIds(koshas, koshaIds);
  const defaultLink = links.find(
    (item) => item.componentType === "kosha" && item.isDefault,
  );
  return {
    koshas: orderedKoshas,
    addons: orderByIds(addons, addonIds),
    welcomeBoards: orderByIds(welcomeBoards, boardIds),
    accessories: orderByIds(accessories, accessoryIds),
    defaultKosha:
      orderedKoshas.find((item) => item.id === defaultLink?.componentId) ??
      orderedKoshas[0] ??
      null,
  };
}

async function formatKoshaPackageFromParts(
  row: any,
  parts: Awaited<ReturnType<typeof loadKoshaPackageParts>>,
  includeInactiveParts = false,
) {
  const koshas = await Promise.all(
    parts.koshas
      .filter((item) => includeInactiveParts || item.isActive)
      .map((item) => formatKosha(item, false)),
  );
  const addons = parts.addons
    .filter((item) => includeInactiveParts || item.isActive)
    .map((item) => formatKoshaOptionProduct(item, "addon"));
  const welcomeBoards = parts.welcomeBoards
    .filter((item) => includeInactiveParts || item.isActive)
    .map((item) => formatKoshaOptionProduct(item, "welcome_board"));
  const accessories = parts.accessories
    .filter((item) => includeInactiveParts || item.isActive)
    .map((item) => formatKoshaOptionProduct(item, "accessory"));
  const defaultKosha =
    koshas.find((item) => item.id === parts.defaultKosha?.id) ??
    koshas[0] ??
    null;
  const componentsTotal = [
    defaultKosha,
    ...addons,
    ...welcomeBoards,
    ...accessories,
  ].reduce((sum, item) => sum + Number(item?.price ?? 0), 0);
  const configuredPrice = Number.parseFloat(String(row.price ?? "0")) || 0;
  const effectivePrice =
    configuredPrice > 0 ? configuredPrice : componentsTotal;
  const featureList = normalizeKoshaAccessories(row.features);
  const generatedFeatures = [
    defaultKosha?.name,
    ...addons.map((item) => item.name),
    ...welcomeBoards.map((item) => item.name),
    ...accessories.map((item) => item.name),
  ].filter(Boolean) as string[];
  return {
    id: row.id,
    name: row.name,
    slug: row.slug,
    description: row.description ?? "",
    price: effectivePrice,
    configuredPrice,
    oldPrice: row.oldPrice ? Number.parseFloat(String(row.oldPrice)) : null,
    mainImage:
      publicMediaValue("kosha-package", row, row.mainImage) ||
      defaultKosha?.mainImage ||
      null,
    features: featureList.length ? featureList : generatedFeatures,
    badgeText: row.badgeText ?? null,
    isFeatured: row.isFeatured ?? false,
    isActive: row.isActive ?? true,
    sortOrder: row.sortOrder ?? 0,
    defaultKosha,
    koshas,
    addons,
    welcomeBoards,
    accessories,
    componentsTotal,
    createdAt: row.createdAt?.toISOString?.() ?? String(row.createdAt ?? ""),
    updatedAt: row.updatedAt?.toISOString?.() ?? String(row.updatedAt ?? ""),
  };
}

async function formatKoshaPackage(row: any, includeInactiveParts = false) {
  return formatKoshaPackageFromParts(
    row,
    await loadKoshaPackageParts(row.id),
    includeInactiveParts,
  );
}

async function formatKoshaPackages(rows: any[], includeInactiveParts = false) {
  if (!rows.length) return [];
  const packageIds = rows.map((row) => row.id);
  const links = await db.query.koshaPackageComponentsTable.findMany({
    where: inArray(koshaPackageComponentsTable.packageId, packageIds),
    orderBy: (item, { asc }) => [asc(item.sortOrder), asc(item.id)],
  });
  const componentIds = (type: string) =>
    Array.from(
      new Set(
        links
          .filter((item) => item.componentType === type)
          .map((item) => item.componentId),
      ),
    );
  const koshaIds = componentIds("kosha");
  const addonIds = componentIds("addon");
  const boardIds = componentIds("welcome_board");
  const accessoryIds = componentIds("accessory");
  const [koshas, addons, welcomeBoards, accessories] = await Promise.all([
    koshaIds.length
      ? db.query.koshasTable.findMany({
          where: inArray(koshasTable.id, koshaIds),
        })
      : Promise.resolve([]),
    addonIds.length
      ? db.query.koshaAddonsTable.findMany({
          where: inArray(koshaAddonsTable.id, addonIds),
        })
      : Promise.resolve([]),
    boardIds.length
      ? db.query.koshaWelcomeBoardsTable.findMany({
          where: inArray(koshaWelcomeBoardsTable.id, boardIds),
        })
      : Promise.resolve([]),
    accessoryIds.length
      ? db.query.koshaAccessoriesTable.findMany({
          where: inArray(koshaAccessoriesTable.id, accessoryIds),
        })
      : Promise.resolve([]),
  ]);
  const partsFor = (packageId: number) => {
    const packageLinks = links.filter((item) => item.packageId === packageId);
    const ids = (type: string) =>
      packageLinks
        .filter((item) => item.componentType === type)
        .map((item) => item.componentId);
    const orderedRows = <T extends { id: number }>(
      source: T[],
      orderedIds: number[],
    ) =>
      orderedIds
        .map((id) => source.find((row) => row.id === id))
        .filter(Boolean) as T[];
    const orderedKoshas = orderedRows(koshas, ids("kosha"));
    const defaultLink = packageLinks.find(
      (item) => item.componentType === "kosha" && item.isDefault,
    );
    return {
      koshas: orderedKoshas,
      addons: orderedRows(addons, ids("addon")),
      welcomeBoards: orderedRows(welcomeBoards, ids("welcome_board")),
      accessories: orderedRows(accessories, ids("accessory")),
      defaultKosha:
        orderedKoshas.find((item) => item.id === defaultLink?.componentId) ??
        orderedKoshas[0] ??
        null,
    };
  };
  return Promise.all(
    rows.map((row) =>
      formatKoshaPackageFromParts(row, partsFor(row.id), includeInactiveParts),
    ),
  );
}

const KOSHA_PACKAGES_CACHE_TAG = "kosha-packages";
const getCachedPublicKoshaPackages = unstable_cache(
  async () => {
    await ensureKoshaTables();
    const rows = await db.query.koshaPackagesTable.findMany({
      where: eq(koshaPackagesTable.isActive, true),
      orderBy: (item, { asc }) => [asc(item.sortOrder), asc(item.id)],
    });
    return (await formatKoshaPackages(rows, false)).filter(
      (item) => item.defaultKosha,
    );
  },
  ["public-kosha-packages-v1"],
  { revalidate: 120, tags: [KOSHA_PACKAGES_CACHE_TAG] },
);

