async function replaceKoshaPackageParts(packageId: number, data: any) {
  const koshaIds = normalizeIdList(data.koshaIds);
  const defaultKoshaId = Number(data.defaultKoshaId) || koshaIds[0] || null;
  if (defaultKoshaId && !koshaIds.includes(defaultKoshaId))
    koshaIds.unshift(defaultKoshaId);
  const addonIds = normalizeIdList(data.addonIds);
  const welcomeBoardIds = normalizeIdList(data.welcomeBoardIds).slice(0, 1);
  const accessoryIds = normalizeIdList(data.accessoryIds);
  const checks = await Promise.all([
    koshaIds.length
      ? db.query.koshasTable.findMany({
          where: inArray(koshasTable.id, koshaIds),
        })
      : Promise.resolve([]),
    addonIds.length
      ? db.query.koshaAddonsTable.findMany({
          where: inArray(koshaAddonsTable.id, addonIds),
        })
      : Promise.resolve([]),
    welcomeBoardIds.length
      ? db.query.koshaWelcomeBoardsTable.findMany({
          where: inArray(koshaWelcomeBoardsTable.id, welcomeBoardIds),
        })
      : Promise.resolve([]),
    accessoryIds.length
      ? db.query.koshaAccessoriesTable.findMany({
          where: inArray(koshaAccessoriesTable.id, accessoryIds),
        })
      : Promise.resolve([]),
  ]);
  if (checks[0].length !== koshaIds.length)
    throw new Error("إحدى الكوشات المختارة غير موجودة");
  if (checks[1].length !== addonIds.length)
    throw new Error("إحدى الخدمات الإضافية غير موجودة");
  if (checks[2].length !== welcomeBoardIds.length)
    throw new Error("بورد الترحيب المختار غير موجود");
  if (checks[3].length !== accessoryIds.length)
    throw new Error("أحد الاكسسوارات المختارة غير موجود");
  const rows = [
    ...koshaIds.map((componentId, index) => ({
      packageId,
      componentType: "kosha",
      componentId,
      isDefault: componentId === defaultKoshaId,
      sortOrder: index,
    })),
    ...addonIds.map((componentId, index) => ({
      packageId,
      componentType: "addon",
      componentId,
      isDefault: false,
      sortOrder: 100 + index,
    })),
    ...welcomeBoardIds.map((componentId, index) => ({
      packageId,
      componentType: "welcome_board",
      componentId,
      isDefault: false,
      sortOrder: 200 + index,
    })),
    ...accessoryIds.map((componentId, index) => ({
      packageId,
      componentType: "accessory",
      componentId,
      isDefault: false,
      sortOrder: 300 + index,
    })),
  ];
  await db.transaction(async (tx) => {
    await tx
      .delete(koshaPackageComponentsTable)
      .where(eq(koshaPackageComponentsTable.packageId, packageId));
    if (rows.length) await tx.insert(koshaPackageComponentsTable).values(rows);
  });
}

async function replaceKoshaImages(koshaId: number, galleryImages: unknown) {
  if (!Array.isArray(galleryImages)) return;
  const rows: Array<{
    koshaId: number;
    imageUrl: string;
    imageMetadata: Record<string, unknown>;
    sortOrder: number;
  }> = [];
  for (let index = 0; index < galleryImages.length; index += 1) {
    const item = galleryImages[index] as any;
    const value = await persistMediaValue(
      item?.imageUrl ?? item?.url ?? "",
      "koshas/gallery",
    );
    if (!value) continue;
    rows.push({
      koshaId,
      imageUrl: value,
      imageMetadata:
        item?.imageMetadata && typeof item.imageMetadata === "object"
          ? item.imageMetadata
          : {},
      sortOrder: Number.isFinite(Number(item?.sortOrder))
        ? Number(item.sortOrder)
        : index,
    });
  }
  await db
    .delete(koshaImagesTable)
    .where(eq(koshaImagesTable.koshaId, koshaId));
  if (rows.length > 0) await db.insert(koshaImagesTable).values(rows);
}

