function productSharedStockId(row: any): number | null {
  return numberId(row?.sharedStockProductId ?? row?.shared_stock_product_id);
}

function productStockAmount(row: any): number {
  return Number(row?.effectiveStock ?? row?.stock ?? 0);
}

type StockMovementMeta = {
  reason: string;
  relatedType?: string | null;
  relatedId?: number | null;
  createdBy?: number | null;
  createdByName?: string | null;
};

const NON_STOCK_CONSUMING_STATUSES = new Set([
  "cancelled",
  "canceled",
  "refunded",
  "returned",
  "deleted",
]);

function consumesStockStatus(status: unknown): boolean {
  const value = String(status ?? "")
    .trim()
    .toLowerCase();
  return value ? !NON_STOCK_CONSUMING_STATUSES.has(value) : true;
}

function hasAppliedStock(row: any): boolean {
  return Number(row?.stockApplied ?? row?.stock_applied ?? 1) === 1;
}

async function hydrateSharedStockProducts(products: any[]): Promise<any[]> {
  const directSharedIds = [
    ...new Set(
      products
        .map((product) => productSharedStockId(product))
        .filter((id): id is number => !!id),
    ),
  ];
  if (directSharedIds.length === 0) {
    const productIds = products
      .map((product) => Number(product?.id))
      .filter((id) => Number.isFinite(id) && id > 0);
    const linkedRows = productIds.length
      ? ((await db.query.productsTable.findMany({
          where: inArray(productsTable.sharedStockProductId, productIds),
        })) as any[])
      : [];
    return products.map((product) => ({
      ...product,
      ownStock: Number(product?.stock ?? 0),
      effectiveStock: Number(product?.stock ?? 0),
      effectiveMinStock: Number(product?.minStock ?? product?.min_stock ?? 0),
      sharedStockLinkedProducts: linkedRows
        .filter(
          (row) =>
            productSharedStockId(row) === product.id && row.id !== product.id,
        )
        .map((row) => ({
          id: row.id,
          name: row.nameAr ?? row.name ?? `#${row.id}`,
        })),
    }));
  }
  const stockProducts = (await db.query.productsTable.findMany({
    where: inArray(productsTable.id, directSharedIds),
  })) as any[];
  const stockMap = new Map(
    stockProducts.map((product) => [product.id, product]),
  );
  const rootMap = new Map<number, any>();
  await Promise.all(
    stockProducts.map(async (product) => {
      const resolved = await getStockOwnerProduct(product.id);
      rootMap.set(product.id, resolved?.stockProduct ?? product);
    }),
  );
  const stockSourceIds = [
    ...new Set(
      products
        .map((product) => {
          const stockProductId = productSharedStockId(product);
          return stockProductId
            ? (rootMap.get(stockProductId)?.id ?? stockProductId)
            : product.id;
        })
        .filter((id): id is number => !!id),
    ),
  ];
  const linkedRows = stockSourceIds.length
    ? ((await db.query.productsTable.findMany({
        where: inArray(productsTable.sharedStockProductId, stockSourceIds),
      })) as any[])
    : [];
  return products.map((product) => {
    const stockProductId = productSharedStockId(product);
    const stockProduct = stockProductId
      ? (rootMap.get(stockProductId) ?? stockMap.get(stockProductId))
      : null;
    const sourceId = stockProduct?.id ?? product.id;
    const linkedProducts = linkedRows
      .filter(
        (row) =>
          productSharedStockId(row) === sourceId && row.id !== product.id,
      )
      .map((row) => ({
        id: row.id,
        name: row.nameAr ?? row.name ?? `#${row.id}`,
      }));
    if (!stockProduct) {
      return {
        ...product,
        ownStock: Number(product?.stock ?? 0),
        effectiveStock: Number(product?.stock ?? 0),
        effectiveMinStock: Number(product?.minStock ?? product?.min_stock ?? 0),
        sharedStockLinkedProducts: linkedProducts,
      };
    }
    return {
      ...product,
      ownStock: Number(product?.stock ?? 0),
      effectiveStock: Number(stockProduct.stock ?? 0),
      effectiveMinStock: Number(
        stockProduct.minStock ?? stockProduct.min_stock ?? 0,
      ),
      sharedStockProductId: stockProduct.id,
      sharedStockProductName:
        stockProduct.nameAr ?? stockProduct.name ?? `#${stockProduct.id}`,
      sharedStockLinkedProducts: linkedProducts,
    };
  });
}

async function hydrateSharedStockProduct(
  product: any | null | undefined,
): Promise<any | null> {
  if (!product) return null;
  const [hydrated] = await hydrateSharedStockProducts([product]);
  return hydrated ?? product;
}

async function resolveSharedStockProductId(
  value: unknown,
  selfId?: number | null,
): Promise<{ id: number | null; message?: string }> {
  const requestedId = numberId(value);
  if (!requestedId) return { id: null };
  if (selfId && requestedId === selfId)
    return { id: null, message: "لا يمكن ربط المنتج بمخزونه نفسه" };
  const target = (await db.query.productsTable.findFirst({
    where: eq(productsTable.id, requestedId),
  })) as any;
  if (!target)
    return { id: null, message: "المنتج المرتبط بالمخزون غير موجود" };
  let root = target;
  const visited = new Set<number>(selfId ? [selfId] : []);
  for (let depth = 0; depth < 20; depth += 1) {
    const nextId = productSharedStockId(root);
    if (!nextId) return { id: root.id };
    if (selfId && nextId === selfId)
      return { id: null, message: "لا يمكن إنشاء ربط دائري للمخزون" };
    if (visited.has(nextId))
      return { id: null, message: "لا يمكن إنشاء ربط دائري للمخزون" };
    visited.add(nextId);
    const next = (await db.query.productsTable.findFirst({
      where: eq(productsTable.id, nextId),
    })) as any;
    if (!next) return { id: root.id };
    root = next;
  }
  return { id: null, message: "لا يمكن إنشاء ربط مخزون بهذا العمق" };
}

async function getStockOwnerProduct(
  productId: number,
): Promise<{ product: any; stockProduct: any } | null> {
  const product = (await db.query.productsTable.findFirst({
    where: eq(productsTable.id, productId),
  })) as any;
  if (!product) return null;
  let stockProduct = product;
  const visited = new Set<number>([product.id]);
  for (let depth = 0; depth < 20; depth += 1) {
    const stockProductId = productSharedStockId(stockProduct);
    if (!stockProductId || visited.has(stockProductId)) break;
    visited.add(stockProductId);
    const next = (await db.query.productsTable.findFirst({
      where: eq(productsTable.id, stockProductId),
    })) as any;
    if (!next) break;
    stockProduct = next;
  }
  return { product, stockProduct };
}

async function stockOwnerIdsForProductIds(
  productIds: number[],
): Promise<number[]> {
  const ids = [
    ...new Set(productIds.filter((id) => Number.isFinite(id) && id > 0)),
  ];
  if (ids.length === 0) return [];
  const rows = (await db.query.productsTable.findMany({
    where: inArray(productsTable.id, ids),
  })) as any[];
  const owners = await Promise.all(
    rows.map(
      async (row) =>
        (await getStockOwnerProduct(row.id))?.stockProduct?.id ?? row.id,
    ),
  );
  return [...new Set(owners.filter((id): id is number => !!id))];
}

async function recordStockMovement(
  resolved: { product: any; stockProduct: any },
  delta: number,
  meta?: StockMovementMeta,
): Promise<void> {
  if (!meta?.reason) return;
  try {
    await ensureStockTrackingTables();
    await db.insert(stockMovementsTable).values({
      productId: resolved.product?.id ?? null,
      stockSourceProductId: resolved.stockProduct?.id ?? null,
      quantityChange: String(delta),
      reason: meta.reason,
      relatedType: meta.relatedType ?? null,
      relatedId: meta.relatedId ?? null,
      createdBy: meta.createdBy ?? null,
      createdByName: meta.createdByName ?? "",
    } as any);
    const kind = stockMovementKind(meta.reason);
    const usageProductId = Number(
      resolved.stockProduct?.id ?? resolved.product?.id ?? 0,
    );
    if (
      usageProductId &&
      ["out", "damage", "replacement"].includes(kind.type)
    ) {
      const existingProfile = await db.query.assetProfilesTable.findFirst({
        where: eq(assetProfilesTable.productId, usageProductId),
      });
      if (existingProfile) {
        const nextUsage = Math.max(
          0,
          Number(existingProfile.usageCount ?? 0) +
            Math.max(1, Math.abs(Math.floor(Number(delta) || 1))),
        );
        const purchasePrice = Number(
          existingProfile.purchasePrice ??
            resolved.stockProduct?.costPrice ??
            0,
        );
        const expectedLifeUses =
          Number(existingProfile.expectedLifeUses ?? 50) || 50;
        const currentValue = Math.max(
          0,
          purchasePrice -
            (purchasePrice * Math.min(nextUsage, expectedLifeUses)) /
              expectedLifeUses,
        );
        await db
          .update(assetProfilesTable)
          .set({
            usageCount: nextUsage,
            currentValue: String(currentValue),
            updatedAt: new Date(),
          })
          .where(eq(assetProfilesTable.id, existingProfile.id));
      } else if (Number(resolved.stockProduct?.costPrice ?? 0) > 0) {
        const cost = Number(resolved.stockProduct.costPrice ?? 0);
        await db
          .insert(assetProfilesTable)
          .values({
            productId: usageProductId,
            purchasePrice: String(cost),
            expectedLifeUses: 50,
            usageCount: Math.max(1, Math.abs(Math.floor(Number(delta) || 1))),
            maintenanceEveryUses: 50,
            currentValue: String(cost),
            status: "active",
            notes: "تم إنشاء ملف الأصل تلقائياً من حركة المخزون",
          })
          .onConflictDoNothing();
      }
      // Integration — reflect inventory/rental movements on the asset's passport timeline.
      const isRental = /rental/i.test(String(meta.reason));
      void addEntityTimeline({
        entityType: "asset",
        entityId: usageProductId,
        type:
          kind.type === "damage"
            ? "damage"
            : kind.type === "replacement"
              ? "replacement"
              : isRental
                ? "rental"
                : "usage",
        title:
          kind.type === "damage"
            ? "⚠️ ضرر (حركة مخزون)"
            : kind.type === "replacement"
              ? "🔁 استبدال"
              : isRental
                ? "🏷️ تأجير الأصل"
                : "📦 استخدام/خروج من المخزن",
        body: meta.reason ? String(meta.reason) : null,
        actor: {
          id: meta.createdBy ?? null,
          name: meta.createdByName || "النظام",
        },
        metadata: {
          delta,
          reason: meta.reason,
          relatedType: meta.relatedType,
          relatedId: meta.relatedId,
        },
      });
    }
  } catch (err) {
    console.warn("stock movement log failed", {
      reason: meta.reason,
      relatedType: meta.relatedType,
      relatedId: meta.relatedId,
      message: err instanceof Error ? err.message : "unknown",
    });
  }
}

async function adjustProductStock(
  productId: number,
  delta: number,
  meta?: StockMovementMeta,
): Promise<number | null> {
  const resolved = await getStockOwnerProduct(productId);
  if (!resolved) return null;
  await db.execute(sql`
    UPDATE products
    SET stock = GREATEST(0, stock + ${Number(delta)}), updated_at = now()
    WHERE id = ${resolved.stockProduct.id}
  `);
  await recordStockMovement(resolved, delta, meta);
  return resolved.stockProduct.id;
}

async function setProductStock(
  productId: number,
  stock: number,
  meta?: StockMovementMeta,
): Promise<number | null> {
  const resolved = await getStockOwnerProduct(productId);
  if (!resolved) return null;
  const previousStock = Number(resolved.stockProduct?.stock ?? 0);
  const nextStock = Math.max(0, Math.floor(Number(stock) || 0));
  await db
    .update(productsTable)
    .set({ stock: nextStock, updatedAt: new Date() })
    .where(eq(productsTable.id, resolved.stockProduct.id));
  const delta = nextStock - previousStock;
  if (delta !== 0) await recordStockMovement(resolved, delta, meta);
  return resolved.stockProduct.id;
}

async function adjustWarehouseStock(
  productId: number,
  warehouseId: number | null | undefined,
  delta: number,
) {
  if (!warehouseId || !productId || !Number.isFinite(delta) || delta === 0)
    return null;
  await ensureAdminExtensionsTables();
  const resolved = await getStockOwnerProduct(productId);
  const stockProductId = resolved?.stockProduct?.id ?? productId;
  const [existing] = await db
    .select()
    .from(warehouseStockTable)
    .where(
      and(
        eq(warehouseStockTable.productId, stockProductId),
        eq(warehouseStockTable.warehouseId, warehouseId),
      ),
    )
    .limit(1);
  if (existing) {
    const next = Math.max(0, Number(existing.quantity ?? 0) + delta);
    const [row] = await db
      .update(warehouseStockTable)
      .set({ quantity: String(next), updatedAt: new Date() })
      .where(eq(warehouseStockTable.id, existing.id))
      .returning();
    return row;
  }
  const [row] = await db
    .insert(warehouseStockTable)
    .values({
      warehouseId,
      productId: stockProductId,
      quantity: String(Math.max(0, delta)),
    })
    .returning();
  return row;
}

async function executeWarehouseTransfer(
  row: typeof warehouseTransfersTable.$inferSelect,
  actor: ErpActor | null,
) {
  if (row.status === "approved") {
    const productId = Number(row.productId ?? 0);
    const quantity = Number(row.quantity ?? 0);
    if (!productId || quantity <= 0)
      return { executed: false, reason: "missing_product_or_quantity" };
    const marker = await db.query.stockMovementsTable.findFirst({
      where: and(
        eq(stockMovementsTable.relatedType, "warehouse_transfer"),
        eq(stockMovementsTable.relatedId, row.id),
        eq(stockMovementsTable.reason, "warehouse_transfer_executed"),
      ),
    });
    if (marker) return { executed: false, reason: "already_executed" };
    const resolved = await getStockOwnerProduct(productId);
    if (!resolved) return { executed: false, reason: "product_not_found" };
    await adjustWarehouseStock(productId, row.fromWarehouseId, -quantity);
    await adjustWarehouseStock(productId, row.toWarehouseId, quantity);
    await recordStockMovement(resolved, 0, {
      reason: "warehouse_transfer_executed",
      relatedType: "warehouse_transfer",
      relatedId: row.id,
      createdBy: actor?.id ?? null,
      createdByName: actor?.name ?? "النظام",
    });
    await addEntityTimeline({
      entityType: "warehouse_transfer",
      entityId: row.id,
      type: "warehouse_transfer_executed",
      title: "تم تنفيذ التحويل المخزني",
      body: `${row.productName} × ${quantity}`,
      actor,
      metadata: {
        fromWarehouseId: row.fromWarehouseId,
        toWarehouseId: row.toWarehouseId,
        productId,
      },
    });
    return { executed: true };
  }
  return { executed: false, reason: "not_approved" };
}

function normalizeSharedStockLinkedIds(
  value: unknown,
  sourceId: number,
): number[] {
  if (!Array.isArray(value)) return [];
  return [
    ...new Set(
      value
        .map((item) => numberId(item))
        .filter((id): id is number => !!id && id !== sourceId),
    ),
  ];
}

async function validateSharedStockLinkedProducts(
  sourceId: number,
  linkedIds: number[],
): Promise<string | null> {
  const source = (await db.query.productsTable.findFirst({
    where: eq(productsTable.id, sourceId),
  })) as any;
  if (!source) return "المنتج الرئيسي غير موجود";
  for (const linkedId of linkedIds) {
    if (linkedId === sourceId) return "لا يمكن ربط المنتج بمخزونه نفسه";
    const child = (await db.query.productsTable.findFirst({
      where: eq(productsTable.id, linkedId),
    })) as any;
    if (!child) return "أحد المنتجات المرتبطة غير موجود";
    const circularCheck = await resolveSharedStockProductId(sourceId, linkedId);
    if (circularCheck.message) return circularCheck.message;
  }
  return null;
}

async function syncSharedStockLinkedProducts(
  sourceId: number,
  linkedIds: number[],
  actorInfo?: { id: number | null; name: string } | null,
): Promise<void> {
  void actorInfo;
  const desiredIds = normalizeSharedStockLinkedIds(linkedIds, sourceId);
  const currentRows = (await db.query.productsTable.findMany({
    where: eq(productsTable.sharedStockProductId, sourceId),
  })) as any[];
  const currentIds = currentRows
    .map((row) => Number(row.id))
    .filter((id) => Number.isFinite(id) && id > 0);
  const desiredSet = new Set(desiredIds);
  const removeIds = currentIds.filter((id) => !desiredSet.has(id));
  if (removeIds.length > 0) {
    await db
      .update(productsTable)
      .set({ sharedStockProductId: null, updatedAt: new Date() } as any)
      .where(inArray(productsTable.id, removeIds));
  }
  for (const linkedId of desiredIds) {
    await db.execute(sql`
      update products
      set shared_stock_product_id = ${sourceId}, updated_at = now()
      where shared_stock_product_id = ${linkedId} and id <> ${sourceId}
    `);
    await db
      .update(productsTable)
      .set({
        sharedStockProductId: sourceId,
        stock: 0,
        minStock: 0,
        updatedAt: new Date(),
      } as any)
      .where(eq(productsTable.id, linkedId));
  }
}

// Sale stock adjustment — MAKE-TO-STOCK model: a sale deducts the FINISHED product's own
// stock (the goods produced via Production Orders). Recipe COMPONENTS are consumed only at
// production time, never at sale time. So this simply adjusts the sold product's stock.
async function adjustSaleStock(
  productId: number,
  delta: number,
  meta: StockMovementMeta,
): Promise<void> {
  if (!productId || !delta) return;
  await adjustProductStock(productId, delta, meta);
}

async function applyOrderItemsStock(
  orderId: number,
  direction: 1 | -1,
  reason: string,
  actorInfo?: { id: number | null; name: string } | null,
): Promise<void> {
  const items = await db
    .select()
    .from(orderItemsTable)
    .where(eq(orderItemsTable.orderId, orderId));
  for (const item of items) {
    const productId = Number(item.productId ?? 0);
    const quantity = Number(item.quantity ?? 0);
    if (productId > 0 && quantity > 0) {
      await adjustSaleStock(productId, direction * quantity, {
        reason,
        relatedType: "order",
        relatedId: orderId,
        createdBy: actorInfo?.id ?? null,
        createdByName: actorInfo?.name ?? "",
      });
    }
  }
}

async function syncOrderStockState(
  order: any,
  actorInfo?: { id: number | null; name: string } | null,
): Promise<void> {
  if (!order?.id) return;
  await ensureStockTrackingTables();
  const shouldConsume = consumesStockStatus(order.status);
  const stockApplied = hasAppliedStock(order);
  if (stockApplied && !shouldConsume) {
    await applyOrderItemsStock(order.id, 1, "order_stock_restored", actorInfo);
    await db
      .update(ordersTable)
      .set({
        stockApplied: 0,
        stockRestoredAt: new Date(),
        updatedAt: new Date(),
      } as any)
      .where(eq(ordersTable.id, order.id));
    return;
  }
  if (!stockApplied && shouldConsume) {
    await applyOrderItemsStock(
      order.id,
      -1,
      "order_stock_deducted_again",
      actorInfo,
    );
    await db
      .update(ordersTable)
      .set({
        stockApplied: 1,
        stockRestoredAt: null,
        updatedAt: new Date(),
      } as any)
      .where(eq(ordersTable.id, order.id));
  }
}

async function restoreOrderStockBeforeDelete(
  order: any,
  actorInfo?: { id: number | null; name: string } | null,
): Promise<void> {
  if (!order?.id || !hasAppliedStock(order)) return;
  await applyOrderItemsStock(
    order.id,
    1,
    "order_stock_restored_before_delete",
    actorInfo,
  );
  await db
    .update(ordersTable)
    .set({
      stockApplied: 0,
      stockRestoredAt: new Date(),
      updatedAt: new Date(),
    } as any)
    .where(eq(ordersTable.id, order.id));
}

async function applySalesInvoiceItemsStock(
  invoiceId: number,
  direction: 1 | -1,
  reason: string,
  actorInfo?: { id: number | null; name: string } | null,
): Promise<void> {
  const items = await db
    .select()
    .from(salesInvoiceItemsTable)
    .where(eq(salesInvoiceItemsTable.invoiceId, invoiceId));
  for (const item of items) {
    const productId = Number(item.productId ?? 0);
    const quantity = Number.parseFloat(String(item.quantity ?? "0")) || 0;
    if (productId > 0 && quantity > 0) {
      await adjustSaleStock(productId, direction * quantity, {
        reason,
        relatedType: "sales_invoice",
        relatedId: invoiceId,
        createdBy: actorInfo?.id ?? null,
        createdByName: actorInfo?.name ?? "",
      });
    }
  }
}

