function formatCrew(c: any) {
  return {
    id: c.id,
    name: c.name,
    isActive: c.isActive,
    status: c.status ?? (c.isActive ? "available" : "inactive"),
    internalNotes: c.internalNotes ?? "",
    createdAt: c.createdAt?.toISOString?.() ?? null,
    updatedAt: c.updatedAt?.toISOString?.() ?? null,
  };
}

function formatAddress(row: any) {
  return {
    id: row.id,
    type: row.type ?? "home",
    fullName: row.fullName ?? row.full_name ?? "",
    phone: row.phone ?? "",
    governorate: row.governorate ?? "",
    city: row.city ?? "",
    address: row.address ?? "",
    landmark: row.landmark ?? "",
    notes: row.notes ?? "",
    isDefault: Boolean(row.isDefault ?? row.is_default),
    createdAt:
      row.createdAt?.toISOString?.() ?? row.created_at?.toISOString?.() ?? null,
    updatedAt:
      row.updatedAt?.toISOString?.() ?? row.updated_at?.toISOString?.() ?? null,
  };
}

function normalizeDetailsInput(value: unknown): Record<string, any> {
  if (!value || typeof value !== "object" || Array.isArray(value)) return {};
  return value as Record<string, any>;
}

