// ---- REPX live-data binding helpers ----
function getByPath(obj: any, path: string): any {
  if (!path) return undefined;
  return path
    .split(".")
    .reduce((acc, key) => (acc == null ? undefined : acc[key]), obj);
}
function reportDateStr(v: any): string {
  const s = iso(v);
  return s ? s.slice(0, 10) : "";
}

async function listReportRecords(
  type: string,
  q: string,
): Promise<Array<{ id: number; label: string }>> {
  const like = `%${q}%`;
  try {
    if (type === "invoice") {
      const rows = await db.query.salesInvoicesTable.findMany({
        where: q
          ? or(
              ilike(salesInvoicesTable.invoiceNo, like),
              ilike(salesInvoicesTable.customerName, like),
            )
          : undefined,
        orderBy: [desc(salesInvoicesTable.id)],
        limit: 20,
      });
      return rows.map((r: any) => ({
        id: r.id,
        label: `${r.invoiceNo ?? r.id} · ${r.customerName ?? ""}`,
      }));
    }
    if (type === "product") {
      const rows = await db.query.productsTable.findMany({
        where: q
          ? or(
              ilike(productsTable.nameAr, like),
              ilike(productsTable.name, like),
            )
          : undefined,
        orderBy: [desc(productsTable.id)],
        limit: 20,
      });
      return rows.map((r: any) => ({
        id: r.id,
        label: r.nameAr || r.name || `#${r.id}`,
      }));
    }
    if (type === "booking") {
      const rows = await db.query.koshaBookingsTable.findMany({
        where: q
          ? or(
              ilike(koshaBookingsTable.customerName, like),
              ilike(koshaBookingsTable.phone, like),
            )
          : undefined,
        orderBy: [desc(koshaBookingsTable.id)],
        limit: 20,
      });
      return rows.map((r: any) => ({
        id: r.id,
        label: `${r.customerName ?? ""} · ${r.eventDate ?? ""}`,
      }));
    }
    if (type === "order") {
      const rows = await db.query.ordersTable.findMany({
        where: q
          ? or(
              ilike(ordersTable.trackingCode, like),
              ilike(ordersTable.customerName, like),
            )
          : undefined,
        orderBy: [desc(ordersTable.id)],
        limit: 20,
      });
      return rows.map((r: any) => ({
        id: r.id,
        label: `${r.trackingCode ?? r.id} · ${r.customerName ?? ""}`,
      }));
    }
    if (type === "customer") {
      const rows = await db.query.customersTable.findMany({
        where: q
          ? or(
              ilike(customersTable.name, like),
              ilike(customersTable.phone, like),
            )
          : undefined,
        orderBy: [desc(customersTable.id)],
        limit: 20,
      });
      return rows.map((r: any) => ({
        id: r.id,
        label: `${r.fullName || r.name || ""} · ${r.phone ?? ""}`,
      }));
    }
  } catch {
    /* table/column mismatch → empty */
  }
  return [];
}

// Detail-band rows — resolves a record's line items into repeating rows (#detail iteration).
async function buildReportRows(
  type: string,
  recordId: number,
  mapping: Record<string, string>,
  fields: string[],
): Promise<Array<Record<string, string>>> {
  let items: any[] = [];
  try {
    if (type === "invoice")
      items = await db.query.salesInvoiceItemsTable.findMany({
        where: eq(salesInvoiceItemsTable.invoiceId, recordId),
        limit: 200,
      });
    else if (type === "order")
      items = await db.query.orderItemsTable.findMany({
        where: eq(orderItemsTable.orderId, recordId),
        limit: 200,
      });
    else return [];
  } catch {
    return [];
  }
  return items.map((it: any) => {
    const qty = Number(it.quantity ?? 1);
    const unit = Number(it.unitPrice ?? it.price ?? 0);
    const itemCtx = {
      item: {
        name: it.productNameAr || it.productName || "",
        price: formatCurrency(unit),
        qty: String(qty),
        total: formatCurrency(it.total ?? unit * qty),
        barcode: it.barcode ?? "",
      },
    };
    const row: Record<string, string> = {};
    for (const f of fields) {
      const v = getByPath(itemCtx, mapping[f] || f);
      if (v !== undefined && v !== null) row[f] = String(v);
    }
    return row;
  });
}

async function buildReportContext(
  type: string,
  recordId: number,
): Promise<(Record<string, any> & { __label?: string }) | null> {
  if (!recordId) return null;
  try {
    if (type === "invoice") {
      const inv: any = await db.query.salesInvoicesTable.findFirst({
        where: eq(salesInvoicesTable.id, recordId),
      });
      if (!inv) return null;
      return {
        invoice: {
          invoiceNo: inv.invoiceNo ?? `#${inv.id}`,
          date: reportDateStr(inv.createdAt ?? inv.date),
          total: formatCurrency(inv.totalAmount ?? inv.total ?? 0),
          paid: formatCurrency(inv.paidAmount ?? 0),
          remaining: formatCurrency(inv.remainingAmount ?? 0),
        },
        customer: {
          fullName: inv.customerName ?? "",
          phone: inv.customerPhone ?? "",
          address: inv.address ?? "",
        },
        __label: `${inv.invoiceNo ?? inv.id} · ${inv.customerName ?? ""}`,
      };
    }
    if (type === "product") {
      const p: any = await db.query.productsTable.findFirst({
        where: eq(productsTable.id, recordId),
      });
      if (!p) return null;
      return {
        product: {
          name: p.nameAr || p.name || "",
          price: formatCurrency(p.price ?? 0),
          barcode: p.barcode ?? "",
          costPrice: formatCurrency(p.costPrice ?? 0),
        },
        __label: p.nameAr || p.name || `#${p.id}`,
      };
    }
    if (type === "booking") {
      const b: any = await db.query.koshaBookingsTable.findFirst({
        where: eq(koshaBookingsTable.id, recordId),
      });
      if (!b) return null;
      return {
        booking: {
          code: b.trackingCode ?? `KB-${b.id}`,
          date: reportDateStr(b.eventDate ?? b.createdAt),
          customerName: b.customerName ?? "",
        },
        customer: {
          fullName: b.customerName ?? "",
          phone: b.phone ?? "",
          address: b.hallLocation ?? b.cityArea ?? "",
        },
        __label: `${b.customerName ?? ""} · ${b.eventDate ?? ""}`,
      };
    }
    if (type === "order") {
      const o: any = await db.query.ordersTable.findFirst({
        where: eq(ordersTable.id, recordId),
      });
      if (!o) return null;
      return {
        order: {
          code: o.trackingCode ?? `#${o.id}`,
          date: reportDateStr(o.createdAt),
        },
        customer: {
          fullName: o.customerName ?? "",
          phone: o.customerPhone ?? "",
          address: o.address ?? "",
        },
        __label: `${o.trackingCode ?? o.id} · ${o.customerName ?? ""}`,
      };
    }
    if (type === "customer") {
      const c: any = await db.query.customersTable.findFirst({
        where: eq(customersTable.id, recordId),
      });
      if (!c) return null;
      return {
        customer: {
          fullName: c.fullName || c.name || "",
          phone: c.phone ?? "",
          address: c.address ?? "",
        },
        __label: c.fullName || c.name || `#${c.id}`,
      };
    }
  } catch {
    return null;
  }
  return null;
}

