  if (section === "daily-closing") {
    const closingDate = String(
      req.nextUrl.searchParams.get("date") ??
        new Date().toISOString().slice(0, 10),
    ).slice(0, 10);
    const branchCode =
      String(req.nextUrl.searchParams.get("branch") ?? "MAIN")
        .trim()
        .slice(0, 30) || "MAIN";
    const calculateChecks = async () => {
      const start = new Date(`${closingDate}T00:00:00`);
      const end = new Date(`${closingDate}T23:59:59.999`);
      const [issued, pendingPayments, openBookings, cashReport, backup] =
        await Promise.all([
          db
            .select({ count: sql<number>`count(*)::int` })
            .from(equipmentCustodyTable)
            .where(eq(equipmentCustodyTable.status, "issued")),
          db
            .select({ count: sql<number>`count(*)::int` })
            .from(financialTransactionsTable)
            .where(
              inArray(financialTransactionsTable.approvalStatus, [
                "draft",
                "pending",
              ]),
            ),
          db.execute(
            sql`select count(*)::int as count from kosha_bookings where archived_at is null and status not in ('completed','cancelled') and event_date is not null and event_date::date <= ${closingDate}::date`,
          ),
          db.query.dailyCashReportsTable.findFirst({
            where: eq(dailyCashReportsTable.reportDate, closingDate),
          }),
          db.query.disasterRecoverySnapshotsTable.findFirst({
            where: and(
              gte(disasterRecoverySnapshotsTable.createdAt, start),
              lte(disasterRecoverySnapshotsTable.createdAt, end),
              eq(disasterRecoverySnapshotsTable.status, "created"),
            ),
          }),
        ]);
      return {
        equipmentReturned: Number(issued[0]?.count ?? 0) === 0,
        paymentsApproved: Number(pendingPayments[0]?.count ?? 0) === 0,
        bookingsClosed:
          Number((openBookings as any).rows?.[0]?.count ?? 0) === 0,
        cashClosed: cashReport?.status === "closed",
        backupCompleted: Boolean(backup),
        details: {
          equipmentOutstanding: Number(issued[0]?.count ?? 0),
          pendingPayments: Number(pendingPayments[0]?.count ?? 0),
          openBookings: Number((openBookings as any).rows?.[0]?.count ?? 0),
        },
      };
    };
    if (method === "GET") {
      const checks = await calculateChecks();
      const row = await db.query.dailyClosingChecklistsTable.findFirst({
        where: and(
          eq(dailyClosingChecklistsTable.closingDate, closingDate),
          eq(dailyClosingChecklistsTable.branchCode, branchCode),
        ),
      });
      return json({
        data: row ?? { closingDate, branchCode, status: "open", ...checks },
        checks,
      });
    }
    if (method === "POST") {
      const data = await body(req);
      const checks = await calculateChecks();
      const requestedClose = Boolean(data?.close);
      const complete =
        checks.equipmentReturned &&
        checks.paymentsApproved &&
        checks.bookingsClosed &&
        checks.cashClosed &&
        checks.backupCompleted;
      if (requestedClose && !complete)
        return json(
          {
            error: "لا يمكن إغلاق اليوم قبل إكمال جميع عناصر القائمة",
            details: checks.details,
          },
          409,
        );
      const values = {
        closingDate,
        branchCode,
        equipmentReturned: checks.equipmentReturned,
        paymentsApproved: checks.paymentsApproved,
        bookingsClosed: checks.bookingsClosed,
        cashClosed: checks.cashClosed,
        backupCompleted: checks.backupCompleted,
        notes: nullableText(data?.notes),
        status: requestedClose ? "closed" : "open",
        closedBy: requestedClose ? auth.id : null,
        closedByName: requestedClose ? auth.fullName || auth.username : "",
        closedAt: requestedClose ? new Date() : null,
        updatedAt: new Date(),
      };
      const [row] = await db
        .insert(dailyClosingChecklistsTable)
        .values(values)
        .onConflictDoUpdate({
          target: [
            dailyClosingChecklistsTable.closingDate,
            dailyClosingChecklistsTable.branchCode,
          ],
          set: values,
        })
        .returning();
      await recordEnterpriseMutation(
        req,
        auth,
        requestedClose ? "daily_closing_completed" : "daily_closing_checked",
        "daily_closing",
        row.id,
        requestedClose ? "تم إغلاق يوم العمل" : "تم تحديث قائمة إغلاق اليوم",
        { closingDate, branchCode, checks },
      );
      return json({ ...row, checks });
    }
  }

