async function ensureExpenseCategoriesSeeded() {
  await ensureExpenseManagementTables();
  for (const category of DEFAULT_EXPENSE_CATEGORIES) {
    const existing = await db.query.expenseCategoriesTable.findFirst({
      where: or(
        eq(expenseCategoriesTable.name, category.name),
        eq(expenseCategoriesTable.nameAr, category.nameAr),
      ),
    });
    if (!existing) await db.insert(expenseCategoriesTable).values(category);
  }
}

function actor(user: AdminUser): { id: number | null; name: string } {
  return { id: user.id ?? null, name: user.fullName || user.username || "" };
}

function canEditOrderFinancials(user: AdminUser): boolean {
  return (
    ["admin", "manager", "accountant"].includes(user.role) ||
    user.permissions.includes("accounting")
  );
}

function financialActor(user: AdminUser): FinancialActor {
  return { ...actor(user), role: user.role };
}

const SYSTEM_FINANCIAL_ACTOR: FinancialActor = {
  id: null,
  name: "النظام",
  role: "system",
};

function serviceDepartment(
  service:
    | { type?: string | null; name?: string | null; nameAr?: string | null }
    | null
    | undefined,
) {
  const value =
    `${service?.type ?? ""} ${service?.name ?? ""} ${service?.nameAr ?? ""}`.toLowerCase();
  if (/kosha|كوش/.test(value)) return "koshas";
  if (/photo|تصوير|album|ألبوم/.test(value)) return "photography";
  if (/audio|sound|dj|صوت/.test(value)) return "audio";
  if (/gift|هدي|توزيع/.test(value)) return "gifts";
  return "general";
}

async function syncOrderFinancialPayment(
  order: typeof ordersTable.$inferSelect,
  financeActorValue: FinancialActor,
) {
  const productAmount = Math.max(
    Number(order.total) - Number(order.deliveryFee),
    0,
  );
  const targetPaid =
    order.status === "cancelled"
      ? 0
      : Math.min(Number(order.depositAmount), productAmount);
  const isRental = isRentalStoreOrder(order);
  return syncSourcePaymentTarget(
    {
      sourceType: "order",
      sourceId: order.id,
      sourceEvent: "payment",
      targetAmount: targetPaid,
      normalDirection: "revenue",
      transactionDate: order.createdAt.toISOString().slice(0, 10),
      department: "store",
      transactionType: isRental ? "rental_order" : "store_order",
      description: `${isRental ? "دفعة حجز إيجار" : "دفعة طلب"} ${order.trackingCode}`,
      paymentMethod: order.paymentMethod === "transfer" ? "transfer" : "cash",
      customerId: order.customerId,
      customerName: order.customerName,
      customerPhone: order.customerPhone,
      dueDate: order.dueDate,
      notes: order.notes,
      attachments: order.attachments ?? [],
    },
    financeActorValue,
  );
}

async function syncServiceOrderFinancialPayment(
  order: typeof serviceOrdersTable.$inferSelect,
  financeActorValue: FinancialActor,
) {
  const service = await db.query.servicesTable.findFirst({
    where: eq(servicesTable.id, order.serviceId),
  });
  const targetPaid =
    order.status === "cancelled" ? 0 : Number(order.depositAmount);
  return syncSourcePaymentTarget(
    {
      sourceType: "service_order",
      sourceId: order.id,
      sourceEvent: "payment",
      targetAmount: targetPaid,
      normalDirection: "revenue",
      transactionDate: order.createdAt.toISOString().slice(0, 10),
      department: serviceDepartment(service),
      transactionType: "service_booking",
      description: `دفعة حجز ${order.trackingCode ?? `#${order.id}`}`,
      paymentMethod:
        (order.customFields as any)?.paymentMethod === "transfer"
          ? "transfer"
          : (order.customFields as any)?.paymentMethod === "pos" ||
              (order.customFields as any)?.paymentMethod === "card"
            ? "pos"
            : "cash",
      customerName: order.customerName,
      customerPhone: order.phone,
      dueDate: order.dueDate,
      notes: order.notes,
    },
    financeActorValue,
  );
}

async function syncKoshaFinancialPayment(
  order: typeof koshaBookingsTable.$inferSelect,
  financeActorValue: FinancialActor,
) {
  const targetPaid =
    order.status === "cancelled" ? 0 : Number(order.paidAmount);
  const paymentMethod = (order.bookingDetails as any)?.pricing?.paymentMethod;
  return syncSourcePaymentTarget(
    {
      sourceType: "kosha_booking",
      sourceId: order.id,
      sourceEvent: "payment",
      targetAmount: targetPaid,
      normalDirection: "revenue",
      transactionDate: order.createdAt.toISOString().slice(0, 10),
      department: "koshas",
      transactionType: "kosha_booking",
      description: `دفعة حجز كوشة #${order.id}`,
      paymentMethod:
        paymentMethod === "transfer"
          ? "transfer"
          : paymentMethod === "pos" || paymentMethod === "card"
            ? "pos"
            : "cash",
      customerName: order.customerName,
      customerPhone: order.phone,
      dueDate: order.dueDate,
      notes: order.notes,
    },
    financeActorValue,
  );
}

const RENTAL_ACTIVE_STATUS = "active";
const RENTAL_CLOSED_STATUSES = new Set(["returned", "cancelled"]);

function isRentalStoreOrder(order: any): boolean {
  return (
    String(order?.serviceType ?? order?.service_type ?? "").toLowerCase() ===
    "rental"
  );
}

function rentalStatusFromStoreStatus(
  status: unknown,
): "active" | "returned" | "cancelled" {
  const value = String(status ?? "")
    .trim()
    .toLowerCase();
  if (value === "returned" || value === "delivered" || value === "completed")
    return "returned";
  if (value === "cancelled" || value === "canceled") return "cancelled";
  return "active";
}

function rentalStorePaymentMethod(
  method: unknown,
  paid: number,
  total: number,
): "cod" | "transfer" | "paid" {
  if (paid >= total && total > 0) return "paid";
  return method === "transfer" ? "transfer" : "cod";
}

function rentalCustomization(input: {
  rentalOrderId: number;
  orderNo: string;
  startDate: string;
  endDate: string;
  days: number;
  pricePerDay: number;
  totalAmount: number;
  status: string;
}) {
  return JSON.stringify({ type: "rental", ...input });
}

function parseRentalCustomization(
  value: unknown,
): Record<string, unknown> | null {
  if (!value || typeof value !== "string") return null;
  try {
    const parsed = JSON.parse(value);
    return parsed && typeof parsed === "object" && parsed.type === "rental"
      ? parsed
      : null;
  } catch {
    return null;
  }
}

async function findRentalByStoreOrder(order: any) {
  if (!order || !isRentalStoreOrder(order)) return null;
  return db.query.rentalOrdersTable.findFirst({
    where: eq(rentalOrdersTable.orderNo, order.trackingCode),
  });
}

async function syncRentalRowFromStoreOrder(
  order: typeof ordersTable.$inferSelect,
) {
  if (!isRentalStoreOrder(order)) return null;
  const rental = await findRentalByStoreOrder(order);
  if (!rental) return null;
  const nextStatus = rentalStatusFromStoreStatus(order.status);
  const update: any = {
    status: nextStatus,
    paidAmount: order.depositAmount,
    remainingAmount: order.remainingAmount,
    paymentStatus: order.paymentStatus,
    updatedAt: new Date(),
    stockApplied: Number(order.stockApplied ?? 1),
    stockRestoredAt: order.stockRestoredAt ?? null,
  };
  if (nextStatus === "returned")
    update.returnedAt = rental.returnedAt ?? new Date();
  if (nextStatus === "cancelled")
    update.cancelledAt = rental.cancelledAt ?? new Date();
  const [row] = await db
    .update(rentalOrdersTable)
    .set(update)
    .where(eq(rentalOrdersTable.id, rental.id))
    .returning();
  return row;
}

const RentalOrderCreateSchema = z.object({
  productId: z.coerce.number().int().positive("المنتج مطلوب"),
  customerName: z.string().trim().max(200).optional().default(""),
  phone: z.string().trim().min(1, "رقم الهاتف مطلوب"),
  startDate: z.string().regex(/^\d{4}-\d{2}-\d{2}$/, "تاريخ البداية غير صحيح"),
  endDate: z.string().regex(/^\d{4}-\d{2}-\d{2}$/, "تاريخ النهاية غير صحيح"),
  paidAmount: z.coerce.number().min(0).optional(),
  paymentMethod: z
    .enum(["cash", "card", "transfer"])
    .optional()
    .default("cash"),
  notes: z.string().trim().max(2000).optional().default(""),
});

function rentalDays(startDate: string, endDate: string): number {
  const start = Date.parse(`${startDate}T00:00:00.000Z`);
  const end = Date.parse(`${endDate}T00:00:00.000Z`);
  if (!Number.isFinite(start) || !Number.isFinite(end) || end < start) return 0;
  return Math.max(1, Math.floor((end - start) / 86_400_000) + 1);
}

function rentalOrderNo(phone: string): string {
  const tail = phoneLast4(phone) || "0000";
  return `RNT-${tail}-${Date.now().toString(36).toUpperCase()}`;
}

async function findRentalOverlap(
  stockSourceProductId: number,
  startDate: string,
  endDate: string,
  excludeId?: number | null,
) {
  return db.query.rentalOrdersTable.findFirst({
    where: and(
      eq(rentalOrdersTable.stockSourceProductId, stockSourceProductId),
      eq(rentalOrdersTable.status, RENTAL_ACTIVE_STATUS),
      lte(rentalOrdersTable.startDate, endDate),
      gte(rentalOrdersTable.endDate, startDate),
      excludeId ? sql`${rentalOrdersTable.id} <> ${excludeId}` : undefined,
    ),
  });
}

async function syncRentalFinancialPayment(
  order: typeof rentalOrdersTable.$inferSelect,
  financeActorValue: FinancialActor,
) {
  const targetPaid =
    order.status === "cancelled" ? 0 : Number(order.paidAmount);
  return syncSourcePaymentTarget(
    {
      sourceType: "rental_order",
      sourceId: order.id,
      sourceEvent: "payment",
      targetAmount: targetPaid,
      normalDirection: "revenue",
      transactionDate: order.createdAt.toISOString().slice(0, 10),
      department: "store",
      transactionType: "rental_order",
      description: `دفعة حجز إيجار ${order.orderNo}`,
      paymentMethod:
        order.paymentMethod === "transfer"
          ? "transfer"
          : order.paymentMethod === "card"
            ? "card"
            : "cash",
      customerId: order.customerId,
      customerName: order.customerName,
      customerPhone: order.phone,
      notes: order.notes,
    },
    financeActorValue,
  );
}

const paymentCollectionSchema = z.object({
  sourceType: z.enum([
    "order",
    "service_order",
    "sales_invoice",
    "kosha_booking",
  ]),
  sourceId: z.coerce.number().int().positive(),
  amount: z.coerce.number().positive("المبلغ يجب أن يكون أكبر من صفر"),
  paymentMethod: z
    .enum(["cash", "transfer", "card", "pos"])
    .default("cash"),
  receiptNo: z.string().trim().max(100).optional().default(""),
  notes: z.string().trim().max(2000).optional().default(""),
  receiptImage: z.string().trim().optional().default(""),
});

type CollectionSourceType = z.infer<
  typeof paymentCollectionSchema
>["sourceType"];

async function collectionSourceSummary(
  sourceType: CollectionSourceType,
  sourceId: number,
) {
  let source: any = null;
  let reference = `#${sourceId}`;
  let customerId: number | null = null;
  let customerName = "";
  let customerPhone: string | null = null;
  let total = 0;
  let discount = 0;
  let paid = 0;
  let remaining = 0;
  let paymentStatus = "unpaid";
  let paymentMethod = "cash";
  let date = new Date().toISOString().slice(0, 10);

  if (sourceType === "order") {
    source = await db.query.ordersTable.findFirst({
      where: eq(ordersTable.id, sourceId),
    });
    if (source) {
      reference = source.trackingCode;
      customerId = source.customerId ?? null;
      customerName = source.customerName;
      customerPhone = source.customerPhone;
      total = money(source.total);
      discount = money(source.couponDiscountAmount) + money(source.loyaltyDiscountAmount);
      paid = money(source.depositAmount);
      remaining = money(source.remainingAmount);
      paymentStatus = source.paymentStatus;
      paymentMethod = source.paymentMethod;
      date = source.createdAt.toISOString().slice(0, 10);
    }
  } else if (sourceType === "service_order") {
    source = await db.query.serviceOrdersTable.findFirst({
      where: eq(serviceOrdersTable.id, sourceId),
    });
    if (source) {
      reference = source.trackingCode ?? `SRV-${source.id}`;
      customerName = source.customerName;
      customerPhone = source.phone;
      total = money(source.totalAmount);
      discount = money((source.customFields as any)?.discountAmount);
      paid = money(source.depositAmount);
      remaining = money(source.remainingAmount);
      paymentStatus = source.paymentStatus;
      paymentMethod = String((source.customFields as any)?.paymentMethod ?? "cash");
      date = source.createdAt.toISOString().slice(0, 10);
    }
  } else if (sourceType === "sales_invoice") {
    source = await db.query.salesInvoicesTable.findFirst({
      where: eq(salesInvoicesTable.id, sourceId),
    });
    if (source) {
      reference = source.invoiceNo;
      customerId = source.customerId ?? null;
      customerName = source.customerName;
      customerPhone = source.customerPhone;
      total = money(source.total);
      discount = money(source.discountAmount) + money(source.couponDiscountAmount);
      paid = money(source.paidAmount);
      remaining = money(source.remainingAmount);
      paymentStatus = source.paymentStatus;
      paymentMethod = source.paymentMethod;
      date = source.date;
    }
  } else {
    source = await db.query.koshaBookingsTable.findFirst({
      where: eq(koshaBookingsTable.id, sourceId),
    });
    if (source) {
      reference = source.trackingCode ?? `KB-${source.id}`;
      customerName = source.customerName;
      customerPhone = source.phone;
      total = money(source.totalAmount);
      discount = money((source.bookingDetails as any)?.pricing?.discountAmount);
      paid = money(source.paidAmount);
      remaining = money(source.remainingAmount);
      paymentStatus = source.paymentStatus;
      paymentMethod = String((source.bookingDetails as any)?.pricing?.paymentMethod ?? "cash");
      date = source.createdAt.toISOString().slice(0, 10);
    }
  }
  if (!source) return null;
  if (!customerId && customerPhone) {
    customerId = (await findCustomerByPhone(customerPhone))?.id ?? null;
  }
  const lastPayment = await db.query.financialTransactionsTable.findFirst({
    where: and(
      eq(financialTransactionsTable.sourceType, sourceType),
      eq(financialTransactionsTable.sourceId, String(sourceId)),
      eq(financialTransactionsTable.sourceEvent, "payment"),
    ),
    orderBy: [desc(financialTransactionsTable.createdAt)],
  });
  return {
    source,
    sourceType,
    sourceId,
    reference,
    customerId,
    customerName,
    customerPhone,
    total,
    discount,
    paid,
    remaining,
    paymentStatus,
    paymentMethod,
    date,
    lastPayment: lastPayment
      ? {
          amount: money(lastPayment.amount),
          date: lastPayment.transactionDate,
          createdAt: lastPayment.createdAt.toISOString(),
          method: lastPayment.paymentMethod,
          status: lastPayment.approvalStatus,
          transactionNo: lastPayment.transactionNo,
        }
      : null,
  };
}

async function collectionLastPayments(
  sourceType: CollectionSourceType,
  sourceIds: number[],
) {
  const ids = [...new Set(sourceIds.filter((id) => Number.isInteger(id) && id > 0))];
  if (!ids.length) return new Map<number, any>();
  const rows = await db.query.financialTransactionsTable.findMany({
    where: and(
      eq(financialTransactionsTable.sourceType, sourceType),
      inArray(financialTransactionsTable.sourceId, ids.map(String)),
      eq(financialTransactionsTable.sourceEvent, "payment"),
    ),
    orderBy: [desc(financialTransactionsTable.createdAt)],
  });
  const result = new Map<number, any>();
  for (const row of rows) {
    const id = Number(row.sourceId);
    if (!result.has(id)) {
      result.set(id, {
        amount: money(row.amount),
        date: row.transactionDate,
        createdAt: row.createdAt.toISOString(),
        method: row.paymentMethod,
        status: row.approvalStatus,
        transactionNo: row.transactionNo,
      });
    }
  }
  return result;
}

async function handleCollections(
  req: NextRequest,
  parts: string[],
  section: string | undefined,
) {
  if (section !== "collections") return null;
  const method = req.method;
  const currentUser = await getAdminUser(req);
  if (!currentUser) return error("غير مخول", 401);

  if (method === "GET" && parts[2] && parts[3]) {
    const auth = await requireAnyPermission(req, [
      "orders",
      "bookings",
      "accounting",
    ]);
    if (isResponse(auth)) return auth;
    const sourceType = parts[2] as CollectionSourceType;
    const sourceId = int(parts[3]);
    if (
      !paymentCollectionSchema.shape.sourceType.safeParse(sourceType).success ||
      !sourceId
    )
      return error("مرجع التحصيل غير صحيح", 400);
    const summary = await collectionSourceSummary(sourceType, sourceId);
    return summary ? json(summary) : error("الطلب أو الحجز غير موجود", 404);
  }

  if (method !== "POST") return error("العملية غير مدعومة", 405);
  if (!canEditOrderFinancials(currentUser))
    return error("تسجيل الدفعات متاح للمحاسب أو المدير فقط", 403);
  const parsed = paymentCollectionSchema.safeParse(await body(req));
  if (!parsed.success) return validationError("collections.create", parsed);
  const data = parsed.data;
  const before = await collectionSourceSummary(data.sourceType, data.sourceId);
  if (!before) return error("الطلب أو الحجز غير موجود", 404);
  if (["cancelled", "deleted"].includes(String(before.source.status)))
    return error("لا يمكن تحصيل دفعة لمعاملة ملغية", 409);
  if ((before.source as any).financiallyReversed)
    return error("تم عكس الأثر المالي لهذه المعاملة", 409);
  if (before.total <= 0) return error("يجب تحديد المبلغ الكلي أولاً", 409);
  if (before.remaining <= 0) return error("الحساب مدفوع بالكامل", 409);
  const amount = money(data.amount);
  if (amount > before.remaining)
    return error(`المبلغ أكبر من المتبقي (${formatCurrency(before.remaining)})`, 400);

  const paid = money(before.paid + amount);
  const remaining = money(Math.max(before.total - paid, 0));
  const paymentStatus = remaining <= 0 ? "paid" : "partial";
  const a = actor(currentUser);
  const sourceMethod = data.paymentMethod === "transfer" ? "transfer" : data.paymentMethod === "card" || data.paymentMethod === "pos" ? "pos" : "cash";

  try {
    if (data.sourceType === "order") {
      await db.update(ordersTable).set({
        depositAmount: String(paid),
        remainingAmount: String(remaining),
        paymentStatus,
        paymentMethod: sourceMethod === "cash" ? "paid" : sourceMethod,
        updatedAt: new Date(),
      }).where(eq(ordersTable.id, data.sourceId));
    } else if (data.sourceType === "service_order") {
      await db.update(serviceOrdersTable).set({
        depositAmount: String(paid),
        remainingAmount: String(remaining),
        paymentStatus,
        customFields: {
          ...((before.source.customFields ?? {}) as Record<string, unknown>),
          paymentMethod: sourceMethod,
        },
      }).where(eq(serviceOrdersTable.id, data.sourceId));
    } else if (data.sourceType === "sales_invoice") {
      await db.update(salesInvoicesTable).set({
        paidAmount: String(paid),
        remainingAmount: String(remaining),
        paymentStatus,
        paymentMethod: sourceMethod,
        updatedAt: new Date(),
      }).where(eq(salesInvoicesTable.id, data.sourceId));
    } else {
      await db.update(koshaBookingsTable).set({
        paidAmount: String(paid),
        remainingAmount: String(remaining),
        paymentStatus,
        bookingDetails: {
          ...((before.source.bookingDetails ?? {}) as Record<string, unknown>),
          pricing: {
            ...(((before.source.bookingDetails as any)?.pricing ?? {}) as Record<string, unknown>),
            paymentMethod: sourceMethod,
          },
        },
        updatedAt: new Date(),
      }).where(eq(koshaBookingsTable.id, data.sourceId));
    }

    const [voucher] = await db.insert(receiptVouchersTable).values({
      voucherNo: temporaryVoucherNo(),
      date: new Date().toISOString().slice(0, 10),
      amount: String(amount),
      payerName: textFallback(before.customerName, "زبون"),
      customerId: before.customerId,
      orderId: data.sourceType === "order" ? data.sourceId : null,
      bookingId: data.sourceType === "service_order" ? data.sourceId : null,
      reference: nullableText(
        data.receiptNo
          ? `${before.reference} | ${data.receiptNo}`
          : before.reference,
      ),
      method: sourceMethod,
      notes: nullableText(data.notes),
      createdBy: a.id,
      createdByName: a.name,
    }).returning();
    const [savedVoucher] = await db.update(receiptVouchersTable).set({
      voucherNo: fmtVoucherNo("REC", voucher.id, voucher.createdAt),
    }).where(eq(receiptVouchersTable.id, voucher.id)).returning();

    const updated = await collectionSourceSummary(data.sourceType, data.sourceId);
    let financialTransaction: any = null;
    if (updated) {
      if (data.sourceType === "order")
        financialTransaction = await syncOrderFinancialPayment(updated.source, financialActor(currentUser));
      else if (data.sourceType === "service_order")
        financialTransaction = await syncServiceOrderFinancialPayment(updated.source, financialActor(currentUser));
      else if (data.sourceType === "kosha_booking")
        financialTransaction = await syncKoshaFinancialPayment(updated.source, financialActor(currentUser));
      else
        financialTransaction = await syncSourcePaymentTarget({
          sourceType: "sales_invoice",
          sourceId: data.sourceId,
          sourceEvent: "payment",
          targetAmount: paid,
          normalDirection: "revenue",
          transactionDate: updated.date,
          department: "store",
          transactionType: "sales_invoice",
          description: `دفعة فاتورة مبيعات ${updated.reference}`,
          paymentMethod: sourceMethod,
          customerId: updated.customerId,
          customerName: updated.customerName,
          customerPhone: updated.customerPhone,
          notes: data.notes,
        }, financialActor(currentUser));
    }
    if (financialTransaction) {
      await db.update(receiptVouchersTable).set({
        approvalStatus: financialTransaction.approvalStatus,
        financialTransactionId: financialTransaction.id,
      }).where(eq(receiptVouchersTable.id, savedVoucher.id));
    }

    let receiptImage: string | null = null;
    if (data.receiptImage) {
      receiptImage = await persistMediaValue(
        data.receiptImage,
        `receipts/${data.sourceType}/${data.sourceId}`,
      );
      if (receiptImage) {
        await ensureAdminExtensionsTables();
        await db.insert(entityDocumentsTable).values({
          entityType: data.sourceType,
          entityId: data.sourceId,
          documentType: "payment_receipt",
          title: `وصل دفعة ${savedVoucher.voucherNo}`,
          fileUrl: receiptImage,
          fileName: `receipt-${savedVoucher.voucherNo}`,
          mimeType: "image/*",
          metadata: { voucherId: savedVoucher.id, amount, receiptNo: data.receiptNo },
          uploadedBy: a.id,
          uploadedByName: a.name,
        });
      }
    }
    await addEntityTimeline({
      entityType: data.sourceType,
      entityId: data.sourceId,
      type: "payment_added",
      title: "تم تسجيل دفعة جديدة",
      body: `${formatCurrency(amount)} بواسطة ${a.name}`,
      actor: erpActorFromAdmin(currentUser),
      metadata: {
        voucherId: savedVoucher.id,
        voucherNo: savedVoucher.voucherNo,
        amount,
        paymentMethod: sourceMethod,
        paid,
        remaining,
        receiptImage,
      },
    });
    await logAdminActivity(req, "payment_added", data.sourceType, data.sourceId, {
      amount,
      paymentMethod: sourceMethod,
      voucherNo: savedVoucher.voucherNo,
      receiptNo: data.receiptNo,
      oldValues: { paid: before.paid, remaining: before.remaining },
      newValues: { paid, remaining, paymentStatus },
      device: req.headers.get("user-agent")?.slice(0, 180) ?? "unknown",
    });
    void notifyTelegramPayment({
      event: "paymentReceived",
      reference: before.reference,
      customerName: before.customerName,
      amount,
      paymentMethod: sourceMethod,
      createdByName: a.name,
      status: financialTransaction?.approvalStatus ?? "pending",
      entityPath: erpEntityHref(data.sourceType, data.sourceId),
    });
    revalidateTag(ENTERPRISE_COMMAND_CENTER_TAG, { expire: 0 });
    return json({
      ok: true,
      voucher: savedVoucher,
      financialTransaction,
      summary: await collectionSourceSummary(data.sourceType, data.sourceId),
    }, 201);
  } catch (err: any) {
    console.error("payment collection failed", {
      sourceType: data.sourceType,
      sourceId: data.sourceId,
      userId: currentUser.id,
      message: err?.message,
    });
    return error(err?.message || "تعذر تسجيل الدفعة", 500);
  }
}

async function formatRentalOrder(row: typeof rentalOrdersTable.$inferSelect) {
  const product = await db.query.productsTable.findFirst({
    where: eq(productsTable.id, row.productId),
  });
  return {
    id: row.id,
    orderNo: row.orderNo,
    trackingCode: row.orderNo,
    kind: "rental",
    productId: row.productId,
    productName: product?.nameAr || product?.name || "منتج إيجار",
    productImage: product
      ? publicMediaValue("product", product, product.images?.[0], 0)
      : null,
    customerName: row.customerName,
    customerPhone: row.phone,
    startDate: row.startDate,
    endDate: row.endDate,
    days: row.days,
    pricePerDay: Number(row.pricePerDay),
    total: Number(row.totalAmount),
    paidAmount: Number(row.paidAmount),
    remainingAmount: Number(row.remainingAmount),
    paymentMethod: row.paymentMethod,
    paymentStatus: row.paymentStatus,
    status: row.status,
    notes: row.notes ?? "",
    createdAt: row.createdAt.toISOString(),
  };
}

async function handleRentalOrders(req: NextRequest, parts: string[]) {
  const method = req.method;
  await ensureRentalProductsTables();

  if (method === "POST" && parts.length === 1) {
    const parsed = RentalOrderCreateSchema.safeParse(await body(req));
    if (!parsed.success) return validationError("rental-orders.create", parsed);
    const data = parsed.data;
    const days = rentalDays(data.startDate, data.endDate);
    if (!days)
      return error("تاريخ النهاية يجب أن يكون بعد أو بنفس تاريخ البداية", 400);

    const product = (await db.query.productsTable.findFirst({
      where: and(
        eq(productsTable.id, data.productId),
        eq(productsTable.isActive, true),
      ),
    })) as any;
    if (!product || !Boolean(product.isRental ?? product.is_rental))
      return error("هذا المنتج غير متاح للإيجار", 404);

    const phone = normalizeIraqiPhone(data.phone);
    if (!phone) return error("رقم الهاتف العراقي غير صحيح", 400);
    const customerName = textFallback(
      data.customerName,
      formatIraqiPhone(phone),
      "زبون",
    );
    const customer = await ensureCustomerForPhone(phone, customerName);
    const stockOwner = await getStockOwnerProduct(product.id);
    if (!stockOwner) return error("المنتج غير موجود", 404);
    const stockSource = stockOwner.stockProduct;
    if (Number(stockSource.stock ?? 0) <= 0)
      return error("المنتج محجوز حالياً أو غير متوفر للإيجار", 409);
    const overlap = await findRentalOverlap(
      stockSource.id,
      data.startDate,
      data.endDate,
    );
    if (overlap) return error("يوجد حجز إيجار لنفس المنتج ضمن هذه الفترة", 409);

    const pricePerDay =
      Number(product.pricePerDay ?? product.price_per_day ?? 0) ||
      Number(product.price ?? 0) ||
      0;
    if (pricePerDay <= 0)
      return error("سعر الإيجار اليومي غير محدد لهذا المنتج", 400);
    const total = days * pricePerDay;
    const payment = paymentSummary(
      total,
      data.paidAmount ?? 0,
      undefined,
      data.paymentMethod,
    );
    const paid = payment.deposit;
    const remaining = payment.remaining;
    const orderNo = rentalOrderNo(phone);
    const paymentStatus = payment.status;
    const [rentalOrder] = await db
      .insert(rentalOrdersTable)
      .values({
        orderNo,
        productId: product.id,
        stockSourceProductId: stockSource.id,
        customerId: customer?.id ?? null,
        customerName,
        phone,
        phoneLast4: phoneLast4(phone),
        startDate: data.startDate,
        endDate: data.endDate,
        days,
        pricePerDay: String(pricePerDay),
        totalAmount: String(total),
        paidAmount: String(paid),
        remainingAmount: String(remaining),
        paymentMethod: data.paymentMethod,
        paymentStatus,
        status: RENTAL_ACTIVE_STATUS,
        notes: data.notes,
        stockApplied: 1,
      })
      .returning();

    const orderPaymentMethod = rentalStorePaymentMethod(
      data.paymentMethod,
      paid,
      total,
    );
    const [storeOrder] = await db
      .insert(ordersTable)
      .values({
        trackingCode: orderNo,
        phoneLast4: phoneLast4(phone),
        customerId: customer?.id ?? undefined,
        customerName,
        customerPhone: phone,
        status: RENTAL_ACTIVE_STATUS,
        serviceType: "rental",
        total: String(total),
        deliveryFee: "0",
        paymentMethod: orderPaymentMethod,
        depositAmount: String(paid),
        remainingAmount: String(remaining),
        paymentStatus,
        notes: data.notes || null,
        stockApplied: 1,
      })
      .returning();
    const rentalDetails = rentalCustomization({
      rentalOrderId: rentalOrder.id,
      orderNo,
      startDate: data.startDate,
      endDate: data.endDate,
      days,
      pricePerDay,
      totalAmount: total,
      status: RENTAL_ACTIVE_STATUS,
    });
    await db.insert(orderItemsTable).values({
      orderId: storeOrder.id,
      productId: product.id,
      productName: product.name ?? "",
      productNameAr: product.nameAr ?? product.name ?? "",
      quantity: 1,
      price: String(total),
      customization: rentalDetails,
      image: publicMediaValue("product", product, product.images?.[0], 0),
    });

    await adjustProductStock(product.id, -1, {
      reason: "rental_stock_deducted",
      relatedType: "order",
      relatedId: storeOrder.id,
    });
    const rentalPassport = await db.query.assetPassportsTable.findFirst({
      where: eq(assetPassportsTable.productId, stockSource.id),
    });
    const rentalRevenue =
      enterpriseNumber(rentalPassport?.revenueTotal) + total;
    await db
      .insert(assetPassportsTable)
      .values({
        productId: stockSource.id,
        revenueTotal: String(rentalRevenue),
      })
      .onConflictDoUpdate({
        target: assetPassportsTable.productId,
        set: { revenueTotal: String(rentalRevenue), updatedAt: new Date() },
      });
    void addEntityTimeline({
      entityType: "asset",
      entityId: stockSource.id,
      type: "rental",
      title: "إيجار الأصل",
      body: `${orderNo} · ${customerName} · ${formatCurrency(total)}`,
      actor: SYSTEM_FINANCIAL_ACTOR,
      metadata: {
        rentalOrderId: rentalOrder.id,
        orderId: storeOrder.id,
        revenue: total,
      },
    });
    const financialTransaction = await syncOrderFinancialPayment(
      storeOrder,
      SYSTEM_FINANCIAL_ACTOR,
    );
    if (financialTransaction?.id) {
      await db
        .update(rentalOrdersTable)
        .set({
          financialTransactionId: financialTransaction.id,
          updatedAt: new Date(),
        })
        .where(eq(rentalOrdersTable.id, rentalOrder.id));
    }
    await db.insert(orderStatusHistoryTable).values({
      orderId: storeOrder.id,
      status: RENTAL_ACTIVE_STATUS,
      notes: "تم إنشاء حجز الإيجار",
    });
    const orderQr = await ensureQrForEntity("order", storeOrder, req);
    void logAdminActivity(req, "rental_order_created", "order", storeOrder.id, {
      orderNo,
      rentalOrderId: rentalOrder.id,
      productId: product.id,
    });
    void createNotification({
      type: "order_new",
      title: "حجز إيجار جديد",
      body: `${customerName} - ${orderNo}`,
      entityType: "order",
      entityId: storeOrder.id,
      href: "/admin/orders",
    });
    void notifyLowStockForProductIds([product.id]);
    void notifyTelegramOrder({
      kind: "store",
      id: storeOrder.id,
      reference: storeOrder.trackingCode,
      customerName: storeOrder.customerName,
      phone: storeOrder.customerPhone,
      createdByName: "المتجر الإلكتروني",
      createdAt: storeOrder.createdAt,
      paymentMethod: storeOrder.paymentMethod,
      total: storeOrder.total,
      paid: storeOrder.depositAmount,
      remaining: storeOrder.remainingAmount,
      status: "إيجار نشط",
      notes: storeOrder.notes,
      qrDataUrl: orderQr.dataUrl,
      items: [
        {
          productName: product.nameAr || product.name || "منتج إيجار",
          quantity: 1,
          unitPrice: total,
          total,
        },
      ],
    });
    return json(
      {
        ...(await formatOrder(storeOrder)),
        orderNo,
        rentalOrderId: rentalOrder.id,
      },
      201,
    );
  }

  if (method === "GET" && parts.length === 1) {
    const auth = await requireAnyPermission(req, [
      "products",
      "orders",
      "accounting",
    ]);
    if (isResponse(auth)) return auth;
    const productId = int(req.nextUrl.searchParams.get("productId") ?? "");
    const status = req.nextUrl.searchParams.get("status")?.trim();
    const where = and(
      productId
        ? or(
            eq(rentalOrdersTable.productId, productId),
            eq(rentalOrdersTable.stockSourceProductId, productId),
          )
        : undefined,
      status ? eq(rentalOrdersTable.status, status) : undefined,
    );
    const rows = await db.query.rentalOrdersTable.findMany({
      where,
      orderBy: [desc(rentalOrdersTable.createdAt)],
      limit: 300,
    });
    return json(await Promise.all(rows.map(formatRentalOrder)));
  }

  if (method === "PATCH" && parts[1]) {
    const auth = await requireAnyPermission(req, ["products", "orders"]);
    if (isResponse(auth)) return auth;
    const id = int(parts[1]);
    if (!id) return error("معرف غير صحيح", 400);
    const data = await body(req);
    const nextStatus = String(data?.status ?? "").trim();
    if (!["active", "returned", "cancelled"].includes(nextStatus))
      return error("حالة الإيجار غير صحيحة", 400);
    const existing = await db.query.rentalOrdersTable.findFirst({
      where: eq(rentalOrdersTable.id, id),
    });
    if (!existing) return error("حجز الإيجار غير موجود", 404);
    const update: any = { status: nextStatus, updatedAt: new Date() };
    if (
      existing.status === RENTAL_ACTIVE_STATUS &&
      RENTAL_CLOSED_STATUSES.has(nextStatus) &&
      Number(existing.stockApplied ?? 1) === 1
    ) {
      await adjustProductStock(existing.productId, 1, {
        reason:
          nextStatus === "cancelled"
            ? "rental_cancelled_stock_restored"
            : "rental_returned_stock_restored",
        relatedType: "rental_order",
        relatedId: existing.id,
        createdBy: auth.id ?? null,
        createdByName: auth.fullName || auth.username,
      });
      update.stockApplied = 0;
      update.stockRestoredAt = new Date();
      if (nextStatus === "returned") update.returnedAt = new Date();
      if (nextStatus === "cancelled") update.cancelledAt = new Date();
    } else if (
      RENTAL_CLOSED_STATUSES.has(existing.status) &&
      nextStatus === RENTAL_ACTIVE_STATUS &&
      Number(existing.stockApplied ?? 0) === 0
    ) {
      const stockOwner = await getStockOwnerProduct(existing.productId);
      if (!stockOwner || Number(stockOwner.stockProduct.stock ?? 0) <= 0)
        return error("لا يوجد مخزون متاح لإعادة تفعيل الحجز", 409);
      const overlap = await findRentalOverlap(
        stockOwner.stockProduct.id,
        String(existing.startDate),
        String(existing.endDate),
        existing.id,
      );
      if (overlap) return error("يوجد حجز إيجار آخر ضمن نفس الفترة", 409);
      await adjustProductStock(existing.productId, -1, {
        reason: "rental_reactivated_stock_deducted",
        relatedType: "rental_order",
        relatedId: existing.id,
        createdBy: auth.id ?? null,
        createdByName: auth.fullName || auth.username,
      });
      update.stockApplied = 1;
      update.stockRestoredAt = null;
      update.returnedAt = null;
      update.cancelledAt = null;
    }
    if (
      existing.status === RENTAL_ACTIVE_STATUS &&
      nextStatus === "cancelled"
    ) {
      const sourceId = existing.stockSourceProductId ?? existing.productId;
      const passport = await db.query.assetPassportsTable.findFirst({
        where: eq(assetPassportsTable.productId, sourceId),
      });
      const nextRevenue = Math.max(
        0,
        enterpriseNumber(passport?.revenueTotal) -
          enterpriseNumber(existing.totalAmount),
      );
      await db
        .insert(assetPassportsTable)
        .values({ productId: sourceId, revenueTotal: String(nextRevenue) })
        .onConflictDoUpdate({
          target: assetPassportsTable.productId,
          set: { revenueTotal: String(nextRevenue), updatedAt: new Date() },
        });
      void addEntityTimeline({
        entityType: "asset",
        entityId: sourceId,
        type: "rental_reversal",
        title: "عكس إيراد إيجار ملغي",
        body: existing.orderNo,
        actor: financialActor(auth),
        metadata: {
          rentalOrderId: existing.id,
          revenueReversal: enterpriseNumber(existing.totalAmount),
        },
      });
    } else if (
      existing.status === "cancelled" &&
      nextStatus === RENTAL_ACTIVE_STATUS
    ) {
      const sourceId = existing.stockSourceProductId ?? existing.productId;
      const passport = await db.query.assetPassportsTable.findFirst({
        where: eq(assetPassportsTable.productId, sourceId),
      });
      const nextRevenue =
        enterpriseNumber(passport?.revenueTotal) +
        enterpriseNumber(existing.totalAmount);
      await db
        .insert(assetPassportsTable)
        .values({ productId: sourceId, revenueTotal: String(nextRevenue) })
        .onConflictDoUpdate({
          target: assetPassportsTable.productId,
          set: { revenueTotal: String(nextRevenue), updatedAt: new Date() },
        });
    }
    const [row] = await db
      .update(rentalOrdersTable)
      .set(update)
      .where(eq(rentalOrdersTable.id, id))
      .returning();
    if (!row) return error("حجز الإيجار غير موجود", 404);
    const storeOrder = await db.query.ordersTable.findFirst({
      where: eq(ordersTable.trackingCode, existing.orderNo),
    });
    let financialTransaction: any = null;
    if (storeOrder) {
      const [updatedStoreOrder] = await db
        .update(ordersTable)
        .set({
          status: nextStatus,
          depositAmount: row.paidAmount,
          remainingAmount: row.remainingAmount,
          paymentStatus: row.paymentStatus,
          stockApplied: update.stockApplied ?? storeOrder.stockApplied,
          stockRestoredAt: update.stockRestoredAt ?? storeOrder.stockRestoredAt,
          updatedAt: new Date(),
        } as any)
        .where(eq(ordersTable.id, storeOrder.id))
        .returning();
      await db.insert(orderStatusHistoryTable).values({
        orderId: storeOrder.id,
        status: nextStatus,
        notes: "تحديث حالة الإيجار",
      });
      financialTransaction = updatedStoreOrder
        ? await syncOrderFinancialPayment(
            updatedStoreOrder,
            financialActor(auth),
          )
        : null;
    } else {
      financialTransaction = row
        ? await syncRentalFinancialPayment(row, financialActor(auth))
        : null;
    }
    if (financialTransaction?.id) {
      await db
        .update(rentalOrdersTable)
        .set({
          financialTransactionId: financialTransaction.id,
          updatedAt: new Date(),
        })
        .where(eq(rentalOrdersTable.id, id));
    }
    void logAdminActivity(
      req,
      "rental_order_status_updated",
      "rental_order",
      id,
      { from: existing.status, to: nextStatus },
    );
    const fresh = await db.query.rentalOrdersTable.findFirst({
      where: eq(rentalOrdersTable.id, id),
    });
    return json(await formatRentalOrder(fresh ?? row));
  }

  return null;
}

const PhotographyEventCreateSchema = z.object({
  clientToken: z.string().trim().min(16).max(64),
  groomName: z.string().trim().min(1, "اسم العريس مطلوب"),
  eventName: z.string().trim().optional().default(""),
  eventDate: z.string().regex(/^\d{4}-\d{2}-\d{2}$/, "تاريخ المناسبة غير صحيح"),
  location: z.string().trim().optional().default(""),
  assignedStaffId: z.coerce.number().int().positive().optional().nullable(),
});

const PhotographyOrderCreateSchema = z.object({
  clientToken: z.string().trim().min(16).max(64),
  customerName: z.string().trim().min(1, "اسم الزبون مطلوب"),
  phone: z.string().trim().optional().default(""),
  copies: z.coerce.number().int().min(1).max(999),
  unitPrice: z.coerce.number().positive("اختر السعر"),
  // Legacy/optional — total is computed server-side from unitPrice × copies.
  printType: z.string().trim().optional().default(""),
  totalAmount: z.coerce.number().nonnegative().optional(),
  // Payment intent: true = "مدفوع" (full amount sent for manager approval), false/undefined = "غير مدفوع".
  paid: z.boolean().optional(),
  paidAmount: z.coerce.number().nonnegative().optional().default(0),
  photoNumber: z.string().trim().optional().default(""),
  notes: z.string().trim().optional().default(""),
  referenceImage: z.string().optional().nullable(),
});

const PhotographyEventUpdateSchema = z.object({
  groomName: z.string().trim().min(1).optional(),
  eventName: z.string().trim().optional(),
  eventDate: z
    .string()
    .regex(/^\d{4}-\d{2}-\d{2}$/)
    .optional(),
  location: z.string().trim().optional(),
  assignedStaffId: z.coerce.number().int().positive().optional().nullable(),
});

const PhotographyOrderUpdateSchema = z.object({
  customerName: z.string().trim().min(1).optional(),
  phone: z.string().trim().optional(),
  copies: z.coerce.number().int().min(1).max(999).optional(),
  unitPrice: z.coerce.number().positive().optional(),
  notes: z.string().trim().optional(),
});

const PhotographyStatusSchema = z.object({
  status: z.enum(PHOTOGRAPHY_ORDER_STAGES),
  note: z.string().trim().optional().default(""),
});

const PhotographyCollectSchema = z.object({
  amount: z.coerce.number().positive(),
  note: z.string().trim().optional().default(""),
});

function isPhotographyManager(user: AdminUser) {
  return user.role === "admin" || user.role === "manager";
}

function photographyStaffName(user: AdminUser) {
  return user.fullName || user.username;
}

async function getPhotographyEventByRef(value: string) {
  // A real server id is short and all-digits; a clientToken is a 32-char hex string that may
  // START with a digit. We MUST NOT parseInt the token (that resolves to a wrong event → 404).
  const isNumericId = /^\d+$/.test(value) && value.length <= 12;
  const event = await db.query.photographyEventsTable.findFirst({
    where: isNumericId
      ? eq(photographyEventsTable.id, Number(value))
      : eq(photographyEventsTable.clientToken, value),
  });
  if (!event)
    console.warn("[photography] event lookup miss", {
      ref: value,
      isNumericId,
    });
  return event;
}

function canAccessPhotographyEvent(
  user: AdminUser,
  event: typeof photographyEventsTable.$inferSelect,
) {
  return isPhotographyManager(user) || event.assignedStaffId === user.id;
}

async function photographyPendingAmount(orderId: number) {
  const [row] = await db
    .select({
      total: sql<string>`coalesce(sum(${photographyPaymentRequestsTable.amount}), 0)`,
    })
    .from(photographyPaymentRequestsTable)
    .where(
      and(
        eq(photographyPaymentRequestsTable.orderId, orderId),
        eq(photographyPaymentRequestsTable.status, "pending"),
      ),
    );
  return Number(row?.total ?? 0);
}

async function formatPhotographyEvent(
  row: typeof photographyEventsTable.$inferSelect,
) {
  const [count] = await db
    .select({ total: sql<number>`count(*)::int` })
    .from(photographyOrdersTable)
    .where(eq(photographyOrdersTable.eventId, row.id));
  return {
    ...row,
    orderCount: Number(count?.total ?? 0),
    createdAt: row.createdAt.toISOString(),
    updatedAt: row.updatedAt.toISOString(),
  };
}

async function formatPhotographyEvents(
  rows: Array<typeof photographyEventsTable.$inferSelect>,
) {
  if (!rows.length) return [];
  const counts = await db
    .select({
      eventId: photographyOrdersTable.eventId,
      total: sql<number>`count(*)::int`,
    })
    .from(photographyOrdersTable)
    .where(
      inArray(
        photographyOrdersTable.eventId,
        rows.map((row) => row.id),
      ),
    )
    .groupBy(photographyOrdersTable.eventId);
  return rows.map((row) => ({
    ...row,
    orderCount: Number(
      counts.find((item) => item.eventId === row.id)?.total ?? 0,
    ),
    createdAt: row.createdAt.toISOString(),
    updatedAt: row.updatedAt.toISOString(),
  }));
}

// Event detail: the event plus ONLY its own (non-cancelled) orders and their financial aggregates.
async function formatPhotographyEventDetail(
  event: typeof photographyEventsTable.$inferSelect,
) {
  const orderRows = await db.query.photographyOrdersTable.findMany({
    where: and(
      eq(photographyOrdersTable.eventId, event.id),
      sql`${photographyOrdersTable.cancelledAt} is null`,
    ),
    orderBy: [desc(photographyOrdersTable.createdAt)],
  });
  const orders = await formatPhotographyOrders(orderRows);
  const summary = {
    orders: orders.length,
    copies: orders.reduce((sum, order) => sum + order.copies, 0),
    total: orders.reduce((sum, order) => sum + order.totalAmount, 0),
    paid: orders.reduce((sum, order) => sum + order.paidAmount, 0),
    remaining: orders.reduce((sum, order) => sum + order.remainingAmount, 0),
    paidCount: orders.filter((order) => order.paymentStatus === "paid").length,
    unpaidCount: orders.filter((order) => order.paymentStatus !== "paid")
      .length,
  };
  return {
    ...event,
    orderCount: orders.length,
    createdAt: event.createdAt.toISOString(),
    updatedAt: event.updatedAt.toISOString(),
    orders,
    summary,
  };
}

function photographyOrderJson(
  row: typeof photographyOrdersTable.$inferSelect,
  event: typeof photographyEventsTable.$inferSelect | null | undefined,
  pendingAmount: number,
  qr: Awaited<ReturnType<typeof ensureQrForEntity>> | null = null,
) {
  const totalAmount = Number(row.totalAmount);
  const paidAmount = Number(row.paidAmount);
  const remainingAmount = Number(row.remainingAmount);
  const paymentLabel =
    row.paymentStatus === "paid"
      ? "مدفوع"
      : pendingAmount > 0
        ? "بانتظار الاعتماد"
        : paidAmount > 0
          ? "مدفوع جزئياً"
          : "غير مدفوع";
  return {
    ...row,
    phone: row.phone ? (formatIraqiPhone(row.phone) ?? row.phone) : "",
    unitPrice: Number(row.unitPrice),
    totalAmount,
    paidAmount,
    remainingAmount,
    pendingAmount,
    paymentLabel,
    cancelledAt: row.cancelledAt?.toISOString() ?? null,
    event: event
      ? {
          id: event.id,
          clientToken: event.clientToken,
          groomName: event.groomName,
          eventName: event.eventName,
          eventDate: event.eventDate,
          location: event.location,
          assignedStaffName: event.assignedStaffName,
        }
      : null,
    referenceImage: publicMediaValue(
      "photography-order",
      row,
      row.referenceImage,
    ),
    qr,
    deliveredAt: row.deliveredAt?.toISOString() ?? null,
    createdAt: row.createdAt.toISOString(),
    updatedAt: row.updatedAt.toISOString(),
  };
}

async function formatPhotographyOrder(
  row: typeof photographyOrdersTable.$inferSelect,
  includeQr = false,
  req?: NextRequest,
) {
  const [event, pendingAmount] = await Promise.all([
    db.query.photographyEventsTable.findFirst({
      where: eq(photographyEventsTable.id, row.eventId),
    }),
    photographyPendingAmount(row.id),
  ]);
  const qr =
    includeQr && req
      ? await ensureQrForEntity("photography_order", row, req)
      : null;
  return photographyOrderJson(row, event, pendingAmount, qr);
}

async function formatPhotographyOrders(
  rows: Array<typeof photographyOrdersTable.$inferSelect>,
) {
  if (!rows.length) return [];
  const orderIds = rows.map((row) => row.id);
  const eventIds = Array.from(new Set(rows.map((row) => row.eventId)));
  const [events, pending] = await Promise.all([
    db.query.photographyEventsTable.findMany({
      where: inArray(photographyEventsTable.id, eventIds),
    }),
    db
      .select({
        orderId: photographyPaymentRequestsTable.orderId,
        total: sql<string>`coalesce(sum(${photographyPaymentRequestsTable.amount}), 0)`,
      })
      .from(photographyPaymentRequestsTable)
      .where(
        and(
          inArray(photographyPaymentRequestsTable.orderId, orderIds),
          eq(photographyPaymentRequestsTable.status, "pending"),
        ),
      )
      .groupBy(photographyPaymentRequestsTable.orderId),
  ]);
  return rows.map((row) =>
    photographyOrderJson(
      row,
      events.find((event) => event.id === row.eventId),
      Number(pending.find((item) => item.orderId === row.id)?.total ?? 0),
    ),
  );
}

async function addPhotographyOrderEvent(input: {
  orderId: number;
  staff: AdminUser;
  type: string;
  fromStatus?: string | null;
  toStatus?: string | null;
  note?: string | null;
}) {
  const [row] = await db
    .insert(photographyOrderEventsTable)
    .values({
      orderId: input.orderId,
      staffId: input.staff.id,
      staffName: photographyStaffName(input.staff),
      type: input.type,
      fromStatus: input.fromStatus ?? null,
      toStatus: input.toStatus ?? null,
      note: input.note ?? null,
    })
    .returning();
  return row;
}

async function photographyOrderForUser(orderId: number, user: AdminUser) {
  const order = await db.query.photographyOrdersTable.findFirst({
    where: eq(photographyOrdersTable.id, orderId),
  });
  if (!order) return null;
  if (!isPhotographyManager(user) && order.assignedStaffId !== user.id)
    return null;
  return order;
}

async function createPhotographyCollectionRequest(
  order: typeof photographyOrdersTable.$inferSelect,
  user: AdminUser,
  amount: number,
  note: string,
) {
  const pending = await photographyPendingAmount(order.id);
  const available = Math.max(0, Number(order.remainingAmount) - pending);
  if (amount > available)
    throw new Error(
      `المبلغ أكبر من المتبقي المتاح (${formatCurrency(available)})`,
    );
  const [request] = await db
    .insert(photographyPaymentRequestsTable)
    .values({
      orderId: order.id,
      staffId: user.id,
      staffName: photographyStaffName(user),
      amount: String(amount),
      note: nullableText(note),
      status: "pending",
    })
    .returning();
  try {
    const transaction = await createSourceFinancialRequest(
      {
        transactionDate: baghdadToday(),
        direction: "revenue",
        amount,
        department: "photography",
        transactionType: "photography_collection",
        description: `تحصيل طلب تصوير ${order.orderNo}`,
        paymentMethod: "cash",
        sourceType: "photography_order",
        sourceId: String(order.id),
        sourceEvent: `collection:${request.id}`,
        customerName: order.customerName,
        customerPhone: order.phone,
        notes: note || `طلب تحصيل من ${photographyStaffName(user)}`,
        idempotencyKey: `photography:${order.id}:collection:${request.id}`,
      },
      financialActor(user),
    );
    await db
      .update(photographyPaymentRequestsTable)
      .set({ financialTransactionId: transaction.id })
      .where(eq(photographyPaymentRequestsTable.id, request.id));
    await addPhotographyOrderEvent({
      orderId: order.id,
      staff: user,
      type: "payment_requested",
      note,
      fromStatus: order.status,
      toStatus: order.status,
    });
    void createNotification({
      type: "photography_payment_request",
      title: "طلب تحصيل تصوير بانتظار الاعتماد",
      body: `${photographyStaffName(user)} - ${order.orderNo} - ${formatCurrency(amount)}`,
      entityType: "financial_transaction",
      entityId: transaction.id,
      href: "/admin/finance/master-cash",
    });
    return { ...request, financialTransactionId: transaction.id };
  } catch (err) {
    await db
      .delete(photographyPaymentRequestsTable)
      .where(eq(photographyPaymentRequestsTable.id, request.id));
    throw err;
  }
}

async function finalizePhotographyPaymentRequest(
  transaction: any,
  approved: boolean,
  reviewer: FinancialActor,
  reason?: string | null,
) {
  if (transaction?.sourceType !== "photography_order") return;
  await ensurePhotographyStaffTables();
  const request = await db.query.photographyPaymentRequestsTable.findFirst({
    where: eq(
      photographyPaymentRequestsTable.financialTransactionId,
      transaction.id,
    ),
  });
  if (!request || request.status !== "pending") return;
  const order = await db.query.photographyOrdersTable.findFirst({
    where: eq(photographyOrdersTable.id, request.orderId),
  });
  if (!order) return;
  const reviewerId = reviewer.id ?? null;
  if (!approved) {
    await db
      .update(photographyPaymentRequestsTable)
      .set({
        status: "rejected",
        reviewedByStaffId: reviewerId,
        reviewedByName: reviewer.name,
        reviewedAt: new Date(),
      })
      .where(eq(photographyPaymentRequestsTable.id, request.id));
    await db.insert(photographyOrderEventsTable).values({
      orderId: order.id,
      staffId: reviewerId,
      staffName: reviewer.name,
      type: "payment_rejected",
      fromStatus: order.status,
      toStatus: order.status,
      note: reason ?? null,
    });
    void createNotification({
      audienceType: "admin",
      staffId: request.staffId,
      type: "photography_payment_rejected",
      title: "تم رفض دفعة التصوير",
      body: `${order.orderNo} - ${formatCurrency(request.amount)}`,
      entityType: "photography_order",
      entityId: order.id,
      href: `/staff/photography/orders/${order.id}`,
    });
    return;
  }
  const amount = Number(request.amount);
  const paidAmount = Math.min(
    Number(order.totalAmount),
    Number(order.paidAmount) + amount,
  );
  const remainingAmount = Math.max(0, Number(order.totalAmount) - paidAmount);
  const paymentStatus =
    remainingAmount <= 0 ? "paid" : paidAmount > 0 ? "partial" : "unpaid";
  await db.transaction(async (tx) => {
    await tx
      .update(photographyOrdersTable)
      .set({
        paidAmount: String(paidAmount),
        remainingAmount: String(remainingAmount),
        paymentStatus,
        updatedAt: new Date(),
      })
      .where(eq(photographyOrdersTable.id, order.id));
    await tx
      .update(photographyPaymentRequestsTable)
      .set({
        status: "approved",
        reviewedByStaffId: reviewerId,
        reviewedByName: reviewer.name,
        reviewedAt: new Date(),
      })
      .where(eq(photographyPaymentRequestsTable.id, request.id));
    await tx.insert(photographyOrderEventsTable).values({
      orderId: order.id,
      staffId: reviewerId,
      staffName: reviewer.name,
      type: "payment_approved",
      fromStatus: order.status,
      toStatus: order.status,
      note: reason ?? null,
    });
  });
  void createNotification({
    audienceType: "admin",
    staffId: request.staffId,
    type: "photography_payment_approved",
    title: "تم اعتماد دفعة التصوير",
    body: `${order.orderNo} - ${formatCurrency(amount)}`,
    entityType: "photography_order",
    entityId: order.id,
    href: `/staff/photography/orders/${order.id}`,
  });
}

function telegramText(value: unknown) {
  return String(value ?? "").replace(
    /[&<>]/g,
    (char) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" })[char] ?? char,
  );
}

async function handlePhotographyStaffPortal(
  req: NextRequest,
  parts: string[],
): Promise<NextResponse | null> {
  if (parts[1] !== "photography") return null;
  await ensurePhotographyStaffTables();
  const auth = await requirePermission(req, "photography");
  if (isResponse(auth)) return auth;
  const method = req.method;
  const resource = parts[2] ?? "dashboard";
  const ref = parts[3] ? decodeURIComponent(parts[3]) : null;
  const action = parts[4];
  const manager = isPhotographyManager(auth);
  const own = <T extends { assignedStaffId: number | null }>(rows: T[]) =>
    manager ? rows : rows.filter((row) => row.assignedStaffId === auth.id);

  if (resource === "photographers" && method === "GET") {
    const rows = await db.query.staffTable.findMany({
      where: eq(staffTable.isActive, true),
      orderBy: [asc(staffTable.fullName), asc(staffTable.id)],
    });
    const photographers = rows.filter(
      (row) =>
        row.role === "admin" ||
        row.role === "manager" ||
        (Array.isArray(row.permissions) &&
          row.permissions.includes("photography")),
    );
    return json(
      (manager
        ? photographers
        : photographers.filter((row) => row.id === auth.id)
      ).map((row) => ({ id: row.id, name: row.fullName || row.username })),
    );
  }

  if (resource === "events") {
    if (method === "GET" && !ref) {
      const params = req.nextUrl.searchParams;
      const search = (params.get("search") || "").trim().toLowerCase();
      const includeArchived = params.get("archived") === "1";
      const photographerId = manager
        ? int(params.get("photographerId") || "")
        : null;
      const from = params.get("from") || "";
      const to = params.get("to") || "";
      let rows = own(
        await db.query.photographyEventsTable.findMany({
          orderBy: [
            desc(photographyEventsTable.eventDate),
            desc(photographyEventsTable.id),
          ],
          limit: 300,
        }),
      );
      if (!includeArchived)
        rows = rows.filter((row) => row.status !== "archived");
      if (photographerId)
        rows = rows.filter((row) => row.assignedStaffId === photographerId);
      if (from) rows = rows.filter((row) => row.eventDate >= from);
      if (to) rows = rows.filter((row) => row.eventDate <= to);
      if (search)
        rows = rows.filter((row) =>
          `${row.groomName} ${row.eventName ?? ""} ${row.location ?? ""}`
            .toLowerCase()
            .includes(search),
        );
      return json(await formatPhotographyEvents(rows));
    }
    if (method === "POST" && !ref) {
      const parsed = PhotographyEventCreateSchema.safeParse(await body(req));
      if (!parsed.success)
        return validationError("staff.photography.events.create", parsed);
      const data = parsed.data;
      const assignedId =
        manager && data.assignedStaffId ? data.assignedStaffId : auth.id;
      const assigned = await db.query.staffTable.findFirst({
        where: and(
          eq(staffTable.id, assignedId),
          eq(staffTable.isActive, true),
        ),
      });
      if (!assigned || (!manager && assigned.id !== auth.id))
        return error("المصور المسؤول غير صحيح", 400);
      const existing = await db.query.photographyEventsTable.findFirst({
        where: eq(photographyEventsTable.clientToken, data.clientToken),
      });
      if (existing) return json(await formatPhotographyEvent(existing));
      const [row] = await db
        .insert(photographyEventsTable)
        .values({
          clientToken: data.clientToken,
          groomName: data.groomName,
          eventName: nullableText(data.eventName),
          eventDate: data.eventDate,
          location: nullableText(data.location),
          assignedStaffId: assigned.id,
          assignedStaffName: assigned.fullName || assigned.username,
          createdBy: auth.id,
        })
        .returning();
      void logAdminActivity(
        req,
        "photography_event_created",
        "photography_event",
        row.id,
        { groomName: row.groomName, assignedStaffId: assigned.id },
      );
      void createNotification({
        audienceType: "admin",
        staffId: assigned.id,
        type: "photography_event_new",
        title: "مناسبة تصوير جديدة",
        body: `${row.groomName} - ${row.eventDate}`,
        entityType: "photography_event",
        entityId: row.id,
        href: `/staff/photography/events/${row.clientToken}/register`,
      });
      void createAutomaticTasksForEntity({
        entityType: "photography_event",
        entityId: row.id,
        serviceType: "photography",
        customerName: row.groomName,
        eventDate: row.eventDate,
        assignedStaffIds: [assigned.id],
        createdBy: auth.id,
      }).catch((err) =>
        console.error("auto photography tasks failed", {
          eventId: row.id,
          message: err?.message,
        }),
      );
      void addEntityTimeline({
        entityType: "photography_event",
        entityId: row.id,
        type: "created",
        title: "تم إنشاء مناسبة تصوير",
        body: `${row.groomName} - ${row.eventDate}`,
        actor: erpActorFromAdmin(auth),
        metadata: {
          assignedStaffId: assigned.id,
          clientToken: row.clientToken,
        },
      }).catch((err) =>
        console.error("photography event timeline failed", {
          eventId: row.id,
          message: err?.message,
        }),
      );
      return json(await formatPhotographyEvent(row), 201);
    }
    if (method === "GET" && ref && !action) {
      const event = await getPhotographyEventByRef(ref);
      if (!event || !canAccessPhotographyEvent(auth, event))
        return error("المناسبة غير موجودة", 404);
      return json(await formatPhotographyEventDetail(event));
    }
    if (method === "POST" && ref && action === "orders") {
      const event = await getPhotographyEventByRef(ref);
      if (!event || !canAccessPhotographyEvent(auth, event))
        return error("المناسبة غير موجودة", 404);
      if (event.status === "archived")
        return error("المناسبة مؤرشفة — لا يمكن إضافة طلبات إليها", 409);
      const parsed = PhotographyOrderCreateSchema.safeParse(await body(req));
      if (!parsed.success)
        return validationError("staff.photography.orders.create", parsed);
      const data = parsed.data;
      // Phone is optional. If provided, normalize it; keep the raw digits if it isn't a valid Iraqi number
      // rather than blocking the save (an empty phone is shown as "غير مسجل" in the UI).
      const phoneInput = (data.phone ?? "").trim();
      const phone = phoneInput
        ? (normalizeIraqiPhone(phoneInput) ?? phoneInput.replace(/\D/g, ""))
        : "";
      // Total is authoritative server-side: selected unit price × number of copies.
      const total = money(data.unitPrice * data.copies);
      // Payment intent: "مدفوع" → full amount sent for manager approval; "غير مدفوع" → nothing collected.
      const paidRequested =
        data.paid !== undefined
          ? data.paid
            ? total
            : 0
          : Math.min(money(data.paidAmount ?? 0), total);
      const existingOrder = await db.query.photographyOrdersTable.findFirst({
        where: eq(photographyOrdersTable.clientToken, data.clientToken),
      });
      if (existingOrder) {
        if (paidRequested > 0) {
          const existingPayment =
            await db.query.photographyPaymentRequestsTable.findFirst({
              where: eq(
                photographyPaymentRequestsTable.orderId,
                existingOrder.id,
              ),
            });
          if (!existingPayment && Number(existingOrder.paidAmount) === 0) {
            await createPhotographyCollectionRequest(
              existingOrder,
              auth,
              paidRequested,
              "دفعة أولية عند تسجيل طلب التصوير",
            );
          }
        }
        return json(await formatPhotographyOrder(existingOrder, true, req));
      }
      const referenceImage = data.referenceImage
        ? await persistMediaValue(
            data.referenceImage,
            `photography/orders/${event.id}`,
          )
        : null;
      const [created] = await db
        .insert(photographyOrdersTable)
        .values({
          clientToken: data.clientToken,
          orderNo: `TMP-${randomUUID()}`,
          eventId: event.id,
          assignedStaffId: event.assignedStaffId ?? auth.id,
          customerName: data.customerName,
          phone,
          copies: data.copies,
          printType: data.printType || "10x15",
          unitPrice: String(money(data.unitPrice)),
          totalAmount: String(total),
          paidAmount: "0",
          remainingAmount: String(total),
          paymentStatus: "unpaid",
          photoNumber: nullableText(data.photoNumber),
          notes: nullableText(data.notes),
          referenceImage,
          status: "registered",
          createdBy: auth.id,
        })
        .returning();
      const day = event.eventDate.replaceAll("-", "");
      const orderNo = `PH-${day}-${String(created.id).padStart(4, "0")}`;
      const [order] = await db
        .update(photographyOrdersTable)
        .set({ orderNo })
        .where(eq(photographyOrdersTable.id, created.id))
        .returning();
      await addPhotographyOrderEvent({
        orderId: order.id,
        staff: auth,
        type: "created",
        toStatus: "registered",
        note: data.notes,
      });
      const qr = await ensureQrForEntity("photography_order", order, req);
      if (paidRequested > 0)
        await createPhotographyCollectionRequest(
          order,
          auth,
          paidRequested,
          "دفعة كاملة عند تسجيل طلب التصوير",
        );
      void logAdminActivity(
        req,
        "photography_order_created",
        "photography_order",
        order.id,
        {
          orderNo,
          eventId: event.id,
          totalAmount: total,
          requestedPaidAmount: paidRequested,
        },
      );
      void createNotification({
        audienceType: "admin",
        staffId: order.assignedStaffId,
        type: "photography_order_new",
        title: "طلب صور جديد",
        body: `${orderNo} - ${order.customerName}`,
        entityType: "photography_order",
        entityId: order.id,
        href: `/staff/photography/orders/${order.id}`,
      });
      void createAutomaticTasksForEntity({
        entityType: "photography_order",
        entityId: order.id,
        serviceType: "photography",
        customerName: order.customerName,
        eventDate: event.eventDate,
        assignedStaffIds: order.assignedStaffId ? [order.assignedStaffId] : [],
        createdBy: auth.id,
      }).catch((err) =>
        console.error("auto photography order tasks failed", {
          orderId: order.id,
          message: err?.message,
        }),
      );
      void addEntityTimeline({
        entityType: "photography_order",
        entityId: order.id,
        type: "created",
        title: "تم تسجيل طلب تصوير",
        body: `${orderNo} - ${order.customerName}`,
        actor: erpActorFromAdmin(auth),
        metadata: { eventId: event.id, totalAmount: total, paidRequested },
      }).catch((err) =>
        console.error("photography order timeline failed", {
          orderId: order.id,
          message: err?.message,
        }),
      );
      void createSmartBookingNotifications({
        entityType: "photography_order",
        entityId: order.id,
        title: orderNo,
        customerName: order.customerName,
        eventDate: event.eventDate,
        remainingAmount: order.remainingAmount,
      }).catch((err) =>
        console.error("photography smart notifications failed", {
          orderId: order.id,
          message: err?.message,
        }),
      );
      void sendTelegramMessage(
        `📷 <b>طلب تصوير جديد</b>\nرقم الطلب: ${telegramText(orderNo)}\nالمناسبة: ${telegramText(event.groomName)}\nالزبون: ${telegramText(order.customerName)}\nالهاتف: ${telegramText(phone ? (formatIraqiPhone(phone) ?? phone) : "غير مسجل")}\nالمصور: ${telegramText(event.assignedStaffName)}\nالسعر: ${formatMoney(order.unitPrice)} × ${order.copies}\nالمبلغ: ${formatCurrency(total)}\nالمدفوع المطلوب اعتماده: ${formatCurrency(paidRequested)}\n${baseUrlFromReq(req)}/staff/photography/orders/${order.id}`,
      );
      return json({ ...(await formatPhotographyOrder(order, false)), qr }, 201);
    }
    if (method === "PATCH" && ref && !action) {
      if (!manager) return error("هذا الإجراء يخص المدير فقط", 403);
      const event = await getPhotographyEventByRef(ref);
      if (!event) return error("المناسبة غير موجودة", 404);
      const parsed = PhotographyEventUpdateSchema.safeParse(await body(req));
      if (!parsed.success)
        return validationError("staff.photography.events.update", parsed);
      const data = parsed.data;
      const patch: Partial<typeof photographyEventsTable.$inferInsert> = {
        updatedAt: new Date(),
      };
      if (data.groomName !== undefined) patch.groomName = data.groomName;
      if (data.eventName !== undefined)
        patch.eventName = nullableText(data.eventName);
      if (data.eventDate !== undefined) patch.eventDate = data.eventDate;
      if (data.location !== undefined)
        patch.location = nullableText(data.location);
      if (data.assignedStaffId) {
        const assigned = await db.query.staffTable.findFirst({
          where: and(
            eq(staffTable.id, data.assignedStaffId),
            eq(staffTable.isActive, true),
          ),
        });
        if (!assigned) return error("المصور المسؤول غير صحيح", 400);
        patch.assignedStaffId = assigned.id;
        patch.assignedStaffName = assigned.fullName || assigned.username;
        await db
          .update(photographyOrdersTable)
          .set({ assignedStaffId: assigned.id })
          .where(eq(photographyOrdersTable.eventId, event.id));
      }
      const [updated] = await db
        .update(photographyEventsTable)
        .set(patch)
        .where(eq(photographyEventsTable.id, event.id))
        .returning();
      void logAdminActivity(
        req,
        "photography_event_updated",
        "photography_event",
        event.id,
        { fields: Object.keys(data) },
      );
      return json(await formatPhotographyEvent(updated));
    }
    if (method === "POST" && ref && action === "archive") {
      if (!manager) return error("هذا الإجراء يخص المدير فقط", 403);
      const event = await getPhotographyEventByRef(ref);
      if (!event) return error("المناسبة غير موجودة", 404);
      const next = event.status === "archived" ? "active" : "archived";
      const [updated] = await db
        .update(photographyEventsTable)
        .set({ status: next, updatedAt: new Date() })
        .where(eq(photographyEventsTable.id, event.id))
        .returning();
      void logAdminActivity(
        req,
        next === "archived"
          ? "photography_event_archived"
          : "photography_event_unarchived",
        "photography_event",
        event.id,
      );
      return json(await formatPhotographyEvent(updated));
    }
    if (method === "DELETE" && ref && !action) {
      if (!manager) return error("هذا الإجراء يخص المدير فقط", 403);
      const event = await getPhotographyEventByRef(ref);
      if (!event) return error("المناسبة غير موجودة", 404);
      const [count] = await db
        .select({ total: sql<number>`count(*)::int` })
        .from(photographyOrdersTable)
        .where(eq(photographyOrdersTable.eventId, event.id));
      if (Number(count?.total ?? 0) > 0)
        return error(
          "لا يمكن حذف مناسبة تحتوي على طلبات — استخدم الأرشفة بدلاً من ذلك",
          409,
        );
      await db
        .delete(photographyEventsTable)
        .where(eq(photographyEventsTable.id, event.id));
      void logAdminActivity(
        req,
        "photography_event_deleted",
        "photography_event",
        event.id,
        { groomName: event.groomName },
      );
      return json({ ok: true });
    }
  }

  if (resource === "orders") {
    if (method === "GET" && !ref) {
      const params = req.nextUrl.searchParams;
      const search = (params.get("search") || "").trim();
      const status = (params.get("status") || "").trim();
      const includeCancelled = params.get("cancelled") === "1";
      const photographerId = manager
        ? int(params.get("photographerId") || "")
        : null;
      const eventRefParam = (params.get("eventRef") || "").trim();
      let eventFilterId: number | null = null;
      if (eventRefParam) {
        const ev = await getPhotographyEventByRef(eventRefParam);
        if (ev && canAccessPhotographyEvent(auth, ev)) eventFilterId = ev.id;
        else eventFilterId = -1;
      }
      let rows = own(
        await db.query.photographyOrdersTable.findMany({
          orderBy: [desc(photographyOrdersTable.createdAt)],
          limit: 400,
        }),
      );
      if (!includeCancelled) rows = rows.filter((row) => !row.cancelledAt);
      if (
        status &&
        (PHOTOGRAPHY_ORDER_STAGES as readonly string[]).includes(status)
      )
        rows = rows.filter((row) => row.status === status);
      if (photographerId)
        rows = rows.filter((row) => row.assignedStaffId === photographerId);
      if (eventFilterId !== null)
        rows = rows.filter((row) => row.eventId === eventFilterId);
      if (search) {
        const token = /(?:\/track\/|\/api\/qr\/)?([a-f0-9]{32,80})/i.exec(
          search,
        )?.[1];
        let qrEntityId: number | null = null;
        if (token) {
          const qr = await db.query.qrTokensTable.findFirst({
            where: and(
              eq(qrTokensTable.token, token),
              eq(qrTokensTable.entityType, "photography_order"),
            ),
          });
          qrEntityId = qr?.entityId ?? null;
        }
        const q = search.toLowerCase();
        rows = rows.filter(
          (row) =>
            row.id === qrEntityId ||
            `${row.orderNo} ${row.customerName} ${row.phone} ${row.photoNumber ?? ""}`
              .toLowerCase()
              .includes(q),
        );
      }
      return json(await formatPhotographyOrders(rows));
    }
    const orderId = ref ? int(ref) : null;
    if (!orderId) return error("رقم الطلب غير صحيح", 400);
    const order = await photographyOrderForUser(orderId, auth);
    if (!order) return error("الطلب غير موجود", 404);
    if (method === "GET" && !action) {
      const [formatted, timeline, payments] = await Promise.all([
        formatPhotographyOrder(order, true, req),
        db.query.photographyOrderEventsTable.findMany({
          where: eq(photographyOrderEventsTable.orderId, order.id),
          orderBy: [asc(photographyOrderEventsTable.createdAt)],
        }),
        db.query.photographyPaymentRequestsTable.findMany({
          where: eq(photographyPaymentRequestsTable.orderId, order.id),
          orderBy: [desc(photographyPaymentRequestsTable.createdAt)],
        }),
      ]);
      return json({
        ...formatted,
        timeline: timeline.map((item) => ({
          ...item,
          createdAt: item.createdAt.toISOString(),
        })),
        paymentRequests: payments.map((item) => ({
          ...item,
          amount: Number(item.amount),
          createdAt: item.createdAt.toISOString(),
          reviewedAt: item.reviewedAt?.toISOString() ?? null,
        })),
      });
    }
    if (method === "POST" && action === "status") {
      const parsed = PhotographyStatusSchema.safeParse(await body(req));
      if (!parsed.success)
        return validationError("staff.photography.orders.status", parsed);
      const { status, note } = parsed.data;
      const [updated] = await db
        .update(photographyOrdersTable)
        .set({
          status,
          deliveredAt: status === "delivered" ? new Date() : order.deliveredAt,
          updatedAt: new Date(),
        })
        .where(eq(photographyOrdersTable.id, order.id))
        .returning();
      await addPhotographyOrderEvent({
        orderId: order.id,
        staff: auth,
        type: status === "delivered" ? "delivered" : "status",
        fromStatus: order.status,
        toStatus: status,
        note,
      });
      await syncAutomaticTasksForEntityStatus({
        entityType: "photography_order",
        entityId: order.id,
        status,
        actor: { id: auth.id, name: photographyStaffName(auth) },
      });
      void addEntityTimeline({
        entityType: "photography_order",
        entityId: order.id,
        type: "status_changed",
        title: "تغيرت حالة طلب التصوير",
        body: `${order.status} → ${status}${note ? ` — ${note}` : ""}`,
        actor: { id: auth.id, name: photographyStaffName(auth) },
        metadata: { from: order.status, to: status, note },
      });
      void logAdminActivity(
        req,
        status === "delivered"
          ? "photography_order_delivered"
          : "photography_order_status_updated",
        "photography_order",
        order.id,
        { from: order.status, to: status },
      );
      void createNotification({
        audienceType: "admin",
        staffId: order.assignedStaffId,
        type: `photography_${status}`,
        title:
          status === "ready_print"
            ? "طلب جاهز للطباعة"
            : status === "ready_pickup"
              ? "طلب جاهز للاستلام"
              : status === "delivered"
                ? "تم تسليم طلب التصوير"
                : "تحديث طلب تصوير",
        body: `${order.orderNo} - ${order.customerName}`,
        entityType: "photography_order",
        entityId: order.id,
        href: `/staff/photography/orders/${order.id}`,
      });
      if (status === "ready_pickup" && order.phone)
        void whatsappSend(
          order.phone,
          `صورك للطلب ${order.orderNo} جاهزة للاستلام.`,
          "booking_ready",
        );
      void sendTelegramMessage(
        `📷 <b>تحديث طلب تصوير</b>\nالطلب: ${telegramText(order.orderNo)}\nالزبون: ${telegramText(order.customerName)}\nالحالة: ${telegramText(status)}\nبواسطة: ${telegramText(photographyStaffName(auth))}`,
      );
      return json(await formatPhotographyOrder(updated, true, req));
    }
    if (method === "POST" && action === "collect") {
      const parsed = PhotographyCollectSchema.safeParse(await body(req));
      if (!parsed.success)
        return validationError("staff.photography.orders.collect", parsed);
      try {
        const request = await createPhotographyCollectionRequest(
          order,
          auth,
          parsed.data.amount,
          parsed.data.note,
        );
        void logAdminActivity(
          req,
          "photography_payment_requested",
          "photography_order",
          order.id,
          { amount: parsed.data.amount, requestId: request.id },
        );
        void sendTelegramMessage(
          `💵 <b>طلب اعتماد دفعة تصوير</b>\nالطلب: ${telegramText(order.orderNo)}\nالمصور: ${telegramText(photographyStaffName(auth))}\nالمبلغ: ${formatCurrency(parsed.data.amount)}`,
        );
        return json({ ok: true, requestId: request.id }, 201);
      } catch (err: any) {
        return error(err?.message || "تعذر إرسال طلب التحصيل", 400);
      }
    }
    if (method === "POST" && action === "printed") {
      await addPhotographyOrderEvent({
        orderId: order.id,
        staff: auth,
        type: "receipt_printed",
        fromStatus: order.status,
        toStatus: order.status,
      });
      void logAdminActivity(
        req,
        "photography_receipt_printed",
        "photography_order",
        order.id,
      );
      return json({ ok: true });
    }
    if (method === "PATCH" && !action) {
      if (!manager) return error("تعديل الطلب يخص المدير فقط", 403);
      const parsed = PhotographyOrderUpdateSchema.safeParse(await body(req));
      if (!parsed.success)
        return validationError("staff.photography.orders.update", parsed);
      const data = parsed.data;
      const patch: Partial<typeof photographyOrdersTable.$inferInsert> = {
        updatedAt: new Date(),
      };
      if (data.customerName !== undefined)
        patch.customerName = data.customerName;
      if (data.notes !== undefined) patch.notes = nullableText(data.notes);
      if (data.phone !== undefined) {
        const trimmed = data.phone.trim();
        patch.phone = trimmed
          ? (normalizeIraqiPhone(trimmed) ?? trimmed.replace(/\D/g, ""))
          : "";
      }
      // Money fields can only change while nothing has been collected/approved on this order.
      const wantsMoneyChange =
        data.copies !== undefined || data.unitPrice !== undefined;
      if (wantsMoneyChange) {
        const pending = await photographyPendingAmount(order.id);
        if (Number(order.paidAmount) > 0 || pending > 0)
          return error(
            "لا يمكن تعديل السعر أو عدد النسخ بعد وجود دفعات معتمدة أو قيد الاعتماد",
            409,
          );
        const copies = data.copies ?? order.copies;
        const unitPrice = data.unitPrice ?? Number(order.unitPrice);
        const total = money(unitPrice * copies);
        patch.copies = copies;
        patch.unitPrice = String(money(unitPrice));
        patch.totalAmount = String(total);
        patch.remainingAmount = String(total);
      }
      const [updated] = await db
        .update(photographyOrdersTable)
        .set(patch)
        .where(eq(photographyOrdersTable.id, order.id))
        .returning();
      await addPhotographyOrderEvent({
        orderId: order.id,
        staff: auth,
        type: "edited",
        fromStatus: order.status,
        toStatus: order.status,
        note: `تعديل: ${Object.keys(data).join(", ")}`,
      });
      void addEntityTimeline({
        entityType: "photography_order",
        entityId: order.id,
        type: "updated",
        title: "تم تعديل طلب التصوير",
        body: Object.keys(data).join(", "),
        actor: { id: auth.id, name: photographyStaffName(auth) },
        metadata: {
          fields: Object.keys(data),
          oldValues: order,
          newValues: updated,
        },
      });
      void logAdminActivity(
        req,
        "photography_order_updated",
        "photography_order",
        order.id,
        { fields: Object.keys(data) },
      );
      return json(await formatPhotographyOrder(updated, true, req));
    }
    if (method === "POST" && action === "cancel") {
      if (!manager) return error("إلغاء الطلب يخص المدير فقط", 403);
      if (order.cancelledAt) return error("الطلب ملغى بالفعل", 409);
      const cancelBody = await body(req).catch(() => ({}) as any);

      // Cancellability is decided from the SOURCE OF TRUTH — the linked financial transactions and
      // payment requests, by status — NOT the order.paid_amount snapshot (which lags a reversal and
      // wrongly blocks cancel even after the cash entry shows "reversed"). A transaction blocks only
      // while it is genuinely live money: status pending/approved/executed, AND not reversed, AND not
      // itself a reversal entry. reversed / rejected / cancelled never block (requirements 2, 3, 6).
      const BLOCKING_TXN_STATUS = new Set(["pending", "approved", "executed"]);
      const [linkedTxns, payReqs] = await Promise.all([
        db.query.financialTransactionsTable.findMany({
          where: and(
            eq(financialTransactionsTable.sourceType, "photography_order"),
            eq(financialTransactionsTable.sourceId, String(order.id)),
          ),
        }),
        db.query.photographyPaymentRequestsTable.findMany({
          where: eq(photographyPaymentRequestsTable.orderId, order.id),
        }),
      ]);
      const blockers: Array<{ ref: string; status: string }> = [];
      const seen = new Set<string>();
      for (const txn of linkedTxns) {
        const isReversalEntry = txn.transactionType.endsWith("_reversal");
        const reversed = !!(txn.reversedAt || txn.reversalTxnId);
        if (
          isReversalEntry ||
          reversed ||
          !BLOCKING_TXN_STATUS.has(txn.approvalStatus)
        )
          continue;
        const status =
          txn.approvalStatus === "pending" ? "pending" : "approved";
        if (!seen.has(txn.transactionNo)) {
          seen.add(txn.transactionNo);
          blockers.push({ ref: txn.transactionNo, status });
        }
      }
      // A still-pending approval request blocks too — even if the original transaction was reversed (requirement 7).
      for (const reqRow of payReqs) {
        if (reqRow.status !== "pending") continue;
        const ref =
          linkedTxns.find((t) => t.id === reqRow.financialTransactionId)
            ?.transactionNo ?? `طلب-تحصيل-${reqRow.id}`;
        if (!seen.has(ref)) {
          seen.add(ref);
          blockers.push({ ref, status: "pending" });
        }
      }

      console.info("[photography] cancel check", {
        orderNo: order.orderNo,
        orderId: order.id,
        eventId: order.eventId,
        linkedTransactions: linkedTxns.length,
        transactionStatuses: linkedTxns.map((t) => ({
          no: t.transactionNo,
          approval: t.approvalStatus,
          reversed: !!(t.reversedAt || t.reversalTxnId),
          type: t.transactionType,
        })),
        pendingPaymentRequests: payReqs.filter((r) => r.status === "pending")
          .length,
        blockers,
      });

      if (blockers.length) {
        const b = blockers[0];
        const statusAr =
          b.status === "approved"
            ? "معتمدة (approved)"
            : "قيد الاعتماد (pending)";
        return error(
          `لا يمكن إلغاء الطلب بسبب الحركة المالية: ${b.ref} — الحالة: ${statusAr}. اعكس هذه الحركة من الصندوق الرئيسي ثم أعد المحاولة.`,
          409,
        );
      }

      const [updated] = await db
        .update(photographyOrdersTable)
        .set({
          cancelledAt: new Date(),
          cancelledBy: auth.id,
          updatedAt: new Date(),
        })
        .where(eq(photographyOrdersTable.id, order.id))
        .returning();
      await addPhotographyOrderEvent({
        orderId: order.id,
        staff: auth,
        type: "cancelled",
        fromStatus: order.status,
        toStatus: order.status,
        note: nullableText((cancelBody as any)?.note),
      });
      await syncAutomaticTasksForEntityStatus({
        entityType: "photography_order",
        entityId: order.id,
        status: "cancelled",
        actor: { id: auth.id, name: photographyStaffName(auth) },
      });
      void addEntityTimeline({
        entityType: "photography_order",
        entityId: order.id,
        type: "cancelled",
        title: "تم إلغاء طلب التصوير",
        body: nullableText((cancelBody as any)?.note),
        actor: { id: auth.id, name: photographyStaffName(auth) },
        metadata: { orderNo: order.orderNo },
      });
      void logAdminActivity(
        req,
        "photography_order_cancelled",
        "photography_order",
        order.id,
        { orderNo: order.orderNo },
      );
      void sendTelegramMessage(
        `🚫 <b>إلغاء طلب تصوير</b>\nالطلب: ${telegramText(order.orderNo)}\nالزبون: ${telegramText(order.customerName)}\nبواسطة: ${telegramText(photographyStaffName(auth))}`,
      );
      return json(await formatPhotographyOrder(updated, false));
    }
  }

  if (resource === "prices" && method === "GET") {
    const items = (await getPhotographyPrices())
      .filter((item) => item.active)
      .map((item) => ({ id: item.id, amount: item.amount }));
    return json(items);
  }

  if (resource === "dashboard" && method === "GET") {
    const events = own(
      await db.query.photographyEventsTable.findMany({
        orderBy: [desc(photographyEventsTable.eventDate)],
        limit: 200,
      }),
    ).filter((event) => event.status !== "archived");
    const orders = own(
      await db.query.photographyOrdersTable.findMany({
        orderBy: [desc(photographyOrdersTable.createdAt)],
        limit: 400,
      }),
    ).filter((order) => !order.cancelledAt);
    const today = baghdadToday();
    const todayOrders = orders.filter(
      (order) => order.createdAt.toISOString().slice(0, 10) === today,
    );
    return json({
      today,
      counts: {
        events: events.filter((event) => event.eventDate === today).length,
        orders: todayOrders.length,
        ready: orders.filter((order) => order.status === "ready_pickup").length,
        delivered: todayOrders.filter((order) => order.status === "delivered")
          .length,
      },
      recentEvents: await formatPhotographyEvents(events.slice(0, 5)),
      recentOrders: await formatPhotographyOrders(orders.slice(0, 6)),
    });
  }

  if (resource === "reports" && method === "GET") {
    const params = req.nextUrl.searchParams;
    const scope = manager && params.get("scope") === "all";
    const photographerId = manager
      ? int(params.get("photographerId") || "")
      : null;
    const from = params.get("from") || "";
    const to = params.get("to") || "";
    let orders = (
      scope
        ? await db.query.photographyOrdersTable.findMany({
            orderBy: [desc(photographyOrdersTable.createdAt)],
            limit: 2000,
          })
        : own(
            await db.query.photographyOrdersTable.findMany({
              orderBy: [desc(photographyOrdersTable.createdAt)],
              limit: 2000,
            }),
          )
    ).filter((order) => !order.cancelledAt);
    let events = (
      scope
        ? await db.query.photographyEventsTable.findMany({ limit: 1000 })
        : own(await db.query.photographyEventsTable.findMany({ limit: 1000 }))
    ).filter((event) => event.status !== "archived");
    if (photographerId) {
      orders = orders.filter(
        (order) => order.assignedStaffId === photographerId,
      );
      events = events.filter(
        (event) => event.assignedStaffId === photographerId,
      );
    }
    if (from) {
      orders = orders.filter(
        (order) => order.createdAt.toISOString().slice(0, 10) >= from,
      );
      events = events.filter((event) => event.eventDate >= from);
    }
    if (to) {
      orders = orders.filter(
        (order) => order.createdAt.toISOString().slice(0, 10) <= to,
      );
      events = events.filter((event) => event.eventDate <= to);
    }
    const ranged = from || to;
    const today = baghdadToday();
    const scoped = ranged
      ? orders
      : orders.filter(
          (order) => order.createdAt.toISOString().slice(0, 10) === today,
        );
    const paidOrders = scoped.filter((order) => order.paymentStatus === "paid");
    const unpaidOrders = scoped.filter(
      (order) => order.paymentStatus !== "paid",
    );
    return json({
      events: events.length,
      orders: scoped.length,
      delivered: scoped.filter((order) => order.status === "delivered").length,
      inProgress: scoped.filter((order) => order.status !== "delivered").length,
      paidCount: paidOrders.length,
      unpaidCount: unpaidOrders.length,
      received: scoped.reduce(
        (sum, order) => sum + Number(order.paidAmount),
        0,
      ),
      remaining: scoped.reduce(
        (sum, order) => sum + Number(order.remainingAmount),
        0,
      ),
    });
  }

  if (resource === "notifications") {
    if (method === "GET") {
      const rows = await db.query.notificationsTable.findMany({
        where: and(
          eq(notificationsTable.staffId, auth.id),
          like(notificationsTable.type, "photography_%"),
          sql`${notificationsTable.archivedAt} is null`,
        ),
        orderBy: [desc(notificationsTable.createdAt)],
        limit: 100,
      });
      return json(rows.map(formatNotification));
    }
    if (method === "POST" && ref === "read-all") {
      await db
        .update(notificationsTable)
        .set({ readAt: new Date() })
        .where(
          and(
            eq(notificationsTable.staffId, auth.id),
            like(notificationsTable.type, "photography_%"),
            sql`${notificationsTable.readAt} is null`,
          ),
        );
      return json({ ok: true });
    }
  }

  return error("المسار غير موجود", 404);
}

// ─────────────────────────────────────────────────────────────────────────────
// Kosha Staff Portal API  (/api/staff/koshas/*)
// ─────────────────────────────────────────────────────────────────────────────

function baghdadToday(): string {
  return new Date(Date.now() + 3 * 3600_000).toISOString().slice(0, 10);
}
function parseEventDateIso(value: unknown): string | null {
  const s = String(value ?? "").trim();
  if (!s) return null;
  const iso = s.slice(0, 10);
  if (/^\d{4}-\d{2}-\d{2}$/.test(iso)) return iso;
  const d = new Date(s);
  if (!Number.isNaN(d.getTime()))
    return new Date(d.getTime() + 3 * 3600_000).toISOString().slice(0, 10);
  return null;
}
type CrewBucket = "today" | "tomorrow" | "upcoming" | "late" | "completed";
function crewBucket(row: any, today: string): CrewBucket {
  const stage = row.executionStage ?? row.execution_stage ?? "preparing";
  if (stage === "delivered") return "completed";
  const ev = parseEventDateIso(row.eventDate ?? row.event_date);
  if (!ev) return "upcoming";
  const day = 86400_000;
  const t = new Date(today + "T00:00:00Z").getTime();
  const e = new Date(ev + "T00:00:00Z").getTime();
  if (e === t) return "today";
  if (e === t + day) return "tomorrow";
  if (e > t + day) return "upcoming";
  return "late";
}

async function formatKoshaBookingForCrew(row: any) {
  const base = await formatKoshaBooking(row);
  return {
    ...base,
    executionStage: row.executionStage ?? row.execution_stage ?? "preparing",
    assignedStaffId: row.assignedStaffId ?? row.assigned_staff_id ?? null,
    bucket: crewBucket(row, baghdadToday()),
  };
}

async function addKoshaEvent(input: {
  bookingId: number;
  staff: AdminUser | null;
  type: string;
  fromStage?: string | null;
  toStage?: string | null;
  note?: string | null;
  meta?: Record<string, unknown>;
}) {
  const [row] = await db
    .insert(koshaBookingEventsTable)
    .values({
      bookingId: input.bookingId,
      staffId: input.staff?.id ?? null,
      staffName: input.staff?.fullName || input.staff?.username || "",
      type: input.type,
      fromStage: input.fromStage ?? null,
      toStage: input.toStage ?? null,
      note: input.note ?? null,
      meta: input.meta ?? {},
    })
    .returning();
  return row;
}

async function addKoshaNotification(input: {
  staffId?: number | null;
  audience: "staff" | "manager";
  type: string;
  title: string;
  body?: string | null;
  href?: string | null;
  bookingId?: number | null;
}) {
  try {
    await db.insert(koshaStaffNotificationsTable).values({
      staffId: input.staffId ?? null,
      audience: input.audience,
      type: input.type,
      title: input.title,
      body: input.body ?? null,
      href: input.href ?? null,
      bookingId: input.bookingId ?? null,
    });
  } catch (err) {
    console.warn("kosha notification insert failed", {
      type: input.type,
      error: err instanceof Error ? err.message : "unknown",
    });
  }
}

async function saveKoshaMedia(input: {
  bookingId: number;
  eventId?: number | null;
  staff: AdminUser | null;
  media: Array<{ url?: string; kind?: string }>;
  stage?: string | null;
  purpose: string;
}) {
  const saved: any[] = [];
  for (const m of input.media || []) {
    const cleaned = String(m?.url ?? "").trim();
    if (!cleaned) continue;
    const isVideo = m?.kind === "video" || cleaned.startsWith("data:video");
    const url = cleaned.startsWith("data:")
      ? await persistDataUrlToStorage(
          cleaned,
          `koshas/${input.purpose}/${input.bookingId}`,
        )
      : cleaned;
    const [row] = await db
      .insert(koshaMediaTable)
      .values({
        bookingId: input.bookingId,
        eventId: input.eventId ?? null,
        staffId: input.staff?.id ?? null,
        url,
        kind: isVideo ? "video" : "image",
        stage: input.stage ?? null,
        purpose: input.purpose,
      })
      .returning();
    saved.push(row);
  }
  return saved;
}

// Resolve a booking's selections into full visual items (image + price) for the crew portal.
// Reuses the same catalogs/formatters the admin uses — no new logic invented.
async function koshaBookingSetup(booking: any) {
  const koshaId = booking.koshaId ?? booking.kosha_id ?? null;
  const packageId = booking.packageId ?? booking.package_id ?? null;
  const [koshaRow, addonRows, boardRows, accessoryRows] = await Promise.all([
    koshaId
      ? db.query.koshasTable.findFirst({ where: eq(koshasTable.id, koshaId) })
      : Promise.resolve(null),
    db.query.koshaAddonsTable.findMany(),
    db.query.koshaWelcomeBoardsTable.findMany(),
    db.query.koshaAccessoriesTable.findMany(),
  ]);
  const resolve = (
    names: unknown,
    rows: any[],
    section: "addon" | "welcome_board" | "accessory",
  ) => {
    const catalog = rows.map((row) => formatKoshaOptionProduct(row, section));
    return (Array.isArray(names) ? names : []).map((name: string) => {
      const match = catalog.find((item) => item.name === name);
      return {
        name,
        image: match?.mainImage ?? null,
        price: match?.price ?? null,
        description: match?.description ?? null,
      };
    });
  };
  let pkg: {
    name: string;
    image: string | null;
    price: number;
    contents: string[];
  } | null = null;
  if (packageId) {
    const packageRow = await db.query.koshaPackagesTable.findFirst({
      where: eq(koshaPackagesTable.id, packageId),
    });
    if (packageRow) {
      const formatted = await formatKoshaPackage(packageRow, true);
      pkg = {
        name: formatted.name,
        image: formatted.mainImage ?? null,
        price: formatted.price,
        contents: [
          ...formatted.koshas.map((item: any) => item.name),
          ...formatted.addons.map((item: any) => item.name),
          ...formatted.welcomeBoards.map((item: any) => item.name),
          ...formatted.accessories.map((item: any) => item.name),
        ].filter(Boolean),
      };
    }
  }
  return {
    kosha: koshaRow
      ? {
          name: koshaRow.name,
          image: publicMediaValue("kosha", koshaRow, koshaRow.mainImage),
          price: Number(koshaRow.price ?? 0),
          specs: [
            koshaRow.numberOfPieces ? `${koshaRow.numberOfPieces} قطعة` : null,
            koshaRow.mainColor || null,
            koshaRow.flowerColor ? `ورد ${koshaRow.flowerColor}` : null,
            koshaRow.koshaSpace ? `مساحة ${koshaRow.koshaSpace}` : null,
            koshaRow.sideConsoleSpace
              ? `سايد ${koshaRow.sideConsoleSpace}`
              : null,
          ].filter(Boolean) as string[],
        }
      : null,
    welcomeBoards: resolve(
      booking.welcomeBoards ?? booking.welcome_boards,
      boardRows,
      "welcome_board",
    ),
    addons: resolve(
      booking.selectedAddons ?? booking.selected_addons,
      addonRows,
      "addon",
    ),
    accessories: resolve(
      booking.selectedAccessories ?? booking.selected_accessories,
      accessoryRows,
      "accessory",
    ),
    package: pkg,
  };
}

async function loadKoshaBookingDetail(bookingId: number) {
  const booking = await db.query.koshaBookingsTable.findFirst({
    where: eq(koshaBookingsTable.id, bookingId),
  });
  if (!booking) return null;
  const [events, media, delivery, payments] = await Promise.all([
    db.query.koshaBookingEventsTable.findMany({
      where: eq(koshaBookingEventsTable.bookingId, bookingId),
      orderBy: [asc(koshaBookingEventsTable.createdAt)],
    }),
    db.query.koshaMediaTable.findMany({
      where: eq(koshaMediaTable.bookingId, bookingId),
      orderBy: [desc(koshaMediaTable.createdAt)],
    }),
    db.query.koshaDeliveryReportsTable.findFirst({
      where: eq(koshaDeliveryReportsTable.bookingId, bookingId),
      orderBy: [desc(koshaDeliveryReportsTable.createdAt)],
    }),
    db.query.koshaPaymentRequestsTable.findMany({
      where: eq(koshaPaymentRequestsTable.bookingId, bookingId),
      orderBy: [desc(koshaPaymentRequestsTable.createdAt)],
    }),
  ]);
  return {
    booking: await formatKoshaBookingForCrew(booking),
    setup: await koshaBookingSetup(booking),
    timeline: events.map((e: any) => ({
      ...e,
      createdAt: e.createdAt?.toISOString?.() ?? String(e.createdAt),
    })),
    media: media.map((m: any) => ({
      ...m,
      createdAt: m.createdAt?.toISOString?.() ?? String(m.createdAt),
    })),
    delivery: delivery
      ? {
          ...delivery,
          compensationAmount: Number(delivery.compensationAmount),
          createdAt:
            delivery.createdAt?.toISOString?.() ?? String(delivery.createdAt),
        }
      : null,
    paymentRequests: payments.map((p: any) => ({
      ...p,
      amount: Number(p.amount),
      createdAt: p.createdAt?.toISOString?.() ?? String(p.createdAt),
      reviewedAt: p.reviewedAt?.toISOString?.() ?? null,
    })),
  };
}

async function handleStaffPortal(
  req: NextRequest,
  parts: string[],
): Promise<NextResponse | null> {
  if (parts[1] === "photography")
    return handlePhotographyStaffPortal(req, parts);
  if (parts[1] !== "koshas") return null;
  const method = req.method;
  const resource = parts[2]; // dashboard | bookings | notifications | reports | payment-requests
  const id = parts[3] ? int(parts[3]) : null;
  const action = parts[4];
  await ensureKoshaStaffTables();

  // Manager-only endpoints (approve/reject collections, list pending requests).
  if (resource === "payment-requests") {
    const auth = await requireAnyPermission(req, ["accounting", "bookings"]);
    if (isResponse(auth)) return auth;

    if (method === "GET" && !id) {
      const status = req.nextUrl.searchParams.get("status") || "pending";
      const rows = await db.query.koshaPaymentRequestsTable.findMany({
        where:
          status === "all"
            ? undefined
            : eq(koshaPaymentRequestsTable.status, status),
        orderBy: [desc(koshaPaymentRequestsTable.createdAt)],
        limit: 200,
      });
      const out = await Promise.all(
        rows.map(async (r: any) => {
          const b = await db.query.koshaBookingsTable.findFirst({
            where: eq(koshaBookingsTable.id, r.bookingId),
          });
          return {
            ...r,
            amount: Number(r.amount),
            createdAt: r.createdAt?.toISOString?.() ?? String(r.createdAt),
            reviewedAt: r.reviewedAt?.toISOString?.() ?? null,
            booking: b
              ? {
                  id: b.id,
                  customerName: b.customerName,
                  totalAmount: Number(b.totalAmount),
                  paidAmount: Number(b.paidAmount),
                  remainingAmount: Number(b.remainingAmount),
                }
              : null,
          };
        }),
      );
      return json(out);
    }

    if (
      method === "POST" &&
      id &&
      (action === "approve" || action === "reject")
    ) {
      const reqRow = await db.query.koshaPaymentRequestsTable.findFirst({
        where: eq(koshaPaymentRequestsTable.id, id),
      });
      if (!reqRow) return error("الطلب غير موجود", 404);
      if (reqRow.status !== "pending")
        return error("تمت معالجة هذا الطلب مسبقًا", 409);
      const booking = await db.query.koshaBookingsTable.findFirst({
        where: eq(koshaBookingsTable.id, reqRow.bookingId),
      });
      if (!booking) return error("الحجز غير موجود", 404);

      if (action === "reject") {
        await db
          .update(koshaPaymentRequestsTable)
          .set({
            status: "rejected",
            reviewedByStaffId: auth.id,
            reviewedByName: auth.fullName || auth.username,
            reviewedAt: new Date(),
          })
          .where(eq(koshaPaymentRequestsTable.id, id));
        await addKoshaEvent({
          bookingId: booking.id,
          staff: auth,
          type: "payment_rejected",
          note: reqRow.note,
          meta: { amount: Number(reqRow.amount) },
        });
        await addKoshaNotification({
          staffId: reqRow.staffId,
          audience: "staff",
          type: "payment_rejected",
          title: "رُفض تحصيل المبلغ",
          body: `رفض المدير تحصيل ${formatCurrency(reqRow.amount)}`,
          href: `/staff/koshas/booking/${booking.id}`,
          bookingId: booking.id,
        });
        return json({ ok: true, status: "rejected" });
      }

      // approve → record payment, push to finance.
      const amount = Number(reqRow.amount);
      const newPaid = Number(booking.paidAmount) + amount;
      const newRemaining = Math.max(
        0,
        Number(booking.remainingAmount) - amount,
      );
      const paymentStatus = newRemaining <= 0 ? "paid" : "partial";
      const [updated] = await db
        .update(koshaBookingsTable)
        .set({
          paidAmount: String(newPaid),
          remainingAmount: String(newRemaining),
          paymentStatus,
          updatedAt: new Date(),
        })
        .where(eq(koshaBookingsTable.id, booking.id))
        .returning();
      await db
        .update(koshaPaymentRequestsTable)
        .set({
          status: "approved",
          reviewedByStaffId: auth.id,
          reviewedByName: auth.fullName || auth.username,
          reviewedAt: new Date(),
        })
        .where(eq(koshaPaymentRequestsTable.id, id));
      try {
        await syncKoshaFinancialPayment(updated, financialActor(auth));
      } catch (err) {
        console.error("kosha payment finance sync failed", {
          bookingId: booking.id,
          error: err instanceof Error ? err.message : "unknown",
        });
      }
      await addKoshaEvent({
        bookingId: booking.id,
        staff: auth,
        type: "payment_approved",
        note: reqRow.note,
        meta: { amount },
      });
      await addKoshaNotification({
        staffId: reqRow.staffId,
        audience: "staff",
        type: "payment_approved",
        title: "اعتُمد تحصيل المبلغ",
        body: `وافق المدير على تحصيل ${formatCurrency(amount)} ودخل النظام`,
        href: `/staff/koshas/booking/${booking.id}`,
        bookingId: booking.id,
      });
      return json({
        ok: true,
        status: "approved",
        paidAmount: newPaid,
        remainingAmount: newRemaining,
      });
    }
    return error("المسار غير موجود", 404);
  }

  // Everything below requires the kosha staff permission.
  const auth = await requirePermission(req, "koshas");
  if (isResponse(auth)) return auth;

  // ── Dashboard ──
  if (resource === "dashboard" && method === "GET") {
    const today = baghdadToday();
    const rows = await db.query.koshaBookingsTable.findMany({
      orderBy: [desc(koshaBookingsTable.createdAt)],
      limit: 500,
    });
    const active = rows.filter(
      (r: any) => String(r.status ?? "") !== "cancelled",
    );
    const counts: Record<CrewBucket, number> = {
      today: 0,
      tomorrow: 0,
      upcoming: 0,
      late: 0,
      completed: 0,
    };
    const todayList: any[] = [];
    const tomorrowList: any[] = [];
    for (const r of active) {
      const b = crewBucket(r, today);
      counts[b] += 1;
      if (b === "today") todayList.push(r);
      if (b === "tomorrow") tomorrowList.push(r);
    }
    return json({
      today,
      counts,
      todayBookings: await Promise.all(
        todayList.map(formatKoshaBookingForCrew),
      ),
      tomorrowBookings: await Promise.all(
        tomorrowList.map(formatKoshaBookingForCrew),
      ),
    });
  }

  // ── Bookings list ──
  if (resource === "bookings" && !id && method === "GET") {
    const bucket = req.nextUrl.searchParams.get("bucket") as
      | CrewBucket
      | "all"
      | null;
    const search = (req.nextUrl.searchParams.get("search") || "").trim();
    const today = baghdadToday();
    let rows = await db.query.koshaBookingsTable.findMany({
      orderBy: [desc(koshaBookingsTable.createdAt)],
      limit: 500,
    });
    rows = rows.filter((r: any) => String(r.status ?? "") !== "cancelled");
    if (bucket && bucket !== "all")
      rows = rows.filter((r: any) => crewBucket(r, today) === bucket);
    if (search) {
      const q = search.toLowerCase();
      rows = rows.filter(
        (r: any) =>
          String(r.customerName ?? "")
            .toLowerCase()
            .includes(q) ||
          String(r.phone ?? "").includes(q) ||
          String(r.hallLocation ?? "")
            .toLowerCase()
            .includes(q) ||
          String(r.cityArea ?? "")
            .toLowerCase()
            .includes(q),
      );
    }
    return json(await Promise.all(rows.map(formatKoshaBookingForCrew)));
  }

  // ── Booking detail ──
  if (resource === "bookings" && id && !action && method === "GET") {
    const detail = await loadKoshaBookingDetail(id);
    return detail ? json(detail) : error("الحجز غير موجود", 404);
  }

  // ── Change execution stage ──
  if (
    resource === "bookings" &&
    id &&
    action === "stage" &&
    method === "POST"
  ) {
    const data = await body(req);
    const toStage = String(data?.toStage ?? "").trim();
    if (!(KOSHA_EXECUTION_STAGES as readonly string[]).includes(toStage))
      return error("مرحلة غير صحيحة", 400);
    if (toStage === "delivered")
      return error("استخدم نموذج التسليم لإكمال هذه المرحلة", 400);
    const booking = await db.query.koshaBookingsTable.findFirst({
      where: eq(koshaBookingsTable.id, id),
    });
    if (!booking) return error("الحجز غير موجود", 404);
    const fromStage = (booking as any).executionStage ?? "preparing";
    const media: Array<{ url?: string; kind?: string }> = Array.isArray(
      data?.media,
    )
      ? data.media
      : [];

    if (toStage === "executed" && media.length === 0) {
      return error(
        "يجب رفع صورة واحدة على الأقل أو فيديو قبل حفظ مرحلة (تم التنفيذ)",
        400,
      );
    }
    const event = await addKoshaEvent({
      bookingId: id,
      staff: auth,
      type: "stage",
      fromStage,
      toStage,
      note: data?.note ?? null,
    });
    if (media.length)
      await saveKoshaMedia({
        bookingId: id,
        eventId: event.id,
        staff: auth,
        media,
        stage: toStage,
        purpose: "execution",
      });
    await db
      .update(koshaBookingsTable)
      .set({ executionStage: toStage, updatedAt: new Date() })
      .where(eq(koshaBookingsTable.id, id));
    return json(await loadKoshaBookingDetail(id));
  }

  // ── Standalone media upload ──
  if (
    resource === "bookings" &&
    id &&
    action === "media" &&
    method === "POST"
  ) {
    const data = await body(req);
    const media: Array<{ url?: string; kind?: string }> = Array.isArray(
      data?.media,
    )
      ? data.media
      : [];
    if (media.length === 0) return error("لا توجد ملفات للرفع", 400);
    const booking = await db.query.koshaBookingsTable.findFirst({
      where: eq(koshaBookingsTable.id, id),
    });
    if (!booking) return error("الحجز غير موجود", 404);
    const event = await addKoshaEvent({
      bookingId: id,
      staff: auth,
      type: "media",
      note: data?.note ?? null,
    });
    await saveKoshaMedia({
      bookingId: id,
      eventId: event.id,
      staff: auth,
      media,
      stage: (booking as any).executionStage,
      purpose: String(data?.purpose ?? "execution"),
    });
    return json(await loadKoshaBookingDetail(id));
  }

  // ── Delivery report (تم التسليم) ──
  if (
    resource === "bookings" &&
    id &&
    action === "delivery" &&
    method === "POST"
  ) {
    const data = await body(req);
    const hasLoss = Boolean(data?.hasLoss);
    const hasBreakage = Boolean(data?.hasBreakage);
    const note = String(data?.note ?? "").trim();
    const media: Array<{ url?: string; kind?: string }> = Array.isArray(
      data?.media,
    )
      ? data.media
      : [];
    const compensation = Math.max(
      0,
      Number(data?.compensationAmount ?? 0) || 0,
    );
    // Proof is mandatory on delivery in BOTH cases (loss/breakage = yes or no).
    if (!note || media.length === 0) {
      return error("التسليم يتطلب كتابة ملاحظة ورفع صورة واحدة على الأقل", 400);
    }
    const booking = await db.query.koshaBookingsTable.findFirst({
      where: eq(koshaBookingsTable.id, id),
    });
    if (!booking) return error("الحجز غير موجود", 404);

    const event = await addKoshaEvent({
      bookingId: id,
      staff: auth,
      type: "delivery",
      fromStage: (booking as any).executionStage ?? null,
      toStage: "delivered",
      note: note || null,
      meta: { hasLoss, hasBreakage, compensation },
    });
    if (media.length)
      await saveKoshaMedia({
        bookingId: id,
        eventId: event.id,
        staff: auth,
        media,
        stage: "delivered",
        purpose: hasLoss || hasBreakage ? "breakage" : "delivery",
      });
    let signatureUrl: string | null = null;
    const sig = String(data?.signature ?? "").trim();
    if (sig) {
      const [m] = await saveKoshaMedia({
        bookingId: id,
        eventId: event.id,
        staff: auth,
        media: [{ url: sig, kind: "image" }],
        stage: "delivered",
        purpose: "signature",
      });
      signatureUrl = m?.url ?? null;
    }

    const existing = await db.query.koshaDeliveryReportsTable.findFirst({
      where: eq(koshaDeliveryReportsTable.bookingId, id),
    });
    if (existing) {
      await db
        .update(koshaDeliveryReportsTable)
        .set({
          staffId: auth.id,
          staffName: auth.fullName || auth.username,
          hasLoss,
          hasBreakage,
          note: note || null,
          compensationAmount: String(compensation),
          signatureUrl: signatureUrl ?? existing.signatureUrl,
        })
        .where(eq(koshaDeliveryReportsTable.id, existing.id));
    } else {
      await db.insert(koshaDeliveryReportsTable).values({
        bookingId: id,
        staffId: auth.id,
        staffName: auth.fullName || auth.username,
        hasLoss,
        hasBreakage,
        note: note || null,
        compensationAmount: String(compensation),
        signatureUrl,
      });
    }

    // Breakage/loss compensation is added to the customer's remaining balance.
    const patch: Record<string, unknown> = {
      executionStage: "delivered",
      updatedAt: new Date(),
    };
    if (compensation > 0) {
      const newRemaining = Number(booking.remainingAmount) + compensation;
      const newTotal = Number(booking.totalAmount) + compensation;
      patch.remainingAmount = String(newRemaining);
      patch.totalAmount = String(newTotal);
      patch.paymentStatus =
        newRemaining <= 0
          ? "paid"
          : Number(booking.paidAmount) > 0
            ? "partial"
            : "unpaid";
    }
    await db
      .update(koshaBookingsTable)
      .set(patch)
      .where(eq(koshaBookingsTable.id, id));
    return json(await loadKoshaBookingDetail(id));
  }

  // ── Collect remaining balance → creates a pending request for the manager ──
  if (
    resource === "bookings" &&
    id &&
    action === "collect" &&
    method === "POST"
  ) {
    const data = await body(req);
    const amount = Number(data?.amount ?? 0);
    const note = String(data?.note ?? "").trim();
    const booking = await db.query.koshaBookingsTable.findFirst({
      where: eq(koshaBookingsTable.id, id),
    });
    if (!booking) return error("الحجز غير موجود", 404);
    if (
      booking.paymentStatus === "pending_pricing" ||
      Number(booking.totalAmount) <= 0
    )
      return error("يجب تسعير الحجز من الإدارة قبل تسجيل أي تحصيل", 400);
    const remaining = Number(booking.remainingAmount);
    if (!(amount > 0)) return error("أدخل مبلغًا صحيحًا", 400);
    if (amount > remaining)
      return error("المبلغ أكبر من المتبقي على العميل", 400);
    const pending = await db.query.koshaPaymentRequestsTable.findFirst({
      where: and(
        eq(koshaPaymentRequestsTable.bookingId, id),
        eq(koshaPaymentRequestsTable.status, "pending"),
      ),
    });
    if (pending)
      return error("يوجد طلب تحصيل بانتظار موافقة المدير لهذا الحجز", 409);

    const [reqRow] = await db
      .insert(koshaPaymentRequestsTable)
      .values({
        bookingId: id,
        staffId: auth.id,
        staffName: auth.fullName || auth.username,
        amount: String(amount),
        note: note || null,
        status: "pending",
      })
      .returning();
    await addKoshaEvent({
      bookingId: id,
      staff: auth,
      type: "payment_request",
      note: note || null,
      meta: { amount },
    });
    await addKoshaNotification({
      audience: "manager",
      type: "payment_request",
      title: "طلب تحصيل ميداني",
      body: `${auth.fullName || auth.username} استلم ${formatCurrency(amount)} — ${booking.customerName}`,
      href: "/admin/kosha-collections",
      bookingId: id,
    });
    // Surface the request inside the site admin panel (notifications bell + manager push).
    try {
      await createNotification({
        audienceType: "admin",
        type: "kosha_collection_request",
        title: "طلب تحصيل كوشة",
        body: `${auth.fullName || auth.username} استلم ${formatCurrency(amount)} من ${booking.customerName} — بانتظار اعتمادك`,
        entityType: "kosha_payment_request",
        entityId: reqRow.id,
        href: "/admin/kosha-collections",
      });
    } catch {
      /* notification is best-effort */
    }
    return json(
      { ok: true, request: { ...reqRow, amount: Number(reqRow.amount) } },
      201,
    );
  }

  // ── Notifications ──
  if (resource === "notifications") {
    const isManager =
      hasPermission(auth, "accounting") || hasPermission(auth, "bookings");
    if (method === "GET" && !id) {
      const rows = await db.query.koshaStaffNotificationsTable.findMany({
        where: isManager
          ? sql`(${koshaStaffNotificationsTable.audience} = 'manager' or ${koshaStaffNotificationsTable.staffId} = ${auth.id})`
          : and(
              eq(koshaStaffNotificationsTable.audience, "staff"),
              eq(koshaStaffNotificationsTable.staffId, auth.id),
            ),
        orderBy: [desc(koshaStaffNotificationsTable.createdAt)],
        limit: 50,
      });
      return json(
        rows.map((n: any) => ({
          ...n,
          createdAt: n.createdAt?.toISOString?.() ?? String(n.createdAt),
        })),
      );
    }
    if (method === "POST" && parts[3] === "read-all") {
      await db
        .update(koshaStaffNotificationsTable)
        .set({ isRead: true })
        .where(
          isManager
            ? sql`(${koshaStaffNotificationsTable.audience} = 'manager' or ${koshaStaffNotificationsTable.staffId} = ${auth.id})`
            : and(
                eq(koshaStaffNotificationsTable.audience, "staff"),
                eq(koshaStaffNotificationsTable.staffId, auth.id),
              ),
        );
      return json({ ok: true });
    }
    if (method === "POST" && id && action === "read") {
      await db
        .update(koshaStaffNotificationsTable)
        .set({ isRead: true })
        .where(eq(koshaStaffNotificationsTable.id, id));
      return json({ ok: true });
    }
  }

  // ── Per-staff report ──
  if (
    resource === "reports" &&
    action === undefined &&
    parts[3] === "me" &&
    method === "GET"
  ) {
    const mine = eq(koshaBookingEventsTable.staffId, auth.id);
    const [executed, delivered, deliveryReports, approved] = await Promise.all([
      db.$count(
        koshaBookingEventsTable,
        and(
          mine,
          eq(koshaBookingEventsTable.type, "stage"),
          eq(koshaBookingEventsTable.toStage, "executed"),
        ),
      ),
      db.$count(
        koshaBookingEventsTable,
        and(mine, eq(koshaBookingEventsTable.type, "delivery")),
      ),
      db.query.koshaDeliveryReportsTable.findMany({
        where: eq(koshaDeliveryReportsTable.staffId, auth.id),
      }),
      db.query.koshaPaymentRequestsTable.findMany({
        where: and(
          eq(koshaPaymentRequestsTable.staffId, auth.id),
          eq(koshaPaymentRequestsTable.status, "approved"),
        ),
      }),
    ]);
    const breakage = deliveryReports.filter((r: any) => r.hasBreakage).length;
    const loss = deliveryReports.filter((r: any) => r.hasLoss).length;
    const collected = approved.reduce(
      (s: number, r: any) => s + Number(r.amount),
      0,
    );
    return json({
      executed: Number(executed),
      delivered: Number(delivered),
      breakage,
      loss,
      collected,
      collectedCount: approved.length,
    });
  }

  return error("المسار غير موجود", 404);
}

async function handleTelegram(
  req: NextRequest,
  parts: string[],
  section: string | undefined,
) {
  if (section !== "telegram") return null;
  const auth = await requirePermission(req, "settings");
  if (isResponse(auth)) return auth;
  const method = req.method;
  const resource = parts[2] ?? "settings";

  if (method === "GET" && resource === "settings") {
    return json({
      settings: await getTelegramSettings(),
      environment: telegramEnvironmentStatus(),
    });
  }

  if ((method === "PUT" || method === "PATCH") && resource === "settings") {
    const parsed = telegramSettingsSchema.safeParse(await body(req));
    if (!parsed.success)
      return validationError("admin.telegram.settings", parsed);
    const saved = await saveTelegramSettings(parsed.data);
    void logAdminActivity(
      req,
      "telegram_settings_updated",
      "settings",
      undefined,
      { enabled: saved.enabled, events: saved.events },
    );
    return json({ settings: saved, environment: telegramEnvironmentStatus() });
  }

  if (method === "POST" && resource === "test-message") {
    const result = await sendTelegramMessage(
      "✅ <b>رسالة اختبار من نظام AJN</b>\n\nتم ربط إشعارات Telegram بنجاح.",
    );
    void logAdminActivity(req, "telegram_test_message", "settings", undefined, {
      ok: result.ok,
    });
    return result.ok
      ? json({ message: "تم إرسال رسالة الاختبار" })
      : error(result.error, result.error.includes("Environment") ? 400 : 502);
  }

  if (method === "POST" && resource === "test-pdf") {
    const result = await sendTelegramTestPdf();
    void logAdminActivity(req, "telegram_test_pdf", "settings", undefined, {
      ok: result.ok,
    });
    return result.ok
      ? json({ message: "تم إرسال ملف PDF الاختباري" })
      : error(result.error, result.error.includes("Environment") ? 400 : 502);
  }

  return error("مسار Telegram غير مدعوم", 404);
}

async function handleMasterCash(
  req: NextRequest,
  parts: string[],
  section: string | undefined,
) {
  if (section !== "master-cash") return null;
  const method = req.method;
  const resource = parts[2];
  const id = parts[3] ? int(parts[3]) : null;
  const action = parts[4];
  const currentUser = await getAdminUser(req);
  if (!currentUser) return error("غير مخول", 401);

  // Any authenticated employee can submit a financial request. Ledger access
  // remains restricted to accounting users and managers.
  if (method === "POST" && resource === "transactions" && !id) {
    const parsed = financialTransactionInputSchema.safeParse(await body(req));
    if (!parsed.success)
      return validationError("master-cash.transaction.create", parsed);
    try {
      const row = await createFinancialTransaction(
        parsed.data,
        financialActor(currentUser),
      );
      void logAdminActivity(
        req,
        "financial_transaction_created",
        "financial_transaction",
        row.id,
        {
          transactionNo: row.transactionNo,
          status: row.approvalStatus,
          direction: row.direction,
          amount: row.amount,
        },
      );
      return json(row, 201);
    } catch (err: any) {
      console.error("financial transaction create failed", {
        message: err?.message,
        userId: currentUser.id,
      });
      return error(err?.message || "تعذر إنشاء الطلب المالي", 400);
    }
  }

  const auth = await requirePermission(req, "accounting");
  if (isResponse(auth)) return auth;
  const financeUser = financialActor(auth);

  try {
    await ensureMasterCashBoxTables();

    if (method === "GET" && resource === "dashboard") {
      return json(await getMasterCashDashboard());
    }

    if (method === "GET" && resource === "transactions" && !id) {
      const parsed = financialTransactionListSchema.safeParse(query(req));
      if (!parsed.success)
        return validationError("master-cash.transaction.list", parsed);
      return json(await listFinancialTransactions(parsed.data));
    }

    if (resource === "transactions" && id) {
      if (method === "GET" && !action) {
        const row = await getFinancialTransaction(id);
        return row ? json(row) : error("المعاملة غير موجودة", 404);
      }

      if ((method === "PATCH" || method === "PUT") && !action) {
        const parsed = financialTransactionPatchSchema.safeParse(
          await body(req),
        );
        if (!parsed.success)
          return validationError("master-cash.transaction.update", parsed);
        const row = await updateFinancialTransaction(
          id,
          parsed.data,
          financeUser,
        );
        void logAdminActivity(
          req,
          "financial_transaction_updated",
          "financial_transaction",
          id,
          { reason: parsed.data.reason },
        );
        return json(row);
      }

      if (method === "POST" && action === "submit") {
        const row = await submitFinancialTransaction(id, financeUser);
        void logAdminActivity(
          req,
          "financial_transaction_submitted",
          "financial_transaction",
          id,
        );
        return json(row);
      }

      if (method === "POST" && action === "approve") {
        if (!canApproveFinancialTransactions(financeUser))
          return error("اعتماد المعاملات متاح للمدير فقط", 403);
        const payload = await body(req);
        const row = await approveAndExecuteFinancialTransaction(
          id,
          financeUser,
          nullableText(payload?.note),
        );
        await finalizePhotographyPaymentRequest(
          row,
          true,
          financeUser,
          nullableText(payload?.note),
        );
        void logAdminActivity(
          req,
          "financial_transaction_executed",
          "financial_transaction",
          id,
          {
            transactionNo: row.transactionNo,
            balanceBefore: row.balanceBefore,
            balanceAfter: row.balanceAfter,
          },
        );
        if (row.direction === "revenue") {
          void notifyTelegramPayment({
            event: "managerApproval",
            reference: row.transactionNo,
            customerName: row.customerName || row.description,
            amount: row.amount,
            paymentMethod: row.paymentMethod,
            createdByName: financeUser.name,
            status: row.approvalStatus,
            entityPath: "/admin/finance/master-cash",
          });
        }
        return json(row);
      }

      if (method === "POST" && action === "reject") {
        if (!canApproveFinancialTransactions(financeUser))
          return error("رفض المعاملات متاح للمدير فقط", 403);
        const payload = await body(req);
        const row = await rejectFinancialTransaction(
          id,
          financeUser,
          String(payload?.reason ?? ""),
        );
        await finalizePhotographyPaymentRequest(
          row,
          false,
          financeUser,
          row.rejectionReason,
        );
        void logAdminActivity(
          req,
          "financial_transaction_rejected",
          "financial_transaction",
          id,
          { reason: row.rejectionReason },
        );
        return json(row);
      }

      if (method === "POST" && action === "reverse") {
        if (!canApproveFinancialTransactions(financeUser))
          return error("عكس الحركة المالية متاح للمدير فقط", 403);
        const payload = await body(req);
        try {
          const { original, reverse } = await reverseFinancialTransaction(
            id,
            financeUser,
            String(payload?.reason ?? ""),
          );
          const amountText = formatCurrency(original.amount);
          void logAdminActivity(
            req,
            "financial_transaction_reversed",
            "financial_transaction",
            id,
            {
              originalNo: original.transactionNo,
              reverseNo: reverse.transactionNo,
              amount: original.amount,
              reason: reverse.reversalReason,
            },
          );
          try {
            await createNotification({
              audienceType: "admin",
              type: "financial_transaction_reversed",
              title: "تم عكس حركة مالية",
              body: `عكس ${financeUser.name} الحركة ${original.transactionNo} بمبلغ ${amountText} — السبب: ${reverse.reversalReason ?? ""}`,
              entityType: "financial_transaction",
              entityId: id,
              href: "/admin/finance/master-cash",
            });
          } catch {
            /* notification is best-effort */
          }
          try {
            await sendTelegramMessage(
              `🔁 <b>تم عكس حركة مالية</b>\nالأصل: ${original.transactionNo}\nالعكسية: ${reverse.transactionNo}\nالمبلغ: ${amountText}\nبواسطة: ${financeUser.name}\nالسبب: ${reverse.reversalReason ?? ""}`,
            );
          } catch {
            /* telegram is best-effort */
          }
          return json({ ok: true, original, reverse });
        } catch (err: any) {
          return error(err?.message || "تعذر عكس الحركة المالية", 400);
        }
      }
    }

    if (method === "POST" && resource === "recalculate") {
      if (!canApproveFinancialTransactions(financeUser))
        return error("إعادة احتساب الصندوق متاحة للمدير فقط", 403);
      const row = await recalculateMasterCashBox(financeUser);
      void logAdminActivity(
        req,
        "master_cash_recalculated",
        "master_cash_box",
        row.id,
      );
      return json(row);
    }
  } catch (err: any) {
    console.error("master cash operation failed", {
      method,
      resource,
      id,
      action,
      userId: currentUser.id,
      message: err?.message,
    });
    const safeMessage = String(err?.message ?? "");
    const status = /غير موجود/.test(safeMessage)
      ? 404
      : /صلاحية|متاح للمدير/.test(safeMessage)
        ? 403
        : /رصيد|حالة|تعديل|مرسلة|مطلوب/.test(safeMessage)
          ? 409
          : 500;
    return error(safeMessage || "تعذر إكمال العملية المالية", status);
  }

  return null;
}

const PAYMENT_METHODS_VO = ["cash", "transfer", "pos"] as const;
function normMethod(v: unknown): "cash" | "transfer" | "pos" {
  if (v === "card") return "pos";
  return (PAYMENT_METHODS_VO as readonly string[]).includes(v as string)
    ? (v as any)
    : "cash";
}

function optionalPositiveId(value: unknown): number | null {
  if (value === null || value === undefined || value === "") return null;
  const normalized =
    typeof value === "string" ? normalizePhoneDigits(value) : value;
  const parsed = Number(normalized);
  return Number.isInteger(parsed) && parsed > 0 ? parsed : null;
}

function normalizeFinanceDepartment(value: unknown): string {
  const raw = String(value ?? "").trim();
  if (!raw) return "general";
  const lower = raw.toLowerCase();
  const known: Record<string, string> = {
    general: "general",
    عام: "general",
    store: "store",
    متجر: "store",
    المتجر: "store",
    koshas: "koshas",
    kosha: "koshas",
    كوشات: "koshas",
    الكوشات: "koshas",
    photography: "photography",
    تصوير: "photography",
    التصوير: "photography",
    audio: "audio",
    صوتيات: "audio",
    الصوتيات: "audio",
    gifts: "gifts",
    هدايا: "gifts",
    الهدايا: "gifts",
  };
  if (known[lower]) return known[lower];
  const ascii = lower
    .replace(/[^a-z0-9_-]+/g, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 40);
  return ascii || "general";
}

const voucherDateSchema = z.preprocess(
  (value) => normalizeDateOnly(value) ?? value,
  z.string().regex(/^\d{4}-\d{2}-\d{2}$/, "التاريخ غير صحيح"),
);

const voucherAmountSchema = z.preprocess(
  (value) => parseAmount(value) ?? value,
  z
    .number({ error: "المبلغ مطلوب" })
    .positive("المبلغ يجب أن يكون أكبر من صفر"),
);

const voucherMethodSchema = z
  .enum(["cash", "transfer", "pos", "card"], { error: "طريقة الدفع غير صحيحة" })
  .transform((value) => normMethod(value));

const financeDepartmentSchema = z.preprocess(
  normalizeFinanceDepartment,
  z
    .string()
    .min(1)
    .max(40)
    .regex(/^[a-zA-Z0-9_-]+$/, "رمز القسم غير صحيح"),
);

const receiptVoucherMutationSchema = z.object({
  date: voucherDateSchema,
  amount: voucherAmountSchema,
  payerName: z.string().trim().optional().default(""),
  customerPhone: z.string().trim().optional().default(""),
  customerId: z
    .preprocess(optionalPositiveId, z.number().int().positive().nullable())
    .optional()
    .default(null),
  orderId: z
    .preprocess(optionalPositiveId, z.number().int().positive().nullable())
    .optional()
    .default(null),
  bookingId: z
    .preprocess(optionalPositiveId, z.number().int().positive().nullable())
    .optional()
    .default(null),
  reference: z.string().trim().optional().default(""),
  method: voucherMethodSchema.default("cash"),
  department: financeDepartmentSchema.default("general"),
  notes: z.string().trim().optional().default(""),
});

const paymentVoucherMutationSchema = z.object({
  date: voucherDateSchema,
  amount: voucherAmountSchema,
  payeeName: z.string().trim().optional().default(""),
  customerPhone: z.string().trim().optional().default(""),
  customerId: z
    .preprocess(optionalPositiveId, z.number().int().positive().nullable())
    .optional()
    .default(null),
  reference: z.string().trim().optional().default(""),
  method: voucherMethodSchema.default("cash"),
  department: financeDepartmentSchema.default("general"),
  notes: z.string().trim().optional().default(""),
});

function accountingMutationError(
  err: unknown,
  fallback: string,
): { message: string; status: number } {
  const messages: string[] = [];
  let current: any = err;
  for (let depth = 0; current && depth < 5; depth += 1) {
    if (current.message) messages.push(String(current.message));
    if (current.detail) messages.push(String(current.detail));
    current = current.cause;
  }
  const message = messages.join("\n");
  if (
    /رصيد الصندوق غير كاف|الصندوق الرئيسي غير مهيأ|دليل الحسابات غير مكتمل/.test(
      message,
    )
  ) {
    return { message, status: 409 };
  }
  if (/permission denied|row-level security|RLS|policy/i.test(message)) {
    return {
      message:
        "صلاحيات قاعدة البيانات لا تسمح بإكمال الحفظ. تأكد من Service Role/RLS لجداول الحسابات.",
      status: 403,
    };
  }
  if (/duplicate key|unique constraint|violates unique/i.test(message)) {
    return {
      message: "رقم السند تكرر في قاعدة البيانات. حاول الحفظ مرة أخرى.",
      status: 409,
    };
  }
  if (/foreign key|violates foreign key/i.test(message)) {
    return {
      message: "يوجد مرجع غير صحيح مرتبط بالسند. حدّث الصفحة وحاول مرة أخرى.",
      status: 400,
    };
  }
  if (/relation .* does not exist|column .* does not exist/i.test(message)) {
    return {
      message:
        "قاعدة البيانات تحتاج تحديث جداول الحسابات. شغّل migrations أو اسمح للتطبيق بتجهيز الجداول.",
      status: 500,
    };
  }
  if (/value too long|character varying\(\d+\)/i.test(message)) {
    return {
      message:
        "إحدى القيم أطول من الحد المسموح. اختصر المرجع أو الاسم ثم حاول مرة أخرى.",
      status: 400,
    };
  }
  if (/numeric field overflow|out of range/i.test(message)) {
    return { message: "المبلغ أكبر من الحد المسموح.", status: 400 };
  }
  if (/invalid input syntax|invalid date|\bNaN\b/i.test(message)) {
    return {
      message: "تحقق من المبلغ أو التاريخ ثم حاول مرة أخرى.",
      status: 400,
    };
  }
  return { message: fallback, status: 500 };
}

const expenseMutationSchema = z.object({
  date: z.preprocess(
    (value) => normalizeDateOnly(value) ?? value,
    z.string().regex(/^\d{4}-\d{2}-\d{2}$/, "التاريخ غير صحيح"),
  ),
  name: z.string().optional().default(""),
  categoryId: z.preprocess(
    (value) =>
      typeof value === "string" ? normalizePhoneDigits(value) : value,
    z.coerce.number({ error: "التصنيف مطلوب" }).int().positive("التصنيف مطلوب"),
  ),
  amount: z.preprocess(
    (value) => parseAmount(value) ?? value,
    z
      .number({ error: "المبلغ مطلوب" })
      .positive("المبلغ يجب أن يكون أكبر من صفر"),
  ),
  paymentMethod: z
    .enum(["cash", "transfer", "pos", "card"], { error: "طريقة الدفع مطلوبة" })
    .transform((value) => (value === "card" ? "pos" : value)),
  notes: z.string().nullish(),
  receiptImage: z.string().nullish(),
});

const expenseCategoryMutationSchema = z.object({
  name: z.string().optional(),
  nameAr: z.string().min(1, "اسم التصنيف مطلوب"),
  isActive: z.boolean().optional(),
});

function parseAmount(v: unknown): number | null {
  const normalized =
    typeof v === "string"
      ? v
          .replace(/[٠-٩]/g, (d) => String("٠١٢٣٤٥٦٧٨٩".indexOf(d)))
          .replace(/[۰-۹]/g, (d) => String("۰۱۲۳۴۵۶۷۸۹".indexOf(d)))
          .replace(/[٬,،\s]/g, "")
          .replace(/[٫]/g, ".")
      : v;
  const n =
    typeof normalized === "string"
      ? Number.parseFloat(normalized)
      : Number(normalized);
  return Number.isFinite(n) && n > 0 ? n : null;
}

function normalizeDateOnly(value: unknown): string | null {
  const raw = String(value ?? "").trim();
  if (!raw) return null;
  const normalized = raw
    .replace(/[٠-٩]/g, (d) => String("٠١٢٣٤٥٦٧٨٩".indexOf(d)))
    .replace(/[۰-۹]/g, (d) => String("۰۱۲۳۴۵۶۷۸۹".indexOf(d)));
  const iso = /^(\d{4})-(\d{1,2})-(\d{1,2})$/.exec(normalized);
  const local = /^(\d{1,2})[\/.-](\d{1,2})[\/.-](\d{4})$/.exec(normalized);
  const parts = iso
    ? { year: Number(iso[1]), month: Number(iso[2]), day: Number(iso[3]) }
    : local
      ? {
          year: Number(local[3]),
          month: Number(local[2]),
          day: Number(local[1]),
        }
      : null;
  if (!parts) return null;
  const date = new Date(Date.UTC(parts.year, parts.month - 1, parts.day));
  if (
    date.getUTCFullYear() !== parts.year ||
    date.getUTCMonth() !== parts.month - 1 ||
    date.getUTCDate() !== parts.day
  )
    return null;
  return `${parts.year}-${String(parts.month).padStart(2, "0")}-${String(parts.day).padStart(2, "0")}`;
}

function fmtVoucherNo(prefix: string, id: number, createdAt: Date): string {
  const y = createdAt.getFullYear().toString().slice(-2);
  const m = String(createdAt.getMonth() + 1).padStart(2, "0");
  return `${prefix}-${y}${m}-${String(id).padStart(4, "0")}`;
}

function temporaryVoucherNo(): string {
  // voucher_no is varchar(30); a full UUID with the TMP prefix is 40 characters.
  // Twenty random hex characters keep the temporary value compact and collision-safe.
  return `TMP-${randomUUID().replaceAll("-", "").slice(0, 20)}`;
}

async function handleAccounting(
  req: NextRequest,
  parts: string[],
  section: string | undefined,
) {
  const method = req.method;

  if (section === "expense-categories") {
    const auth = await requirePermission(req, "accounting");
    if (isResponse(auth)) return auth;
    await ensureExpenseManagementTables();
    if (method === "GET") {
      await ensureExpenseCategoriesSeeded();
      const includeAll = req.nextUrl.searchParams.get("all") === "1";
      const rows = await db.query.expenseCategoriesTable.findMany({
        where: includeAll ? undefined : eq(expenseCategoriesTable.isActive, 1),
        orderBy: (c, { asc }) => [asc(c.id)],
      });
      return json(rows);
    }
    if (method === "POST") {
      const parsed = expenseCategoryMutationSchema.safeParse(await body(req));
      if (!parsed.success)
        return validationError("expense-categories.create", parsed);
      const { name, nameAr, isActive } = parsed.data;
      const finalNameAr = textFallback(nameAr, name, "تصنيف مصروف جديد");
      const finalName = textFallback(
        name,
        nameAr,
        slugFallback(nameAr, `expense-${Date.now().toString(36)}`),
      );
      const [row] = await db
        .insert(expenseCategoriesTable)
        .values({
          name: finalName,
          nameAr: finalNameAr,
          isActive: isActive === false ? 0 : 1,
        })
        .returning();
      void logAdminActivity(
        req,
        "expense_category_created",
        "expense_category",
        row.id,
        { name: row.nameAr },
      );
      return json(row, 201);
    }
    if (method === "PATCH" && parts[2]) {
      const id = int(parts[2]);
      if (!id) return error("معرف غير صحيح", 400);
      const parsed = expenseCategoryMutationSchema
        .partial()
        .safeParse(await body(req));
      if (!parsed.success)
        return validationError("expense-categories.update", parsed);
      const b = parsed.data;
      const update: any = { updatedAt: new Date() };
      if (b?.name !== undefined) update.name = b.name;
      if (b?.nameAr !== undefined) update.nameAr = b.nameAr;
      if (b?.isActive !== undefined) update.isActive = b.isActive ? 1 : 0;
      if (update.name !== undefined && !String(update.name ?? "").trim())
        delete update.name;
      if (update.nameAr !== undefined && !String(update.nameAr ?? "").trim())
        delete update.nameAr;
      const [row] = await db
        .update(expenseCategoriesTable)
        .set(update)
        .where(eq(expenseCategoriesTable.id, id))
        .returning();
      if (!row) return error("غير موجود", 404);
      void logAdminActivity(
        req,
        "expense_category_updated",
        "expense_category",
        row.id,
        { fields: Object.keys(update) },
      );
      return json(row);
    }
    if (method === "DELETE" && parts[2]) {
      const id = int(parts[2]);
      if (!id) return error("معرف غير صحيح", 400);
      const used = await db
        .select({ c: sql<number>`count(*)::int` })
        .from(expensesTable)
        .where(eq(expensesTable.categoryId, id));
      if ((used[0]?.c ?? 0) > 0) {
        return error(
          `لا يمكن الحذف — يوجد ${used[0].c} مصروف مرتبط بهذا النوع. عطّله بدل الحذف.`,
          409,
        );
      }
      await db
        .delete(expenseCategoriesTable)
        .where(eq(expenseCategoriesTable.id, id));
      void logAdminActivity(
        req,
        "expense_category_deleted",
        "expense_category",
        id,
      );
      return json({ message: "تم الحذف" });
    }
  }

  if (section === "receipt-vouchers") {
    const auth = await requirePermission(req, "accounting");
    if (isResponse(auth)) return auth;
    try {
      await ensureAccountingVoucherTables();
    } catch (err: any) {
      console.error("accounting vouchers table ensure failed", {
        section,
        message: err?.message,
      });
      return error(
        "تعذر تجهيز جداول الحسابات. تأكد من صلاحيات قاعدة البيانات ثم حاول مرة أخرى.",
        500,
      );
    }
    if (method === "GET") {
      const from = req.nextUrl.searchParams.get("from") ?? undefined;
      const to = req.nextUrl.searchParams.get("to") ?? undefined;
      const search = (req.nextUrl.searchParams.get("search") ?? "").trim();
      const conds = [] as any[];
      if (from) conds.push(gte(receiptVouchersTable.date, from));
      if (to) conds.push(lte(receiptVouchersTable.date, to));
      const rows = await db
        .select()
        .from(receiptVouchersTable)
        .where(conds.length ? (and(...conds) as any) : undefined)
        .orderBy(
          desc(receiptVouchersTable.date),
          desc(receiptVouchersTable.id),
        );
      const customerIds = [
        ...new Set(
          rows.map((row) => row.customerId).filter((id): id is number => !!id),
        ),
      ];
      const customers = customerIds.length
        ? await db.query.customersTable.findMany({
            where: inArray(customersTable.id, customerIds),
          })
        : [];
      const customerMap = new Map(
        customers.map((customer) => [customer.id, customer]),
      );
      const normalizedSearchPhone = normalizeIraqiPhone(search);
      const searchLower = search.toLowerCase();
      return json(
        rows
          .map((row) => ({
            ...row,
            customerPhone: row.customerId
              ? (customerMap.get(row.customerId)?.phone ?? null)
              : null,
          }))
          .filter(
            (row) =>
              !search ||
              [
                row.payerName,
                row.reference,
                row.customerPhone,
                row.customerPhone ? formatIraqiPhone(row.customerPhone) : null,
              ].some((value) =>
                String(value ?? "")
                  .toLowerCase()
                  .includes(searchLower),
              ) ||
              (normalizedSearchPhone &&
                row.customerPhone &&
                normalizeIraqiPhone(row.customerPhone) ===
                  normalizedSearchPhone),
          ),
      );
    }
    if (method === "POST") {
      const parsed = receiptVoucherMutationSchema.safeParse(await body(req));
      if (!parsed.success)
        return validationError("receipt-vouchers.create", parsed);
      const b = parsed.data;
      let customer = b.customerId
        ? await db.query.customersTable.findFirst({
            where: eq(customersTable.id, b.customerId),
          })
        : null;
      if (b.customerId && !customer)
        return error("العميل المختار غير موجود", 400);
      if (!customer && b.customerPhone.trim()) {
        const normalizedPhone = normalizeIraqiPhone(b.customerPhone);
        if (!normalizedPhone) return error("رقم الهاتف العراقي غير صحيح", 400);
        customer = await findCustomerByPhone(normalizedPhone);
      }
      const a = actor(auth);
      try {
        await ensureMasterCashBoxTables();
        const [row] = await db
          .insert(receiptVouchersTable)
          .values({
            voucherNo: temporaryVoucherNo(),
            date: b.date,
            amount: String(b.amount),
            payerName: textFallback(b.payerName, customer?.name, "زبون"),
            customerId: customer?.id ?? null,
            orderId: b.orderId ?? null,
            bookingId: b.bookingId ?? null,
            reference: nullableText(b.reference),
            method: b.method,
            notes: nullableText(b.notes),
            createdBy: a.id,
            createdByName: a.name,
          })
          .returning();
        const [updated] = await db
          .update(receiptVouchersTable)
          .set({ voucherNo: fmtVoucherNo("REC", row.id, row.createdAt) })
          .where(eq(receiptVouchersTable.id, row.id))
          .returning();
        const financialTransaction = await createSourceFinancialRequest(
          {
            transactionDate: updated.date,
            direction: "revenue",
            amount: Number(updated.amount),
            department: b.department,
            transactionType: "receipt_voucher",
            description: `سند قبض من ${updated.payerName}`,
            paymentMethod: b.method,
            sourceType: "receipt_voucher",
            sourceId: updated.id,
            sourceEvent: "payment",
            idempotencyKey: `receipt_voucher:${updated.id}:payment`,
            customerId: updated.customerId,
            customerName: updated.payerName,
            customerPhone: customer?.phone,
            notes: updated.notes,
            attachments: [],
          },
          financialActor(auth),
        );
        const [savedVoucher] = await db
          .update(receiptVouchersTable)
          .set({
            approvalStatus: financialTransaction.approvalStatus,
            financialTransactionId: financialTransaction.id,
          })
          .where(eq(receiptVouchersTable.id, updated.id))
          .returning();
        void logAdminActivity(
          req,
          "receipt_voucher_created",
          "receipt_voucher",
          updated.id,
          { voucherNo: updated.voucherNo },
        );
        void notifyTelegramPayment({
          event: "paymentReceived",
          reference: updated.voucherNo,
          customerName: updated.payerName,
          amount: updated.amount,
          paymentMethod: updated.method,
          createdByName:
            updated.createdByName || auth.fullName || auth.username,
          status: financialTransaction.approvalStatus,
          entityPath: "/admin/accounting",
        });
        return json(savedVoucher, 201);
      } catch (err: any) {
        console.error("receipt voucher save failed", {
          message: err?.message,
          code: err?.code,
          detail: err?.detail,
        });
        const safe = accountingMutationError(
          err,
          "تعذر حفظ سند القبض. تحقق من البيانات أو صلاحيات قاعدة البيانات.",
        );
        return error(safe.message, safe.status);
      }
    }
    if (method === "DELETE" && parts[2]) {
      const id = int(parts[2]);
      if (!id) return error("معرف غير صحيح", 400);
      try {
        const voucher = await db.query.receiptVouchersTable.findFirst({
          where: eq(receiptVouchersTable.id, id),
        });
        if (!voucher) return error("سند القبض غير موجود", 404);
        if (!(auth.role === "admin" || auth.role === "manager")) {
          const approval = await createApprovalRequest({
            type: "cancel_receipt_voucher",
            title: `إلغاء سند قبض ${voucher.voucherNo}`,
            entityType: "receipt_voucher",
            entityId: voucher.id,
            oldValues: voucher as any,
            actor: erpActorFromAdmin(auth),
          });
          return json({ message: "تم إرسال طلب الإلغاء لموافقة المدير", approval: formatApprovalRequest(approval) }, 202);
        }
        if (voucher.financialTransactionId) {
          const transaction = await db.query.financialTransactionsTable.findFirst({ where: eq(financialTransactionsTable.id, voucher.financialTransactionId) });
          if (transaction?.approvalStatus === "executed")
            await reverseFinancialTransaction(voucher.financialTransactionId, financialActor(auth), "إلغاء سند القبض المعتمد");
          else await cancelFinancialTransactionRequest(voucher.financialTransactionId, financialActor(auth), "إلغاء سند القبض");
        }
        await db
          .update(receiptVouchersTable)
          .set({ approvalStatus: "cancelled" })
          .where(eq(receiptVouchersTable.id, id));
        void logAdminActivity(req, "payment_deleted", "receipt_voucher", id, { voucherNo: voucher.voucherNo, device: req.headers.get("user-agent")?.slice(0, 180) ?? "unknown" });
      } catch (err: any) {
        console.error("receipt voucher delete failed", {
          id,
          message: err?.message,
        });
        return error(
          err?.message || "تعذر حذف سند القبض.",
          /منفذة/.test(String(err?.message)) ? 409 : 500,
        );
      }
      return json({ message: "تم إلغاء السند وحفظ أثره للتدقيق" });
    }
  }

  if (section === "payment-vouchers") {
    const auth = await requirePermission(req, "accounting");
    if (isResponse(auth)) return auth;
    try {
      await ensureAccountingVoucherTables();
    } catch (err: any) {
      console.error("accounting vouchers table ensure failed", {
        section,
        message: err?.message,
      });
      return error(
        "تعذر تجهيز جداول الحسابات. تأكد من صلاحيات قاعدة البيانات ثم حاول مرة أخرى.",
        500,
      );
    }
    if (method === "GET") {
      const from = req.nextUrl.searchParams.get("from") ?? undefined;
      const to = req.nextUrl.searchParams.get("to") ?? undefined;
      const search = (req.nextUrl.searchParams.get("search") ?? "").trim();
      const conds = [] as any[];
      if (from) conds.push(gte(paymentVouchersTable.date, from));
      if (to) conds.push(lte(paymentVouchersTable.date, to));
      const rows = await db
        .select()
        .from(paymentVouchersTable)
        .where(conds.length ? (and(...conds) as any) : undefined)
        .orderBy(
          desc(paymentVouchersTable.date),
          desc(paymentVouchersTable.id),
        );
      const customerIds = [
        ...new Set(
          rows.map((row) => row.customerId).filter((id): id is number => !!id),
        ),
      ];
      const customers = customerIds.length
        ? await db.query.customersTable.findMany({
            where: inArray(customersTable.id, customerIds),
          })
        : [];
      const customerMap = new Map(
        customers.map((customer) => [customer.id, customer]),
      );
      const normalizedSearchPhone = normalizeIraqiPhone(search);
      const searchLower = search.toLowerCase();
      return json(
        rows
          .map((row) => ({
            ...row,
            customerPhone: row.customerId
              ? (customerMap.get(row.customerId)?.phone ?? null)
              : null,
          }))
          .filter(
            (row) =>
              !search ||
              [
                row.payeeName,
                row.reference,
                row.customerPhone,
                row.customerPhone ? formatIraqiPhone(row.customerPhone) : null,
              ].some((value) =>
                String(value ?? "")
                  .toLowerCase()
                  .includes(searchLower),
              ) ||
              (normalizedSearchPhone &&
                row.customerPhone &&
                normalizeIraqiPhone(row.customerPhone) ===
                  normalizedSearchPhone),
          ),
      );
    }
    if (method === "POST") {
      const parsed = paymentVoucherMutationSchema.safeParse(await body(req));
      if (!parsed.success)
        return validationError("payment-vouchers.create", parsed);
      const b = parsed.data;
      let customer = b.customerId
        ? await db.query.customersTable.findFirst({
            where: eq(customersTable.id, b.customerId),
          })
        : null;
      if (b.customerId && !customer)
        return error("العميل المختار غير موجود", 400);
      if (!customer && b.customerPhone.trim()) {
        const normalizedPhone = normalizeIraqiPhone(b.customerPhone);
        if (!normalizedPhone) return error("رقم الهاتف العراقي غير صحيح", 400);
        customer = await findCustomerByPhone(normalizedPhone);
      }
      const a = actor(auth);
      try {
        await ensureMasterCashBoxTables();
        const [row] = await db
          .insert(paymentVouchersTable)
          .values({
            voucherNo: temporaryVoucherNo(),
            date: b.date,
            amount: String(b.amount),
            payeeName: textFallback(b.payeeName, customer?.name, "مستلم"),
            customerId: customer?.id ?? null,
            reference: nullableText(b.reference),
            method: b.method,
            notes: nullableText(b.notes),
            createdBy: a.id,
            createdByName: a.name,
          })
          .returning();
        const [updated] = await db
          .update(paymentVouchersTable)
          .set({ voucherNo: fmtVoucherNo("PAY", row.id, row.createdAt) })
          .where(eq(paymentVouchersTable.id, row.id))
          .returning();
        const financialTransaction = await createSourceFinancialRequest(
          {
            transactionDate: updated.date,
            direction: "expense",
            amount: Number(updated.amount),
            department: b.department,
            transactionType: "payment_voucher",
            description: `سند صرف إلى ${updated.payeeName}`,
            paymentMethod: b.method,
            sourceType: "payment_voucher",
            sourceId: updated.id,
            sourceEvent: "payment",
            idempotencyKey: `payment_voucher:${updated.id}:payment`,
            customerId: updated.customerId,
            customerName: updated.payeeName,
            customerPhone: customer?.phone,
            notes: updated.notes,
            attachments: [],
          },
          financialActor(auth),
        );
        const [savedVoucher] = await db
          .update(paymentVouchersTable)
          .set({
            approvalStatus: financialTransaction.approvalStatus,
            financialTransactionId: financialTransaction.id,
          })
          .where(eq(paymentVouchersTable.id, updated.id))
          .returning();
        void logAdminActivity(
          req,
          "payment_voucher_created",
          "payment_voucher",
          updated.id,
          { voucherNo: updated.voucherNo },
        );
        return json(savedVoucher, 201);
      } catch (err: any) {
        console.error("payment voucher save failed", {
          message: err?.message,
          code: err?.code,
          detail: err?.detail,
        });
        const safe = accountingMutationError(
          err,
          "تعذر حفظ سند الصرف. تحقق من البيانات أو صلاحيات قاعدة البيانات.",
        );
        return error(safe.message, safe.status);
      }
    }
    if (method === "DELETE" && parts[2]) {
      const id = int(parts[2]);
      if (!id) return error("معرف غير صحيح", 400);
      try {
        const voucher = await db.query.paymentVouchersTable.findFirst({
          where: eq(paymentVouchersTable.id, id),
        });
        if (!voucher) return error("سند الصرف غير موجود", 404);
        if (!(auth.role === "admin" || auth.role === "manager")) {
          const approval = await createApprovalRequest({
            type: "cancel_payment_voucher",
            title: `إلغاء سند صرف ${voucher.voucherNo}`,
            entityType: "payment_voucher",
            entityId: voucher.id,
            oldValues: voucher as any,
            actor: erpActorFromAdmin(auth),
          });
          return json({ message: "تم إرسال طلب الإلغاء لموافقة المدير", approval: formatApprovalRequest(approval) }, 202);
        }
        if (voucher.financialTransactionId) {
          const transaction = await db.query.financialTransactionsTable.findFirst({ where: eq(financialTransactionsTable.id, voucher.financialTransactionId) });
          if (transaction?.approvalStatus === "executed")
            await reverseFinancialTransaction(voucher.financialTransactionId, financialActor(auth), "إلغاء سند الصرف المعتمد");
          else await cancelFinancialTransactionRequest(voucher.financialTransactionId, financialActor(auth), "إلغاء سند الصرف");
        }
        await db
          .update(paymentVouchersTable)
          .set({ approvalStatus: "cancelled" })
          .where(eq(paymentVouchersTable.id, id));
        void logAdminActivity(req, "refund_deleted", "payment_voucher", id, { voucherNo: voucher.voucherNo, device: req.headers.get("user-agent")?.slice(0, 180) ?? "unknown" });
      } catch (err: any) {
        console.error("payment voucher delete failed", {
          id,
          message: err?.message,
        });
        return error(
          err?.message || "تعذر حذف سند الصرف.",
          /منفذة/.test(String(err?.message)) ? 409 : 500,
        );
      }
      return json({ message: "تم إلغاء السند وحفظ أثره للتدقيق" });
    }
  }

  if (section === "expenses") {
    const auth = await requirePermission(req, "accounting");
    if (isResponse(auth)) return auth;
    await ensureExpenseManagementTables();
    if (method === "GET") {
      const from = req.nextUrl.searchParams.get("from") ?? undefined;
      const to = req.nextUrl.searchParams.get("to") ?? undefined;
      const categoryId = numberId(req.nextUrl.searchParams.get("categoryId"));
      const paymentMethod = (
        req.nextUrl.searchParams.get("paymentMethod") ?? ""
      ).trim();
      const search = (req.nextUrl.searchParams.get("search") ?? "").trim();
      const user = (req.nextUrl.searchParams.get("user") ?? "").trim();
      const searchLike = `%${search}%`;
      const userLike = `%${user}%`;
      const conds = [] as any[];
      conds.push(sql`${expensesTable.deletedAt} is null`);
      if (from) conds.push(gte(expensesTable.date, from));
      if (to) conds.push(lte(expensesTable.date, to));
      if (categoryId) conds.push(eq(expensesTable.categoryId, categoryId));
      if (paymentMethod)
        conds.push(eq(expensesTable.paymentMethod, normMethod(paymentMethod)));
      if (search)
        conds.push(
          or(
            ilike(expensesTable.name, searchLike),
            ilike(expensesTable.categoryName, searchLike),
            ilike(expensesTable.notes, searchLike),
          ),
        );
      if (user) conds.push(ilike(expensesTable.createdByName, userLike));
      const rows = await db
        .select()
        .from(expensesTable)
        .where(conds.length ? (and(...conds) as any) : undefined)
        .orderBy(desc(expensesTable.date), desc(expensesTable.id));
      return json(rows);
    }
    if (method === "POST") {
      const parsed = expenseMutationSchema.safeParse(await body(req));
      if (!parsed.success) return validationError("expenses.create", parsed);
      const b = parsed.data;
      let categoryName = "";
      if (b?.categoryId) {
        const cat = await db.query.expenseCategoriesTable.findFirst({
          where: eq(expenseCategoriesTable.id, b.categoryId),
        });
        categoryName = cat?.nameAr ?? "";
      }
      const a = actor(auth);
      const receiptImage = b?.receiptImage
        ? await persistMediaValue(b.receiptImage, "expenses")
        : null;
      const [row] = await db
        .insert(expensesTable)
        .values({
          date: b?.date || new Date().toISOString().slice(0, 10),
          name: textFallback(b?.name, categoryName || "مصروف"),
          amount: String(b.amount),
          categoryId: b?.categoryId ?? null,
          categoryName,
          paymentMethod: normMethod(b?.paymentMethod),
          receiptImage,
          notes: b?.notes ?? null,
          createdBy: a.id,
          createdByName: a.name,
          approvalStatus: "pending",
        })
        .returning();
      let financialTransaction;
      try {
        financialTransaction = await createSourceFinancialRequest(
          {
            transactionDate: row.date,
            direction: "expense",
            amount: Number(row.amount),
            department: "general",
            transactionType: "expense",
            description: row.name || row.categoryName || "مصروف",
            paymentMethod: normMethod(row.paymentMethod),
            sourceType: "expense",
            sourceId: row.id,
            sourceEvent: "payment",
            idempotencyKey: `expense:${row.id}:payment`,
            notes: row.notes,
            attachments: row.receiptImage ? [row.receiptImage] : [],
          },
          financialActor(auth),
        );
      } catch (err: any) {
        await db
          .update(expensesTable)
          .set({ deletedAt: new Date() })
          .where(eq(expensesTable.id, row.id));
        console.error("expense financial request failed", {
          expenseId: row.id,
          message: err?.message,
        });
        return error(
          "تعذر إنشاء الطلب المالي للمصروف، لم يتم حفظ المصروف",
          500,
        );
      }
      const [savedRow] = await db
        .update(expensesTable)
        .set({
          financialTransactionId: financialTransaction.id,
          approvalStatus: financialTransaction.approvalStatus,
        })
        .where(eq(expensesTable.id, row.id))
        .returning();
      void logAdminActivity(req, "expense_created", "expense", row.id);
      return json(savedRow, 201);
    }
    if ((method === "PATCH" || method === "PUT") && parts[2]) {
      const id = int(parts[2]);
      if (!id) return error("معرف غير صحيح", 400);
      const parsed = expenseMutationSchema.partial().safeParse(await body(req));
      if (!parsed.success) return validationError("expenses.update", parsed);
      const b = parsed.data;
      const existingExpense = await db.query.expensesTable.findFirst({
        where: and(
          eq(expensesTable.id, id),
          sql`${expensesTable.deletedAt} is null`,
        ),
      });
      if (!existingExpense) return error("المصروف غير موجود", 404);
      const update: any = { updatedAt: new Date() };
      if (b.date !== undefined) update.date = b.date;
      if (b.amount !== undefined) update.amount = String(b.amount);
      if (b.categoryId !== undefined) {
        const cat = await db.query.expenseCategoriesTable.findFirst({
          where: eq(expenseCategoriesTable.id, b.categoryId),
        });
        if (!cat) return error("تصنيف المصروف غير موجود", 400);
        update.categoryId = b.categoryId;
        update.categoryName = cat.nameAr;
      }
      if (b.name !== undefined)
        update.name = textFallback(b.name, update.categoryName, "مصروف");
      if (b.paymentMethod !== undefined)
        update.paymentMethod = normMethod(b.paymentMethod);
      if (b.notes !== undefined) update.notes = nullableText(b.notes);
      if (b.receiptImage !== undefined)
        update.receiptImage = b.receiptImage
          ? await persistMediaValue(b.receiptImage, "expenses")
          : null;
      const a = actor(auth);
      update.updatedBy = a.id;
      update.updatedByName = a.name;
      if (existingExpense.financialTransactionId) {
        try {
          await syncSourceFinancialRequest(
            existingExpense.financialTransactionId,
            {
              transactionDate: update.date ?? existingExpense.date,
              direction: "expense",
              amount: Number(update.amount ?? existingExpense.amount),
              department: "general",
              transactionType: "expense",
              description:
                update.name ??
                existingExpense.name ??
                existingExpense.categoryName ??
                "مصروف",
              paymentMethod:
                update.paymentMethod ?? existingExpense.paymentMethod,
              sourceType: "expense",
              sourceId: existingExpense.id,
              sourceEvent: "payment",
              idempotencyKey: `expense:${existingExpense.id}:payment`,
              notes: update.notes ?? existingExpense.notes,
              attachments: [
                update.receiptImage ?? existingExpense.receiptImage,
              ].filter(Boolean),
            },
            financialActor(auth),
            "تعديل المصروف المرتبط",
          );
          update.approvalStatus = "pending";
        } catch (err: any) {
          return error(
            err?.message || "تعذر تحديث المعاملة المالية المرتبطة",
            409,
          );
        }
      }
      const [row] = await db
        .update(expensesTable)
        .set(update)
        .where(
          and(
            eq(expensesTable.id, id),
            sql`${expensesTable.deletedAt} is null`,
          ) as any,
        )
        .returning();
      if (!row) return error("المصروف غير موجود", 404);
      void logAdminActivity(req, "expense_updated", "expense", row.id, {
        fields: Object.keys(update),
      });
      return json(row);
    }
    if (method === "DELETE" && parts[2]) {
      const id = int(parts[2]);
      if (!id) return error("معرف غير صحيح", 400);
      const existingExpense = await db.query.expensesTable.findFirst({
        where: and(
          eq(expensesTable.id, id),
          sql`${expensesTable.deletedAt} is null`,
        ),
      });
      if (!existingExpense) return error("المصروف غير موجود", 404);
      const a = actor(auth);
      if (existingExpense.financialTransactionId) {
        try {
          await cancelFinancialTransactionRequest(
            existingExpense.financialTransactionId,
            financialActor(auth),
            "إلغاء المصروف من الإدارة",
          );
        } catch (err: any) {
          return error(
            err?.message || "لا يمكن حذف المصروف بعد تنفيذه مالياً",
            409,
          );
        }
      }
      const [row] = await db
        .update(expensesTable)
        .set({
          deletedAt: new Date(),
          updatedAt: new Date(),
          updatedBy: a.id,
          updatedByName: a.name,
        })
        .where(
          and(
            eq(expensesTable.id, id),
            sql`${expensesTable.deletedAt} is null`,
          ) as any,
        )
        .returning();
      if (!row) return error("المصروف غير موجود", 404);
      void logAdminActivity(req, "expense_deleted", "expense", id, {
        name: row.name,
        amount: row.amount,
      });
      return json({ message: "تم الحذف" });
    }
  }

  if (section === "accounting") {
    const auth = await requirePermission(req, "accounting");
    if (isResponse(auth)) return auth;
    try {
      await ensureAccountingVoucherTables();
    } catch (err: any) {
      console.error("accounting tables ensure failed", {
        section,
        message: err?.message,
      });
      return error(
        "تعذر تجهيز جداول الحسابات. تأكد من صلاحيات قاعدة البيانات ثم حاول مرة أخرى.",
        500,
      );
    }
    if (method === "GET" && parts[2] === "receivables") {
      const type = (req.nextUrl.searchParams.get("type") ?? "outstanding").trim();
      const from = req.nextUrl.searchParams.get("from") ?? new Date(Date.now() - 30 * 86400_000).toISOString().slice(0, 10);
      const to = req.nextUrl.searchParams.get("to") ?? new Date().toISOString().slice(0, 10);
      if (type === "daily-payments" || type === "monthly-payments") {
        const period = type === "daily-payments" ? "YYYY-MM-DD" : "YYYY-MM";
        const rows = await db.execute(sql`
          SELECT to_char(transaction_date, ${period}) AS period,
            count(*)::int AS payment_count,
            coalesce(sum(amount::numeric), 0)::float AS total_paid
          FROM financial_transactions
          WHERE direction = 'revenue' AND approval_status = 'executed'
            AND transaction_date BETWEEN ${from} AND ${to}
          GROUP BY to_char(transaction_date, ${period})
          ORDER BY period DESC
        `);
        return json({ type, from, to, rows: rows.rows ?? [] });
      }
      if (type === "receipts") {
        const rows = await db.execute(sql`
          SELECT rv.id, rv.voucher_no, rv.date::text AS date, rv.payer_name,
            coalesce(c.phone, '') AS phone, rv.amount::float AS amount,
            rv.method, rv.reference, rv.approval_status
          FROM receipt_vouchers rv
          LEFT JOIN customers c ON c.id = rv.customer_id
          WHERE rv.date BETWEEN ${from} AND ${to}
          ORDER BY rv.date DESC, rv.id DESC
          LIMIT 2000
        `);
        return json({ type, from, to, rows: rows.rows ?? [] });
      }
      const receivablesHaving =
        type === "paid"
          ? sql`coalesce(sum(remaining), 0) <= 0 AND coalesce(sum(total), 0) > 0`
          : type === "outstanding"
            ? sql`coalesce(sum(remaining), 0) > 0`
            : type === "overdue"
              ? sql`coalesce(sum(remaining), 0) > 0 AND min(due_date) < current_date`
              : sql`true`;
      const rows = await db.execute(sql`
        WITH ledger AS (
          SELECT customer_id, customer_name, customer_phone AS phone, tracking_code AS reference,
            'طلب متجر'::text AS source, created_at::date AS date, due_date,
            total::numeric AS total, deposit_amount::numeric AS paid, remaining_amount::numeric AS remaining
          FROM orders WHERE archived_at IS NULL AND status <> 'cancelled'
          UNION ALL
          SELECT NULL, customer_name, phone, coalesce(tracking_code, 'SRV-' || id),
            'حجز خدمة', created_at::date, due_date,
            total_amount::numeric, deposit_amount::numeric, remaining_amount::numeric
          FROM service_orders WHERE archived_at IS NULL AND status <> 'cancelled'
          UNION ALL
          SELECT NULL, customer_name, phone, coalesce(tracking_code, 'KB-' || id),
            'حجز كوشة', created_at::date, due_date,
            total_amount::numeric, paid_amount::numeric, remaining_amount::numeric
          FROM kosha_bookings WHERE archived_at IS NULL AND status <> 'cancelled'
          UNION ALL
          SELECT customer_id, customer_name, customer_phone, invoice_no,
            'فاتورة مبيعات', date, due_date,
            total::numeric, paid_amount::numeric, remaining_amount::numeric
          FROM sales_invoices WHERE status = 'active' AND financially_reversed = false
        ), filtered AS (
          SELECT *, regexp_replace(coalesce(phone, ''), '[^0-9]', '', 'g') AS phone_key
          FROM ledger
          WHERE date BETWEEN ${from} AND ${to}
        )
        SELECT max(customer_id) AS customer_id, max(customer_name) AS customer_name, max(phone) AS phone,
          count(*)::int AS invoice_count,
          coalesce(sum(total), 0)::float AS total,
          coalesce(sum(paid), 0)::float AS paid,
          coalesce(sum(remaining), 0)::float AS remaining,
          count(*) FILTER (WHERE remaining > 0)::int AS open_invoices,
          max(date)::text AS last_invoice_date,
          min(due_date)::text AS oldest_due_date
        FROM filtered
        GROUP BY coalesce(nullif(phone_key, ''), 'customer:' || coalesce(customer_id::text, customer_name))
        HAVING ${receivablesHaving}
        ORDER BY remaining DESC, customer_name
        LIMIT 2000
      `);
      return json({ type, from, to, rows: rows.rows ?? [] });
    }
    if (method === "GET" && parts[2] === "statement") {
      const customerId = req.nextUrl.searchParams.get("customerId")
        ? Number.parseInt(req.nextUrl.searchParams.get("customerId")!, 10)
        : null;
      const rawPhoneParam = req.nextUrl.searchParams.get("phone")?.trim();
      const phoneParam = rawPhoneParam
        ? normalizeIraqiPhone(rawPhoneParam)
        : null;
      if (rawPhoneParam && !phoneParam)
        return error("رقم الهاتف العراقي غير صحيح", 400);
      let customer = null as any;
      if (customerId)
        customer = await db.query.customersTable.findFirst({
          where: eq(customersTable.id, customerId),
        });
      if (!customer && phoneParam)
        customer = await findCustomerByPhone(phoneParam);
      const phone = customer?.phone ?? phoneParam ?? null;
      if (!phone) return error("اختر زبون أو رقم هاتف", 400);
      const phoneVariants = iraqiPhoneVariants(phone);
      const [orders, bookings, receipts, salesInvoices] = await Promise.all([
        db
          .select({
            id: ordersTable.id,
            trackingCode: ordersTable.trackingCode,
            total: ordersTable.total,
            depositAmount: ordersTable.depositAmount,
            createdAt: ordersTable.createdAt,
          })
          .from(ordersTable)
          .where(inArray(ordersTable.customerPhone, phoneVariants))
          .orderBy(desc(ordersTable.createdAt)),
        db
          .select({
            id: serviceOrdersTable.id,
            trackingCode: serviceOrdersTable.trackingCode,
            totalAmount: serviceOrdersTable.totalAmount,
            depositAmount: serviceOrdersTable.depositAmount,
            createdAt: serviceOrdersTable.createdAt,
          })
          .from(serviceOrdersTable)
          .where(inArray(serviceOrdersTable.phone, phoneVariants))
          .orderBy(desc(serviceOrdersTable.createdAt)),
        customer
          ? db
              .select({
                voucherNo: receiptVouchersTable.voucherNo,
                date: receiptVouchersTable.date,
                amount: receiptVouchersTable.amount,
                payerName: receiptVouchersTable.payerName,
                orderId: receiptVouchersTable.orderId,
                bookingId: receiptVouchersTable.bookingId,
                reference: receiptVouchersTable.reference,
                method: receiptVouchersTable.method,
              })
              .from(receiptVouchersTable)
              .where(eq(receiptVouchersTable.customerId, customer.id))
              .orderBy(desc(receiptVouchersTable.date))
          : Promise.resolve([] as any[]),
        db
          .select({
            id: salesInvoicesTable.id,
            invoiceNo: salesInvoicesTable.invoiceNo,
            date: salesInvoicesTable.date,
            customerName: salesInvoicesTable.customerName,
            total: salesInvoicesTable.total,
            paidAmount: salesInvoicesTable.paidAmount,
            createdAt: salesInvoicesTable.createdAt,
          })
          .from(salesInvoicesTable)
          .where(
            and(
              sql`${salesInvoicesTable.status} != 'deleted'`,
              customer
                ? or(
                    inArray(salesInvoicesTable.customerPhone, phoneVariants),
                    eq(salesInvoicesTable.customerId, customer.id),
                  )
                : inArray(salesInvoicesTable.customerPhone, phoneVariants),
            ),
          )
          .orderBy(desc(salesInvoicesTable.createdAt)),
      ]);
      type Entry = {
        date: string;
        kind: "order" | "booking" | "receipt" | "invoice" | "invoice_payment";
        ref: string;
        description: string;
        debit: number;
        credit: number;
        href: string | null;
      };
      const entries: Entry[] = [];
      for (const o of orders) {
        entries.push({
          date: o.createdAt.toISOString(),
          kind: "order",
          ref: o.trackingCode,
          description: "طلب من المتجر",
          debit: Number.parseFloat(o.total),
          credit: Number.parseFloat(o.depositAmount ?? "0"),
          href: `/admin/invoice/${o.id}`,
        });
      }
      for (const b of bookings) {
        entries.push({
          date: b.createdAt.toISOString(),
          kind: "booking",
          ref: b.trackingCode ?? `#${b.id}`,
          description: "حجز خدمة",
          debit: Number.parseFloat(b.totalAmount ?? "0"),
          credit: Number.parseFloat(b.depositAmount ?? "0"),
          href: `/admin/invoice/${b.id}?type=booking`,
        });
      }
      // Sales invoices — the charge (debit) and any amount paid against it (credit).
      for (const si of salesInvoices) {
        const when = si.createdAt
          ? si.createdAt.toISOString()
          : new Date(`${si.date}T00:00:00`).toISOString();
        const nameSuffix = si.customerName ? ` — ${si.customerName}` : "";
        entries.push({
          date: when,
          kind: "invoice",
          ref: si.invoiceNo,
          description: `فاتورة مبيعات${nameSuffix}`,
          debit: Number.parseFloat(si.total),
          credit: 0,
          href: `/admin/sales?invoice=${si.id}`,
        });
        const paid = Number.parseFloat(si.paidAmount);
        if (paid > 0)
          entries.push({
            date: when,
            kind: "invoice_payment",
            ref: si.invoiceNo,
            description: `دفعة فاتورة ${si.invoiceNo}`,
            debit: 0,
            credit: paid,
            href: `/admin/sales?invoice=${si.id}`,
          });
      }
      for (const r of receipts) {
        if (r.orderId || r.bookingId) continue;
        if (salesInvoices.some((invoice) => String(r.reference ?? "").startsWith(invoice.invoiceNo))) continue;
        entries.push({
          date: new Date(r.date).toISOString(),
          kind: "receipt",
          ref: r.voucherNo,
          description: `سند قبض (${r.method}) — ${r.payerName ?? ""}`,
          debit: 0,
          credit: Number.parseFloat(r.amount),
          href: null,
        });
      }
      entries.sort((a, b) => a.date.localeCompare(b.date));
      let running = 0;
      const withBalance = entries.map((e) => {
        running += e.debit - e.credit;
        return { ...e, balance: running };
      });
      return json({
        customer: customer
          ? { id: customer.id, name: customer.name, phone: customer.phone }
          : { id: null, name: phone, phone },
        entries: withBalance,
        totals: {
          totalCharges: entries.reduce((s, e) => s + e.debit, 0),
          totalPayments: entries.reduce((s, e) => s + e.credit, 0),
          balance: running,
        },
      });
    }

    if (method === "GET" && parts[2] === "pnl") {
      const from =
        req.nextUrl.searchParams.get("from") ||
        new Date(Date.now() - 30 * 86400_000).toISOString().slice(0, 10);
      const to =
        req.nextUrl.searchParams.get("to") ||
        new Date().toISOString().slice(0, 10);
      const fromDate = new Date(`${from}T00:00:00.000Z`);
      const toDate = new Date(`${to}T23:59:59.999Z`);
      const [sales, receipts, payments, expensesByCat] = await Promise.all([
        db
          .select({
            s: sql<number>`coalesce(sum((total::numeric - delivery_fee::numeric)),0)::float`,
          })
          .from(ordersTable)
          .where(
            and(
              gte(ordersTable.createdAt, fromDate),
              lte(ordersTable.createdAt, toDate),
              sql`status <> 'cancelled'`,
            ),
          ),
        db
          .select({ s: sql<number>`coalesce(sum(amount::numeric),0)::float` })
          .from(receiptVouchersTable)
          .where(
            and(
              gte(receiptVouchersTable.date, from),
              lte(receiptVouchersTable.date, to),
              sql`coalesce(${receiptVouchersTable.approvalStatus}, 'executed') = 'executed'`,
            ),
          ),
        db
          .select({ s: sql<number>`coalesce(sum(amount::numeric),0)::float` })
          .from(paymentVouchersTable)
          .where(
            and(
              gte(paymentVouchersTable.date, from),
              lte(paymentVouchersTable.date, to),
              sql`coalesce(${paymentVouchersTable.approvalStatus}, 'executed') = 'executed'`,
            ),
          ),
        db
          .select({
            categoryId: expensesTable.categoryId,
            categoryName: sql<string>`max(${expensesTable.categoryName})`,
            total: sql<number>`coalesce(sum(amount::numeric),0)::float`,
          })
          .from(expensesTable)
          .where(
            and(
              gte(expensesTable.date, from),
              lte(expensesTable.date, to),
              sql`${expensesTable.deletedAt} is null`,
              sql`coalesce(${expensesTable.approvalStatus}, 'executed') = 'executed'`,
            ),
          )
          .groupBy(expensesTable.categoryId)
          .orderBy(sql`coalesce(sum(amount::numeric),0) desc`),
      ]);
      const totalSales = sales[0].s;
      const totalReceipts = receipts[0].s;
      const totalPayments = payments[0].s;
      const totalExpenses = expensesByCat.reduce((s, r) => s + r.total, 0);
      return json({
        from,
        to,
        totalSales,
        totalReceipts,
        totalPayments,
        totalExpenses,
        netProfit: totalReceipts - totalPayments - totalExpenses,
        expensesByCategory: expensesByCat.map((r) => ({
          categoryId: r.categoryId,
          categoryName: r.categoryName || "غير مصنف",
          total: r.total,
        })),
      });
    }
  }

  return null;
}

