type BackupPayload = {
  meta: {
    app: string;
    version: number;
    exportedAt: string;
    mediaCount: number;
    mediaArchivedCount?: number;
    mediaSkippedCount?: number;
  };
  data: Record<string, any[]>;
  mediaManifest: string[];
  mediaFiles?: Array<{
    url: string;
    path: string | null;
    contentType: string;
    base64: string;
    size: number;
  }>;
  mediaSkipped?: Array<{ url: string; reason: string }>;
};

function collectBackupMedia(rows: any[]) {
  const urls = new Set<string>();
  const visit = (value: unknown) => {
    if (!value) return;
    if (typeof value === "string") {
      if (/^https?:\/\//i.test(value) || value.startsWith("/api/media/"))
        urls.add(value);
      return;
    }
    if (Array.isArray(value)) {
      for (const item of value) visit(item);
      return;
    }
    if (typeof value === "object") {
      for (const item of Object.values(value as Record<string, unknown>))
        visit(item);
    }
  };
  for (const row of rows) visit(row);
  return Array.from(urls);
}

async function buildBackupPayload(): Promise<BackupPayload> {
  const data: Record<string, any[]> = {};
  const media = new Set<string>();
  for (const [name, table] of Object.entries(BACKUP_ENTITIES) as [
    string,
    any,
  ][]) {
    try {
      const rows = await db.select().from(table);
      data[name] = rows;
      for (const url of collectBackupMedia(rows)) media.add(url);
    } catch (err: any) {
      console.warn("backup entity export failed", {
        name,
        message: err?.message,
      });
      data[name] = [];
    }
  }
  const mediaArchive = await buildBackupMediaArchive(Array.from(media));
  return {
    meta: {
      app: "ajn-platform",
      version: 2,
      exportedAt: new Date().toISOString(),
      mediaCount: media.size,
      mediaArchivedCount: mediaArchive.files.length,
      mediaSkippedCount: mediaArchive.skipped.length,
    },
    data,
    mediaManifest: Array.from(media),
    mediaFiles: mediaArchive.files,
    mediaSkipped: mediaArchive.skipped,
  };
}

function storagePathFromPublicUrl(url: string) {
  if (!STORAGE_URL) return null;
  const marker = `/storage/v1/object/public/${STORAGE_BUCKET}/`;
  const index = url.indexOf(marker);
  if (index < 0) return null;
  try {
    return decodeURIComponent(url.slice(index + marker.length));
  } catch {
    return url.slice(index + marker.length);
  }
}

async function buildBackupMediaArchive(urls: string[]) {
  const maxBytes = Number(process.env.AJN_BACKUP_MEDIA_MAX_BYTES ?? 25_000_000);
  const maxFileBytes = Number(
    process.env.AJN_BACKUP_MEDIA_MAX_FILE_BYTES ?? 5_000_000,
  );
  const files: BackupPayload["mediaFiles"] = [];
  const skipped: BackupPayload["mediaSkipped"] = [];
  let totalBytes = 0;
  for (const url of urls) {
    if (!/^https?:\/\//i.test(url)) {
      skipped.push({ url, reason: "not_remote_url" });
      continue;
    }
    try {
      const head = await fetch(url, { method: "HEAD" }).catch(() => null);
      const sizeFromHead = Number(head?.headers.get("content-length") ?? 0);
      if (sizeFromHead && sizeFromHead > maxFileBytes) {
        skipped.push({ url, reason: "file_too_large" });
        continue;
      }
      if (sizeFromHead && totalBytes + sizeFromHead > maxBytes) {
        skipped.push({ url, reason: "backup_media_limit_reached" });
        continue;
      }
      const res = await fetch(url);
      if (!res.ok) {
        skipped.push({ url, reason: `http_${res.status}` });
        continue;
      }
      const bytes = Buffer.from(await res.arrayBuffer());
      if (bytes.length > maxFileBytes || totalBytes + bytes.length > maxBytes) {
        skipped.push({ url, reason: "backup_media_limit_reached" });
        continue;
      }
      totalBytes += bytes.length;
      files.push({
        url,
        path: storagePathFromPublicUrl(url),
        contentType:
          res.headers.get("content-type") ?? "application/octet-stream",
        base64: bytes.toString("base64"),
        size: bytes.length,
      });
    } catch (err: any) {
      skipped.push({ url, reason: err?.message ?? "fetch_failed" });
    }
  }
  return { files, skipped };
}

async function restoreBackupMediaFiles(payload: BackupPayload) {
  const mediaFiles = Array.isArray(payload.mediaFiles)
    ? payload.mediaFiles
    : [];
  if (!mediaFiles.length) return { restored: 0, skipped: 0 };
  if (!STORAGE_URL || !STORAGE_SERVICE_KEY)
    return { restored: 0, skipped: mediaFiles.length };
  let restored = 0;
  let skipped = 0;
  for (const file of mediaFiles) {
    if (!file?.path || !file.base64) {
      skipped += 1;
      continue;
    }
    try {
      const upload = await fetch(
        `${STORAGE_URL.replace(/\/$/, "")}/storage/v1/object/${STORAGE_BUCKET}/${file.path}`,
        {
          method: "POST",
          headers: {
            apikey: STORAGE_SERVICE_KEY,
            authorization: `Bearer ${STORAGE_SERVICE_KEY}`,
            "content-type": file.contentType || "application/octet-stream",
            "x-upsert": "true",
          },
          body: bodyFromBuffer(Buffer.from(file.base64, "base64")),
        },
      );
      if (upload.ok) restored += 1;
      else skipped += 1;
    } catch {
      skipped += 1;
    }
  }
  return { restored, skipped };
}

async function importBackupPayload(payload: any) {
  const data: Record<string, any[]> = (payload?.data ?? payload ?? {}) as any;
  if (!data || typeof data !== "object")
    throw new Error("صيغة النسخة الاحتياطية غير صحيحة");
  const mediaReport = await restoreBackupMediaFiles(payload as BackupPayload);
  const report: Record<
    string,
    { inserted: number; skipped: number; errors: number }
  > = {};
  for (const name of BACKUP_IMPORT_ORDER) {
    const rows = Array.isArray(data[name]) ? data[name] : [];
    if (rows.length === 0) continue;
    const table = BACKUP_ENTITIES[name] as any;
    const stats = { inserted: 0, skipped: 0, errors: 0 };
    for (const row of rows) {
      try {
        const inserted = await db
          .insert(table)
          .values(row)
          .onConflictDoNothing()
          .returning({ id: table.id })
          .catch(async () => {
            await db.insert(table).values(row).onConflictDoNothing();
            return [{ id: -1 }];
          });
        if (inserted.length > 0) stats.inserted++;
        else stats.skipped++;
      } catch (err: any) {
        stats.errors++;
        console.warn("backup entity import row failed", {
          name,
          message: err?.message,
        });
      }
    }
    report[name] = stats;
  }
  return {
    ...report,
    __media: {
      inserted: mediaReport.restored,
      skipped: mediaReport.skipped,
      errors: 0,
    },
  };
}

async function uploadBackupPayload(payload: BackupPayload, snapshotNo: string) {
  if (!STORAGE_URL || !STORAGE_SERVICE_KEY) return null;
  const path = `disaster-recovery/${snapshotNo}.json`;
  const upload = await fetch(
    `${STORAGE_URL.replace(/\/$/, "")}/storage/v1/object/${STORAGE_BUCKET}/${path}`,
    {
      method: "POST",
      headers: {
        apikey: STORAGE_SERVICE_KEY,
        authorization: `Bearer ${STORAGE_SERVICE_KEY}`,
        "content-type": "application/json; charset=utf-8",
        "x-upsert": "true",
      },
      body: JSON.stringify(payload, null, 2),
    },
  );
  if (!upload.ok) {
    console.warn("backup storage upload failed", { status: upload.status });
    return null;
  }
  return `${STORAGE_URL.replace(/\/$/, "")}/storage/v1/object/public/${STORAGE_BUCKET}/${path}`;
}

function toCsv(rows: any[]): string {
  if (!rows.length) return "";
  const colsSet = new Set<string>();
  for (const r of rows) for (const k of Object.keys(r)) colsSet.add(k);
  const cols = Array.from(colsSet);
  const esc = (v: any) => {
    if (v == null) return "";
    let s =
      typeof v === "string"
        ? v
        : v instanceof Date
          ? v.toISOString()
          : JSON.stringify(v);
    if (/[",\n\r]/.test(s)) s = `"${s.replace(/"/g, '""')}"`;
    return s;
  };
  return `\ufeff${cols.join(",")}\n${rows.map((r) => cols.map((c) => esc(r[c])).join(",")).join("\n")}`;
}

async function handleBackup(
  req: NextRequest,
  parts: string[],
  section: string | undefined,
) {
  if (section !== "backup") return null;
  const auth = await requirePermission(req, "backup");
  if (isResponse(auth)) return auth;
  const method = req.method;

  if (method === "GET" && parts[2] === "export" && !parts[3]) {
    const payload = await buildBackupPayload();
    const stamp = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
    return text(JSON.stringify(payload, null, 2), 200, {
      "content-type": "application/json; charset=utf-8",
      "content-disposition": `attachment; filename="ajn-backup-${stamp}.json"`,
    });
  }

  if (method === "GET" && parts[2] === "export" && parts[3]) {
    const entity = parts[3] as BackupEntity;
    const fmt = (
      req.nextUrl.searchParams.get("format") ?? "json"
    ).toLowerCase();
    const table = BACKUP_ENTITIES[entity];
    if (!table) return error("كيان غير معروف", 404);
    const rows = await db.select().from(table as any);
    const stamp = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
    if (fmt === "csv") {
      return text(toCsv(rows), 200, {
        "content-type": "text/csv; charset=utf-8",
        "content-disposition": `attachment; filename="ajn-${entity}-${stamp}.csv"`,
      });
    }
    return text(JSON.stringify(rows, null, 2), 200, {
      "content-type": "application/json; charset=utf-8",
      "content-disposition": `attachment; filename="ajn-${entity}-${stamp}.json"`,
    });
  }

  if (method === "POST" && parts[2] === "import") {
    const b = await body(req);
    if (b?.confirm !== "AJN-IMPORT-CONFIRMED")
      return error("التأكيد مطلوب لاستيراد البيانات", 400);
    const report = await importBackupPayload(b?.payload ?? b);
    return json({ ok: true, report });
  }

  return null;
}

export async function handleApi(req: NextRequest, rawParts: string[] = []) {
  const parts = rawParts.map((p) => decodeURIComponent(p)).filter(Boolean);
  const root = parts[0];
  const isAdminAuth = root === "admin" && parts[1] === "auth";

  try {
    if (!root && req.method === "GET") return json({ status: "ok" });
    if (req.method === "GET" && root === "healthz")
      return json({ status: "ok" });
    if (
      root === "cron" &&
      parts[1] === "smart-notifications" &&
      req.method === "GET"
    ) {
      const secret = process.env.CRON_SECRET;
      if (secret) {
        const auth = req.headers.get("authorization") ?? "";
        if (auth !== `Bearer ${secret}`) return error("غير مصرح", 401);
      }
      const summary = await runSmartNotificationsSweep();
      return json({ ok: true, summary });
    }

    // Run all schema ensures in parallel — they are singleton-promise guarded, so
    // after first resolution each subsequent await is a microtask (effectively free).
    await Promise.all(
      [
        root === "auth" ||
        root === "orders" ||
        root === "track" ||
        (!isAdminAuth && root === "admin") ||
        root === "dashboard" ||
        root === "customer"
          ? ensureCustomerProfileColumns()
          : undefined,
        root === "products" ||
        root === "services" ||
        root === "gallery" ||
        (!isAdminAuth && root === "admin") ||
        root === "auth" ||
        root === "customer" ||
        root === "settings"
          ? ensureImageMetadataColumns()
          : undefined,
        root === "cart" ||
        root === "orders" ||
        root === "products" ||
        (!isAdminAuth && root === "admin") ||
        root === "customer" ||
        root === "dashboard"
          ? ensureProductColorColumns()
          : undefined,
        root === "customer" ||
        root === "orders" ||
        root === "service-orders" ||
        (!isAdminAuth && root === "admin") ||
        root === "auth"
          ? ensureCustomerRewards()
          : undefined,
        root === "orders" ||
        root === "track" ||
        root === "service-orders" ||
        (!isAdminAuth && root === "admin") ||
        root === "dashboard"
          ? Promise.all([
              ensureTrackingColumns(),
              ensurePaymentWorkflowColumns(),
              ensureArchiveColumns(),
              ensurePerformanceIndexes(),
            ])
          : undefined,
        root === "admin" ? ensureStaffActivityColumn() : undefined,
        root === "admin" ? ensureAdminProductsColumns() : undefined,
        root === "products" || (!isAdminAuth && root === "admin")
          ? ensureStoreCategoryColumns()
          : undefined,
        root === "coupons" || (!isAdminAuth && root === "admin")
          ? ensureCouponsTables()
          : undefined,
        root === "messages" ||
        root === "activity" ||
        root === "qr" ||
        root === "track" ||
        root === "notifications" ||
        (!isAdminAuth && root === "admin")
          ? ensureAdminExtensionsTables()
          : undefined,
        root === "koshas" ||
        root === "track" ||
        (!isAdminAuth && root === "admin")
          ? ensureKoshaTables()
          : undefined,
        root === "staff" && parts[1] === "koshas"
          ? ensureKoshaStaffTables()
          : undefined,
        root === "staff" && parts[1] === "photography"
          ? ensurePhotographyStaffTables()
          : undefined,
        root === "rental-orders" ? ensureRentalProductsTables() : undefined,
        root === "graduation" || (!isAdminAuth && root === "admin")
          ? ensureGraduationTables()
          : undefined,
        root === "orders" ||
        root === "service-orders" ||
        root === "koshas" ||
        root === "rental-orders" ||
        (root === "staff" && parts[1] === "photography") ||
        (!isAdminAuth && root === "admin")
          ? ensureMasterCashBoxTables()
          : undefined,
      ].filter(Boolean),
    );

    const route =
      root === "auth"
        ? await handleAuth(req, parts)
        : root === "media"
          ? await handleMedia(req, parts)
          : root === "settings"
            ? await handlePublicSettings(req, parts)
            : root === "customer"
              ? await handleCustomer(req, parts)
              : root === "messages"
                ? await handlePublicMessages(req, parts)
                : root === "activity"
                  ? await handleCustomerActivity(req, parts)
                  : root === "qr"
                    ? await handleQr(req, parts)
                    : root === "track"
                      ? await handleUnifiedTracking(req, parts)
                      : root === "notifications"
                        ? await handleNotifications(req, parts)
                        : root === "products"
                          ? await handleProducts(req, parts)
                          : root === "rental-orders"
                            ? await handleRentalOrders(req, parts)
                            : root === "koshas"
                              ? await handleKoshas(req, parts)
                              : root === "graduation"
                                ? await handleGraduationPublic(req, parts)
                                : root === "offers"
                                  ? await handleOffers(req, parts)
                                  : root === "coupons"
                                    ? await handleCoupons(req, parts)
                                    : root === "services"
                                      ? await handleServices(req, parts)
                                      : root === "crews"
                                        ? await handleCrews(req, parts)
                                        : root === "service-orders"
                                          ? await handleServiceOrders(
                                              req,
                                              parts,
                                            )
                                          : root === "cart"
                                            ? await handleCart(req, parts)
                                            : root === "orders"
                                              ? await handleOrders(req, parts)
                                              : root === "gallery"
                                                ? await handleGallery(
                                                    req,
                                                    parts,
                                                  )
                                                : root === "reviews"
                                                  ? await handleReviews(
                                                      req,
                                                      parts,
                                                    )
                                                  : root === "delivery-zones"
                                                    ? await handleDelivery(
                                                        req,
                                                        parts,
                                                      )
                                                    : root === "dashboard"
                                                      ? await handleDashboard(
                                                          req,
                                                          parts,
                                                        )
                                                      : root === "staff"
                                                        ? await handleStaffPortal(
                                                            req,
                                                            parts,
                                                          )
                                                        : root === "admin"
                                                          ? await handleAdmin(
                                                              req,
                                                              parts,
                                                            )
                                                          : null;

    return route ?? error("المسار غير موجود", 404);
  } catch (err) {
    console.error("API route failed", {
      method: req.method,
      path: req.nextUrl.pathname,
      error: err instanceof Error ? err.message : "unknown",
    });
    return error(
      "تعذر إكمال العملية. حاول مرة أخرى، وإذا استمرت المشكلة راجع سجل الخادم.",
      500,
    );
  }
}
